// MARK: - Sport Filter Bar

struct SportFilterBar: View {
    @Binding var selected: Sport
    let availableSports: Set<String>
    var todaySports: Set<String> = []  // Sports with picks TODAY — sorted closest to "All"
    var showAll: Bool = true  // Whether to show the ALL option
    var showPropsOnly: Bool = false  // Whether to show props-only filters (like NFL TDs)

    // Sort: ALL → sports with today's picks → sports with yesterday data → unavailable (faded)
    private var sortedSports: [Sport] {
        Sport.allCases.sorted { a, b in
            if a == .all { return true }
            if b == .all { return false }

            let aToday = todaySports.contains(a.rawValue)
            let bToday = todaySports.contains(b.rawValue)
            if aToday && !bToday { return true }
            if !aToday && bToday { return false }

            let aAvailable = availableSports.contains(a.rawValue)
            let bAvailable = availableSports.contains(b.rawValue)
            if aAvailable && !bAvailable { return true }
            if !aAvailable && bAvailable { return false }

            return (Sport.allCases.firstIndex(of: a) ?? 0) < (Sport.allCases.firstIndex(of: b) ?? 0)
        }
    }
    
    var body: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 8) {
                ForEach(sortedSports, id: \.self) { sport in
                    // Skip ALL if showAll is false
                    // Skip props-only sports (like NFL TDs) unless showPropsOnly is true
                    let shouldShow = {
                        if sport == .all && !showAll { return false }
                        if sport.isPropsOnly && !showPropsOnly { return false }
                        return true
                    }()
                    
                    if shouldShow {
                        let isAvailable = sport == .all || availableSports.contains(sport.rawValue)
                        let isSelected = selected == sport
                        
                        Button {
                            withAnimation(.spring(response: 0.25, dampingFraction: 0.8)) {
                                selected = sport
                            }
                        } label: {
                            VStack(spacing: 4) {
                                HStack(spacing: 4) {
                                    Image(systemName: sport.icon)
                                        .font(.system(size: 9, weight: .semibold))
                                    Text(sport.rawValue)
                                        .font(.system(size: 11.5, weight: isSelected ? .bold : .medium))
                                }
                                .foregroundStyle(
                                    isSelected ? .white :
                                    isAvailable ? .white.opacity(0.4) :
                                    .white.opacity(0.15)
                                )
                                .padding(.horizontal, 6)

                                RoundedRectangle(cornerRadius: 1)
                                    .fill(isSelected ? sport.accentColor : .clear)
                                    .frame(height: 1.75)
                            }
                        }
                        .disabled(!isAvailable)
                    }
                }
            }
            .padding(.horizontal, 16)
            .padding(.vertical, 2)
        }
        .frame(height: 36)
    }
}


// MARK: - Premium Picks (paywalled "best bets" — the Winners tab)
//
// Gary's highest-conviction plays, sold per sport through Stripe Payment
// Links. Entitlements live in Supabase (user_entitlements), keyed to the
// signed-in auth user — or the anonymous install when nobody's signed in.
// The storefront tail sells locked boards; PaywallPanel sells All-Access.

/// Normalized identity of a game pick WITHIN its matchup — the pick text minus
/// any trailing American-odds token — so multiple picks on ONE game don't collide
/// on a matchup-only result key. (The WC side-+-total feature ships two picks per
/// match: e.g. "Egypt ML -175" AND "Under 2.5 -125". A matchup-only map kept only
/// the last-written one, so the Under read the ML's result → a LOST pick showed
/// CASHED.) `GameResult.pick_text` is written from the pick's own `.pick` — verified
/// byte-identical across daily_picks and game_results — so the same normalization
/// on the result (build) side and the pick (lookup) side aligns them. Odds are the
/// volatile part; the side/total/line is the stable identity that disambiguates.
func garyGamePickSig(_ pickText: String?) -> String {
    var s = (pickText ?? "").lowercased()
    s = s.replacingOccurrences(of: #"\s*[+-]\d{2,}\s*$"#, with: "", options: .regularExpression)
    return s.trimmingCharacters(in: .whitespacesAndNewlines)
}

/// A game-result map key that disambiguates multiple picks on one matchup. Build
/// side passes the result's matchup key + `pick_text`; lookup side passes the
/// pick's matchup key + `.pick`. Both resolve to the same string.
func garyGameResultKey(matchupKey: String, pickText: String?) -> String {
    "\(matchupKey)|\(garyGamePickSig(pickText))"
}

