        }
        .padding(.horizontal, 14).padding(.top, 12)
        .overlay(alignment: .top) {
            ProgressView().tint(GaryColors.gold).padding(.top, 44)
        }
    }

    private var failedState: some View {
        VStack {
            Spacer()
            VStack(spacing: 16) {
                Image(systemName: "wifi.slash").font(.system(size: 50)).foregroundStyle(.tertiary)
                Text("Couldn't load props").foregroundStyle(.secondary)
                Button {
                    Task { await loadProps(forceRefresh: true) }
                } label: {
                    Text("Tap to retry").font(.subheadline.weight(.semibold)).foregroundStyle(GaryColors.gold)
                }
            }
            .padding().liquidGlass(cornerRadius: 24)
            Spacer()
        }
    }

    private var emptyState: some View {
        VStack {
            Spacer()
            VStack(spacing: 16) {
                Image(systemName: "person.fill.questionmark").font(.system(size: 50)).foregroundStyle(.tertiary)
                Text(selectedSport == .all ? "No props yet." : "No \(selectedSport.rawValue) props today.")
                    .foregroundStyle(.secondary)
            }
            .padding().liquidGlass(cornerRadius: 24)
            Spacer()
        }
    }

    /// Check if a prop is from yesterday's fallback
    private func isYesterdayProp(_ prop: PropPick) -> Bool {
        let sport = (prop.effectiveLeague ?? "").uppercased()
        return showingYesterdayResults && !sportsWithFreshProps.contains(sport)
    }

    /// Strip the numeric line value from a prop string (e.g., "points 0.5" → "points")
    private func normalizePropType(_ raw: String) -> String {
        raw.lowercased().replacingOccurrences(of: #"\s+[\d.]+"#, with: "", options: .regularExpression).trimmingCharacters(in: .whitespaces)
    }

    /// Canonical line-value string so "1.5", "1.50", and " 1.5 " all match.
    /// Used to build a precise result-match key that includes the line value
    /// (player + prop_type + line) — prevents cross-day collisions where the
    /// same player has the same prop_type with different lines.
    private func normalizeLine(_ raw: String) -> String {
        let trimmed = raw.trimmingCharacters(in: .whitespaces)
        guard !trimmed.isEmpty else { return "" }
        if let d = Double(trimmed) { return String(format: "%g", d) }
        return trimmed
    }

    /// Canonical matchup string for keying — lowercased + trimmed + run through
    /// shortenMatchup so "Los Angeles Angels @ Detroit Tigers" and "Angels @ Tigers"
    /// resolve to the same value. When both prop and result carry a matchup we add
    /// it to the key, which makes today's "Colt Keith Total Bases 1.5 (Angels @ Tigers)"
    /// impossible to collide with yesterday's same player + same prop_type + same
    /// line from a different opponent.
    private func normalizeMatchup(_ raw: String) -> String {
        let trimmed = raw.trimmingCharacters(in: .whitespaces)
        guard !trimmed.isEmpty else { return "" }
        return shortenMatchup(trimmed).lowercased()
    }

    /// Build the canonical result-match key. Includes only the parts that are
    /// present on the input — keeps the key shape consistent between prop-side
    /// and result-side construction so matchup-rich data on one side and
    /// matchup-missing on the other don't accidentally collide via the looser key.
    private func makeResultKey(player: String, propType: String, line: String, matchup: String) -> String {
        var parts: [String] = [player.lowercased(), propType.lowercased()]
        if !line.isEmpty { parts.append(line) }
        if !matchup.isEmpty { parts.append(matchup) }
        return parts.joined(separator: "_")
    }

    /// Match a prop to its result — checks today's results first, then yesterday's
    private func resultForProp(_ prop: PropPick) -> String? {
        // Hard rule: W/L stamps only appear on YESTERDAY's fallback props
        // (the recap mode when a sport has no fresh picks today). Today's
        // fresh picks NEVER show a stamp — even if the Supabase result table
        // happens to have a row keyed under today's date, we don't trust it
        // for our own freshly-generated picks (some other cron may have put
        // it there before our grading actually ran).
        guard isYesterdayProp(prop) else { return nil }

        let player = (prop.player ?? "").lowercased()
        let propType = normalizePropType(prop.prop ?? "")
        guard !player.isEmpty, !propType.isEmpty else { return nil }

        let line = normalizeLine(prop.line ?? "")
        let matchup = normalizeMatchup(prop.matchup ?? "")
        let key = makeResultKey(player: player, propType: propType, line: line, matchup: matchup)

        return yesterdayResultsMap[key]
    }

    /// Load Gary's GAME picks so the per-game view can show the game pick above
    /// the prop picks — today's fresh picks AND yesterday's settled picks (for
    /// games without a fresh pick) plus their W/L results. Fails silently.
    private func loadGamePicks(forceRefresh: Bool = false) async {
        let date = SupabaseAPI.todayEST()
        var today: [GaryPick] = []
        if let arr = try? await SupabaseAPI.fetchAllPicks(date: date, forceRefresh: forceRefresh) {
            today = arr.filter { !($0.pick ?? "").isEmpty }
        }
        let freshSports = Set(today.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty })

        var yPicks: [GaryPick] = []
        var resultsMap: [String: String] = [:]
        let yesterday = SupabaseAPI.yesterdayEST()
        if let fetched = try? await SupabaseAPI.fetchDailyPicks(date: yesterday) {
            // Only keep yesterday's picks for sports that DON'T have fresh picks today.
            yPicks = fetched.filter { !($0.pick ?? "").isEmpty && !freshSports.contains(($0.league ?? "").uppercased()) }
            if !yPicks.isEmpty {
                let results = (try? await SupabaseAPI.fetchAllGameResults(since: yesterday, forceRefresh: forceRefresh)) ?? []
                for r in results.filter({ $0.game_date == yesterday }) {
                    guard let k = gpKey(from: r.matchup), let outcome = r.result else { continue }
                    resultsMap[garyGameResultKey(matchupKey: k, pickText: r.pick_text)] = outcome.lowercased()
                }
            }
        }

        await MainActor.run {
            gamePicks = today
            yesterdayGamePicks = yPicks
            gameResultsMap = resultsMap
        }
    }

    /// The game pick for a matchup — prefers today's; falls back to yesterday's
    /// (settled). `isYesterday` drives whether we stamp a W/L result (per-game).
    private func gamePickEntry(forMatchup matchup: String) -> (pick: GaryPick, isYesterday: Bool)? {
        if let p = matchGamePick(in: gamePicks, matchup: matchup) { return (p, false) }
        if let p = matchGamePick(in: yesterdayGamePicks, matchup: matchup) { return (p, true) }
        return nil
    }

    private func matchGamePick(in arr: [GaryPick], matchup: String) -> GaryPick? {
        let m = matchup.lowercased()
        return arr.first { p in
            guard let h = p.homeTeam?.lowercased(), let a = p.awayTeam?.lowercased(), !h.isEmpty, !a.isEmpty else { return false }
            let hKey = h.split(separator: " ").last.map(String.init) ?? h
            let aKey = a.split(separator: " ").last.map(String.init) ?? a
            return m.contains(hKey) && m.contains(aKey)
        }
    }

    /// W/L for a settled (yesterday) game pick, matched by normalized teams AND the
    /// pick's own signature — so a game's side and total don't collide on a
    /// matchup-only key (the WC two-pick bug).
    private func gamePickResult(_ pick: GaryPick) -> String? {
        let away = gpTeamKey(pick.awayTeam), home = gpTeamKey(pick.homeTeam)
        guard !away.isEmpty, !home.isEmpty else { return nil }
        return gameResultsMap[garyGameResultKey(matchupKey: "\(away)@\(home)", pickText: pick.pick)]
    }

    private func gpTeamKey(_ value: String?) -> String {
        (value ?? "").lowercased().components(separatedBy: CharacterSet.alphanumerics.inverted).joined()
    }
    private func gpKey(from matchup: String?) -> String? {
        guard let matchup else { return nil }
        for sep in [" @ ", " vs ", " v "] {
            let parts = matchup.components(separatedBy: sep)
            if parts.count == 2 {
                let a = gpTeamKey(parts[0]), h = gpTeamKey(parts[1])
                if !a.isEmpty && !h.isEmpty { return "\(a)@\(h)" }
            }
        }
        return nil
    }

    private func loadProps(forceRefresh: Bool = false) async {
        await MainActor.run {
            loading = true
            fetchFailed = false
        }

        let date = SupabaseAPI.todayEST()

        // Use a timeout to prevent infinite loading
        var props: [PropPick] = []
        var didFail = false
        do {
            props = try await withTimeout(seconds: 30) {
                try await SupabaseAPI.fetchPropPicks(date: date, forceRefresh: forceRefresh)
            }
        } catch {
            didFail = true
        }

        // Fetch today's prop results to stamp W/L on completed props
        var todayMap: [String: String] = [:]
        let allResults = (try? await SupabaseAPI.fetchPropResults(since: SupabaseAPI.yesterdayEST(), forceRefresh: forceRefresh)) ?? []
        for result in allResults.filter({ $0.game_date == date }) {
            guard let playerName = result.player_name, let propType = result.prop_type,
                  let outcome = result.result, !outcome.isEmpty else { continue }
            // Only count actually-graded results — a record must have a real
            // measured actual_value to count as a true W/L. Skips stale/duplicate
            // records that may carry today's game_date without being real grades.
            let actualValue = (result.actual_value?.value ?? "").trimmingCharacters(in: .whitespaces)
            guard !actualValue.isEmpty else { continue }

            let line = normalizeLine(result.line_value?.value ?? "")
            let matchup = normalizeMatchup(result.matchup ?? "")
            let key = makeResultKey(player: playerName, propType: normalizePropType(propType), line: line, matchup: matchup)
            todayMap[key] = outcome.lowercased()
        }

        // Determine which sports have fresh props today
        let freshSports = Set(props.compactMap { ($0.effectiveLeague ?? "").uppercased() }.filter { !$0.isEmpty })

        // Fetch yesterday's props + results for sports without fresh props today
        var yProps: [PropPick] = []
        var yMap: [String: String] = [:]
        var hasYesterday = false
        do {
            let yesterday = SupabaseAPI.yesterdayEST()
            let fetched = try await withTimeout(seconds: 20) {
                try await SupabaseAPI.fetchPropPicks(date: yesterday, forceRefresh: forceRefresh)
            }

            let yesterdaySportsNeeded = fetched.filter { !freshSports.contains(($0.effectiveLeague ?? "").uppercased()) }
            if !yesterdaySportsNeeded.isEmpty {
                yProps = yesterdaySportsNeeded
                hasYesterday = true

                for result in allResults.filter({ $0.game_date == yesterday }) {
                    guard let playerName = result.player_name, let propType = result.prop_type,
                          let outcome = result.result, !outcome.isEmpty else { continue }
                    let actualValue = (result.actual_value?.value ?? "").trimmingCharacters(in: .whitespaces)
                    guard !actualValue.isEmpty else { continue }

                    let line = normalizeLine(result.line_value?.value ?? "")
                    let matchup = normalizeMatchup(result.matchup ?? "")
                    let key = makeResultKey(player: playerName, propType: normalizePropType(propType), line: line, matchup: matchup)
                    yMap[key] = outcome.lowercased()
                }
            }
        } catch {
            // Yesterday fetch failed — just show today's props
        }

        await MainActor.run {
            allProps = props
            propResultsMap = todayMap
            yesterdayProps = yProps
            yesterdayResultsMap = yMap
            sportsWithFreshProps = freshSports
            showingYesterdayResults = hasYesterday
            fetchFailed = didFail && props.isEmpty && yProps.isEmpty
            loading = false
            if !didFail { lastUpdated = Date() }

            // Auto-select the first sport with props if only one sport has fresh props
            if selectedSport == .all && freshSports.count == 1, let onlySport = freshSports.first {
                if let match = Sport.allCases.first(where: { $0.rawValue == onlySport }) {
                    selectedSport = match
                }
            }
        }
    }
}

// MARK: - Props Dashboard support types (Quant Terminal)

enum PropDashViewMode: Hashable { case cards, table }

enum PropDashSort: CaseIterable, Identifiable {
    case confidence, time, player
    var id: Self { self }
    var label: String {
        switch self {
        case .confidence: return "Confidence"
        case .time:       return "Game Time"
        case .player:     return "Player"
        }
    }
}

enum PropDashOU: CaseIterable, Identifiable {
    case all, over, under
    var id: Self { self }
    var label: String {
        switch self {
        case .all:   return "All"
        case .over:  return "Over"
        case .under: return "Under"
        }
    }
}

/// Thin horizontal confidence bar (gold fill on a faint track). `value` is 0...1.
struct QuantConfidenceBar: View {
    let value: Double
    var height: CGFloat = 4
    var body: some View {
        GeometryReader { geo in
            ZStack(alignment: .leading) {
                Capsule().fill(Color.white.opacity(0.08))
                Capsule().fill(GaryColors.gold)
                    .frame(width: max(2, geo.size.width * CGFloat(max(0.04, min(1, value)))))
            }
        }
        .frame(height: height)
    }
}

/// "Confidence shape" — an equalizer of bars (one per prop), heights proportional
/// to confidence, sorted high→low. A 3-second read of how strong the slate leans.
struct ConfidenceShapeView: View {
    let values: [Double]
    var body: some View {
        GeometryReader { geo in
            let n = max(values.count, 1)
            let gap: CGFloat = 2
            let w = max(1.5, (geo.size.width - gap * CGFloat(n - 1)) / CGFloat(n))
            HStack(alignment: .bottom, spacing: gap) {
                ForEach(Array(values.enumerated()), id: \.offset) { _, v in
                    let h = max(0.12, min(1, v))
                    Capsule()
                        .fill(GaryColors.gold.opacity(0.3 + 0.6 * h))
                        .frame(width: w, height: max(2, geo.size.height * CGFloat(h)))
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottom)
        }
    }
}

/// Compact KPI stat tile for the dashboard's at-a-glance row.
struct QuantKpiTile: View {
    let label: String
    let value: String
    var sub: String? = nil
    var accent: Color = .white
    var body: some View {
        VStack(alignment: .leading, spacing: 5) {
            Text(label)
                .font(GaryFonts.mono(8.5, bold: true)).tracking(1.4)
                .foregroundStyle(.white.opacity(0.62))
            Text(value)
                .font(GaryFonts.mono(21, bold: true))
                .foregroundStyle(accent).lineLimit(1).minimumScaleFactor(0.55)
            if let sub {
                Text(sub)
                    .font(GaryFonts.mono(8, bold: false)).tracking(0.6)
                    .foregroundStyle(.white.opacity(0.62)).lineLimit(1).minimumScaleFactor(0.7)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.horizontal, 12).padding(.vertical, 11)
        .background(
            RoundedRectangle(cornerRadius: 10, style: .continuous)
                .fill(Color.white.opacity(0.025))
                .overlay(RoundedRectangle(cornerRadius: 10, style: .continuous).stroke(Color.white.opacity(0.07), lineWidth: 1))
        )
    }
}

/// Faint card chrome shared by the dashboard's panels.
private struct QuantPanel: ViewModifier {
    var radius: CGFloat = 12
    // Warm-white overlay, not pure white: white at 2% over the warm black
    // page reads as the cool blue-grey AI-slop cast. Same lightness, warm hue.
    private static let warm = GaryColors.warmWhite
    func body(content: Content) -> some View {
        content.background(
            RoundedRectangle(cornerRadius: radius, style: .continuous)
                .fill(Self.warm.opacity(0.022))
                .overlay(RoundedRectangle(cornerRadius: radius, style: .continuous).stroke(Self.warm.opacity(0.07), lineWidth: 1))
        )
    }
}

private extension View {
    func quantPanel(radius: CGFloat = 12) -> some View { modifier(QuantPanel(radius: radius)) }
}

// MARK: - Tomorrow View (the "TOMORROW" Home state — the look-ahead board)
//
// The C1plus mock rebuilt on the app's real components/spacing: a countdown
// hero, big-games-to-watch, the full scoreboard, and a by-sport probable-
// starters / key-returns footer grid. Everything is server-precomputed
// (tomorrow_board); the only live work is the 1Hz countdown tick. Rendered as
// the body of the new TOMORROW switcher pill on Home — it is not its own tab,
// so it carries no masthead (Home's GaryPageHeader sits above the switcher).
struct TomorrowView {

    /// sport -> hero eyebrow term, keyed on countdown_sport (uppercased). The
    /// mock's "FIRST PITCH IN" is just the MLB branch; tomorrow it auto-switches
    /// to "KICKOFF IN" if a WC match is the earliest game.
    static func countdownTerm(_ sport: String?) -> String {
        let s = (sport ?? "").uppercased()
        switch s {
        case "MLB":                       return "FIRST PITCH IN"
        case "NFL", "NCAAF":              return "KICKOFF IN"
        case "NBA", "NCAAB":             return "TIP-OFF IN"
        case "NHL":                       return "PUCK DROP IN"
        default:
            if s == "WC" || s.hasPrefix("SOCCER") { return "KICKOFF IN" }
            return "FIRST GAME IN"
        }
    }

    /// Sport-dot legend color: MLB green, WC teal, everything else gold.
    static func sportDotColor(_ league: String?) -> Color {
        switch (league ?? "").uppercased() {
        case "MLB": return Color(hex: "#4FB14F")
        case "WC":  return Color(hex: "#3FB6A8")
        default:    return GaryColors.gold
        }
    }

    /// "7:10 PM ET" from an ISO commence time, in Eastern.
    static func etTime(_ iso: String?, withZone: Bool = true, meridiem: Bool = false) -> String {
        guard let iso, let date = parseISO8601(iso) else { return "—" }
        let f = DateFormatter()
        f.timeZone = TimeZone(identifier: "America/New_York")
        // meridiem = AM/PM but no " ET" suffix (e.g. "9:00 PM"); withZone adds " ET".
        f.dateFormat = (withZone || meridiem) ? "h:mm a" : "h:mm"
        var s = f.string(from: date)
        if withZone { s += " ET" }
        return s
    }

    /// "Saturday, June 27" for tomorrow's slate day (countdown_iso's date, ET).
    static func weekdayLabel(_ iso: String?) -> String {
        guard let iso, let date = parseISO8601(iso) else { return "" }
        let f = DateFormatter()
        f.timeZone = TimeZone(identifier: "America/New_York")
        f.dateFormat = "EEEE, MMMM d"
        return f.string(from: date)
    }

    /// "Saturday" — short weekday for section subs.
    static func weekday(_ iso: String?) -> String {
        guard let iso, let date = parseISO8601(iso) else { return "Tomorrow" }
        let f = DateFormatter()
        f.timeZone = TimeZone(identifier: "America/New_York")
        f.dateFormat = "EEEE"
        return f.string(from: date)
    }

    /// "Sat Jun 27" — the tight date for the countdown hero subtitle.
    static func shortDateLabel(_ iso: String?) -> String {
        guard let iso, let date = parseISO8601(iso) else { return "" }
        let f = DateFormatter()
        f.timeZone = TimeZone(identifier: "America/New_York")
        f.dateFormat = "EEE MMM d"
        return f.string(from: date)
    }

    /// Stable sport order for the by-sport footer groups: MLB, WC, then the rest.
    static func sortedLeagues(_ people: [TomorrowPerson]) -> [String] {
        let order = ["MLB", "WC"]
        let present = Array(Set(people.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty }))
        let head = order.filter { present.contains($0) }
        let tail = present.filter { !order.contains($0) }.sorted()
        return head + tail
    }

    /// The Tomorrow body — the scrolling content under the switcher. Lives inside
    /// Home's ScrollView, so it returns a VStack (no ScrollView/background here).
    struct Body: View {
        let board: TomorrowBoard?
        // (Jul 5 redesign: the Hub/Today flag machinery — leagueFilter,
        // include*, dayLabel, liveStatus, the 1Hz ticker — left with its last
        // consumers. Home's TOMORROW tab is the only caller; the page is now
        // static per data refresh, no per-second re-render.)
        /// The active look-ahead tab (Starters · Key Returns · Form · Run
        /// Profile · Weather). The giant inline list overflowed the screen — this
        /// is now a contained tabbed table that scrolls internally.
        @State private var lookAheadTab = 0
        /// The active WC look-ahead lane (Form · Key Scorers · Lineups) — the WC
        /// twin of lookAheadTab.
        @State private var wcLookAheadTab = 0
        /// MLB / WC top-level switch for "The Day Ahead". MLB = the existing
        /// tabbed table; WC = the per-match World Cup look-ahead cards.
        @State private var lookAheadSport: LookAheadSport = .mlb
        /// Teal WC accent, matching the board's sport-dot legend.
        private let wcAccent = Color(hex: "#3FB6A8")

        var body: some View {
            VStack(alignment: .leading, spacing: 22) {
                slateHero
                bigGames
                lookAheadTabs
                if let b = board, !b.board.isEmpty { tomorrowBoardSection(b) }
            }
        }

        // ── ① The slate masthead ───────────────────────────────────────────
        // Jul 5 redesign: the giant ticking HH:MM:SS clock is gone (18 hours
        // of second-precision was noise) — the hero is now the DAY: date in
        // the display face, one meta line with the count, first start, and
        // the game that opens the slate.

        private var slateHero: some View {
            let iso = board?.countdown_iso
            let anyLines = board?.any_lines ?? false
            let count = board?.game_count ?? 0
            return VStack(alignment: .leading, spacing: 0) {
                HStack(spacing: 7) {
                    BroadcastBar(height: 10)
                    Text("THE SLATE")
                        .font(GaryFonts.accent(11)).tracking(0.6)
                        .foregroundStyle(GaryColors.gold)
                }
                if let iso {
                    Text(TomorrowView.weekdayLabel(iso))
                        .font(GaryFonts.display(34))
                        .foregroundStyle(GaryColors.warmWhite)
                        .lineLimit(1).minimumScaleFactor(0.7)
                        .padding(.top, 6)
                    Text(heroMeta(iso: iso, anyLines: anyLines, count: count))
                        .font(GaryFonts.mono(11, bold: true)).tracking(0.8)
                        .foregroundStyle(.white.opacity(0.66))
                        .lineLimit(1).minimumScaleFactor(0.8)
                        .padding(.top, 8)
                } else if board != nil && count == 0 {
                    // The board POSTED and is legitimately empty (All-Star
                    // break, tournament rest day) — say so. "Posts soon"
                    // here reads as an outage (founder, Jul 12).
                    Text("No games tomorrow")
                        .font(GaryFonts.text(20, .semibold))
                        .foregroundStyle(.white.opacity(0.9))
                        .padding(.top, 8)
                    Text("The league is dark — the board returns with the next slate.")
                        .font(GaryFonts.text(13))
                        .foregroundStyle(.white.opacity(0.6))
                        .padding(.top, 6)
                } else {
                    Text("Tomorrow's board posts soon")
                        .font(GaryFonts.text(20, .semibold))
                        .foregroundStyle(.white.opacity(0.9))
                        .padding(.top, 8)
                }
            }
            .frame(maxWidth: .infinity, alignment: .leading)
            .padding(18)
            .quantPanel(radius: 18)
            // The gold radial-glow corner from the mock.
            .overlay(alignment: .topTrailing) {
                RadialGradient(colors: [GaryColors.gold.opacity(0.18), .clear],
                               center: .topTrailing, startRadius: 0, endRadius: 150)
                    .frame(width: 200, height: 200)
                    .allowsHitTesting(false)
                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
            }
            .padding(.horizontal, 16)
        }

        /// "10 GAMES · FIRST PITCH 1:05 PM ET · PHI @ KC OPENS" — or the honest
        /// pre-lines state. The start word keys on the opening game's sport.
        private func heroMeta(iso: String, anyLines: Bool, count: Int) -> String {
            let plural = count == 1 ? "GAME" : "GAMES"
            guard anyLines else { return "\(count) \(plural) · LINES OPEN SOON" }
            let startWord = TomorrowView.countdownTerm(board?.countdown_sport)
                .replacingOccurrences(of: " IN", with: "")
            var bits = ["\(count) \(plural)", "\(startWord) \(TomorrowView.etTime(iso))"]
            if let m = board?.countdown_matchup, !m.isEmpty { bits.append("\(m.uppercased()) OPENS") }
            return bits.joined(separator: " · ")
        }

        // ── ② Big games to watch ───────────────────────────────────────────

        @ViewBuilder private var bigGames: some View {
            let games = (board?.big_games ?? []).sorted { $0.rank < $1.rank }.prefix(5)
            if !games.isEmpty {
                VStack(alignment: .leading, spacing: 10) {
                    HubSectionHeader(eyebrow: "The Marquee", sub: "")
                    VStack(spacing: 0) {
                        ForEach(Array(games.enumerated()), id: \.element.rank) { idx, g in
                            bigGameRow(g, displayRank: idx + 1)
                            if idx < games.count - 1 {
                                Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1)
                            }
                        }
                    }
                    .padding(.vertical, 4)
                    .quantPanel()
                    .padding(.horizontal, 16)
                }
            }
        }

        private func bigGameRow(_ g: TomorrowBigGame, displayRank: Int) -> some View {
            // Both probable starters, "Away vs Home" — gold, mono. MLB only;
            // WC big games leave the pitchers nil → no line. "Undecided" is
            // shown verbatim when a probable is unposted.
            let away = (g.awayPitcher ?? g.pitchers?.away)?.trimmingCharacters(in: .whitespaces)
            let home = (g.homePitcher ?? g.pitchers?.home)?.trimmingCharacters(in: .whitespaces)
            let pitchersLine: String? = {
                guard let a = away, !a.isEmpty, let h = home, !h.isEmpty else { return nil }
                return "\(a) vs \(h)"
            }()
            return HStack(alignment: .top, spacing: 12) {
                Text("\(displayRank)")
                    .font(GaryFonts.display(22))
                    .foregroundStyle(GaryColors.gold)
                    .frame(width: 18, alignment: .leading)
                VStack(alignment: .leading, spacing: 7) {
                    // Top line: the matchup in the display face (left) · time (right).
                    HStack(alignment: .firstTextBaseline, spacing: 8) {
                        Text((g.matchup ?? "").uppercased())
                            .font(GaryFonts.display(22))
                            .foregroundStyle(.white.opacity(0.95))
                            .lineLimit(1)
                            .minimumScaleFactor(0.7)
                        Spacer(minLength: 6)
                        Text(TomorrowView.etTime(g.commence_time, withZone: false, meridiem: true))
                            .font(GaryFonts.mono(12))
                            .foregroundStyle(.white.opacity(0.62))
                    }
                    // Plain-text standing under the matchup — readable (was 9.5/0.55).
                    if let standing = g.standing, !standing.isEmpty {
                        Text(standing)
                            .font(GaryFonts.mono(11))
                            .foregroundStyle(.white.opacity(0.6))
                            .lineLimit(2)
                            .multilineTextAlignment(.leading)
                            .fixedSize(horizontal: false, vertical: true)
                    }
                    // The pitching matchup — the heart of the game. Each starter on its
                    // own readable row: abbr · name · ERA (quality-coloured) · xERA (the
                    // honest regression number, so an elite-looking ERA can't mislead).
                    // MLB only; WC big games have nil pitchers.
                    if pitchersLine != nil, let a = away, let h = home {
                        let bRow = bigGameBoardRow(g)
                        VStack(alignment: .leading, spacing: 5) {
                            pitcherLine(fallback: a, abbr: bRow?.away_abbr,
                                        stat: starterStat(lastName: a, abbr: bRow?.away_abbr))
                            pitcherLine(fallback: h, abbr: bRow?.home_abbr,
                                        stat: starterStat(lastName: h, abbr: bRow?.home_abbr))
                        }
                        .padding(.top, 3)
                    } else if let wc = wcMatch(g) {
                        // WC parity — same LOOK as the pitcher rows, WC-appropriate
                        // stats: each nation on its own row (abbr · name · L5 record,
                        // form-coloured · goals/game), grounded from wc_lookahead.
                        VStack(alignment: .leading, spacing: 5) {
                            wcTeamLine(team: wc.away_team, form: wc.away?.form, league: g.league)
                            wcTeamLine(team: wc.home_team, form: wc.home?.form, league: g.league)
                        }
                        .padding(.top, 3)
                    }
                    // Market line — the favourite + total (MLB ML/total · WC ML/goals).
                    if let mkt = bigGameMarket(g) {
                        Text(mkt)
                            .font(GaryFonts.mono(11.5))
                            .foregroundStyle(.white.opacity(0.6))
                            .lineLimit(1).minimumScaleFactor(0.9)
                            .padding(.top, 1)
                    }
                }
            }
            .padding(.horizontal, 14)
            .padding(.vertical, 12)
        }

        /// One probable starter — abbr · name · ERA (quality-coloured) · xERA.
        private func pitcherLine(fallback: String, abbr: String?,
                                 stat: (name: String, era: String, xera: String?, color: Color)?) -> some View {
            HStack(spacing: 8) {
                if let ab = abbr, !ab.isEmpty {
                    Text(ab.uppercased())
                        .font(GaryFonts.mono(10.5, bold: true))
                        .foregroundStyle(GaryColors.gold.opacity(0.85))
                        .frame(width: 34, alignment: .leading)
                }
                Text(stat?.name ?? fallback)
                    .font(GaryFonts.text(13))
                    .foregroundStyle(.white.opacity(0.9))
                    .lineLimit(1).minimumScaleFactor(0.85)
                Spacer(minLength: 8)
                if let s = stat {
                    // Label BOTH stats — a bare quality-coloured number next to a
                    // labelled xERA made readers guess what the first one was.
                    Text("ERA \(s.era)")
                        .font(GaryFonts.mono(13, bold: true))
                        .foregroundStyle(s.color)
                    if let x = s.xera {
                        Text("xERA \(x)")
                            .font(GaryFonts.mono(10.5))
                            .foregroundStyle(.white.opacity(0.55))
                    }
                } else {
                    Text("ERA —")
                        .font(GaryFonts.mono(11))
                        .foregroundStyle(.white.opacity(0.62))
                }
            }
        }

        /// The wc_lookahead entry for a WC big game, matched by matchup string.
        private func wcMatch(_ g: TomorrowBigGame) -> TomorrowWcMatch? {
            guard (g.league ?? "").uppercased() == "WC",
                  let mu = g.matchup?.lowercased() else { return nil }
            return board?.wc_lookahead?.first {
                ($0.match ?? "").lowercased() == mu
            }
        }

        /// One WC nation — abbr · name · L5 record (form-coloured) · goals/game. The
        /// WC twin of pitcherLine: same shape, soccer stats (not ERA).
        private func wcTeamLine(team: String?, form: TomorrowWcForm?, league: String?) -> some View {
            let ab = teamAbbrevFromName(team ?? "", league: league)
            // THIS World Cup's record only (founder: "only the WC games"), falling
            // back to the L5 form when a team hasn't played a tournament game yet.
            let rec = form?.wc?.record ?? form?.record
            let w = form?.wc?.w ?? form?.w
            let l = form?.wc?.l ?? form?.l
            let gf = form?.wc?.gf_per_game ?? form?.gf_per_game
            let recColor: Color = {
                guard let w = w, let l = l else { return .white.opacity(0.9) }
                if w > l { return GaryColors.win }
                if l > w { return GaryColors.loss }
                return Color(hex: "#E8B339")   // even — amber
            }()
            return HStack(spacing: 8) {
                Text(ab.uppercased())
                    .font(GaryFonts.mono(10.5, bold: true))
                    .foregroundStyle(GaryColors.gold.opacity(0.85))
                    .frame(width: 34, alignment: .leading)
                Text(team ?? "")
                    .font(GaryFonts.text(13))
                    .foregroundStyle(.white.opacity(0.9))
                    .lineLimit(1).minimumScaleFactor(0.85)
                Spacer(minLength: 8)
                if let rec = rec {
                    Text(rec)
                        .font(GaryFonts.mono(13, bold: true))
                        .foregroundStyle(recColor)
                    if let gf = gf {
                        // Spelled out for US fans — not the cryptic "GF".
                        Text("\(Self.trimNum(gf)) Goals/Gm")
                            .font(GaryFonts.mono(10))
                            .foregroundStyle(.white.opacity(0.62))
                    }
                } else {
                    Text("—")
                        .font(GaryFonts.mono(11))
                        .foregroundStyle(.white.opacity(0.62))
                }
            }
        }

        /// The board row for a big game, matched by team last-words ("Reds @ Brewers").
        private func bigGameBoardRow(_ g: TomorrowBigGame) -> TomorrowBoardRow? {
            guard let mu = g.matchup?.lowercased(), let rows = board?.board else { return nil }
            let sides = mu.components(separatedBy: " @ ")
            guard sides.count == 2,
                  let aKey = sides[0].split(separator: " ").last.map(String.init),
                  let hKey = sides[1].split(separator: " ").last.map(String.init) else { return nil }
            return rows.first {
                ($0.away_team ?? "").lowercased().contains(aKey) &&
                ($0.home_team ?? "").lowercased().contains(hKey)
            }
        }

        /// A probable starter's full read (name, ERA, xERA, quality colour), matched
        /// by team abbr + last name. nil when ERA isn't posted.
        private func starterStat(lastName: String?, abbr: String?) -> (name: String, era: String, xera: String?, color: Color)? {
            guard let lastName, !lastName.isEmpty, let starters = board?.starters else { return nil }
            let key = lastName.lowercased()
            let p = starters.first {
                $0.era != nil &&
                (($0.name ?? "").lowercased().split(separator: " ").last.map(String.init) == key) &&
                (abbr == nil || ($0.abbr ?? "").uppercased() == abbr!.uppercased())
            }
            guard let p, let era = p.era else { return nil }
            let avg = board?.league_avg_era ?? 4.32
            return (p.name ?? lastName, Self.trimNum(era), p.xera.map { Self.trimNum($0) },
                    Self.bigGameEraColor(era, avg: avg))
        }

        /// Tiered ERA quality colour vs league avg — elite (bright green) · good
        /// (green, at/below avg) · amber (a run above) · red (well above). Replaces
        /// the old meaningless binary cliff at exactly the average.
        private static func bigGameEraColor(_ era: Double, avg: Double) -> Color {
            switch era - avg {
            case ..<(-1.0): return Color(hex: "#36D17A")   // elite
            case ..<0:      return GaryColors.win           // good
            case ..<1.0:    return Color(hex: "#E8B339")    // amber — a run above
            default:        return GaryColors.loss          // well above avg
            }
        }

        /// "MIL -145 · O/U 7.5" — favourite (more-negative ML) + total.
        private func bigGameMarket(_ g: TomorrowBigGame) -> String? {
            guard let row = bigGameBoardRow(g) else { return nil }
            var parts: [String] = []
            if let mh = row.ml_home, let ma = row.ml_away {
                let homeFav = mh <= ma
                let favTeam = homeFav ? row.home_team : row.away_team
                // Proper FIFA/league code (NED, MAR) — not the prefix(3) fallback (NET, MOR).
                let favAbbr = (homeFav ? row.home_abbr : row.away_abbr)
                    ?? (favTeam.map { teamAbbrevFromName($0, league: g.league) } ?? abbr(favTeam))
                parts.append("\(favAbbr) \(Self.mlStr(homeFav ? mh : ma))")
            }
            if let t = row.total { parts.append("O/U \(Self.trimNum(t))") }
            return parts.isEmpty ? nil : parts.joined(separator: "  ·  ")
        }

        // ── ③ Tomorrow's board (full scoreboard) ───────────────────────────

        private func tomorrowBoardSection(_ b: TomorrowBoard) -> some View {
            VStack(alignment: .leading, spacing: 8) {
                // Board label row + sport-dot legend.
                HStack(spacing: 10) {
                    Text("Tomorrow's Board")
                        .font(GaryFonts.display(17))
                        .foregroundStyle(GaryColors.sectionHead)   // match "The Day Ahead" header
                    Spacer(minLength: 6)
                    legendDot(Color(hex: "#4FB14F"), "MLB")
                    legendDot(Color(hex: "#3FB6A8"), "WC")
                }
                .padding(.horizontal, 16)

                VStack(spacing: 0) {
                    boardHeader
                    ForEach(Array(b.board.enumerated()), id: \.offset) { idx, row in
                        boardRow(row, alt: idx % 2 == 1)
                    }
                }
                .quantPanel(radius: 14)
                .padding(.horizontal, 16)
            }
        }

        private func legendDot(_ c: Color, _ label: String) -> some View {
            HStack(spacing: 4) {
                Circle().fill(c).frame(width: 6, height: 6)
                Text(label).font(GaryFonts.mono(9)).foregroundStyle(.white.opacity(0.62))
            }
        }

        // 48 | 1fr | 46 | 42 | 46  (TIME | MATCHUP | SPR | O/U | ML)
        private var boardHeader: some View {
            HStack(spacing: 0) {
                Text("TIME").frame(width: 48, alignment: .leading)
                Text("MATCHUP").frame(maxWidth: .infinity, alignment: .leading)
                Text("SPR").frame(width: 46, alignment: .trailing)
                Text("O/U").frame(width: 42, alignment: .trailing)
                Text("ML").frame(width: 46, alignment: .trailing)
            }
            .font(GaryFonts.mono(10))
            .foregroundStyle(.white.opacity(0.62))
            .padding(.horizontal, 12)
            .padding(.vertical, 8)
        }

        private func boardRow(_ row: TomorrowBoardRow, alt: Bool) -> some View {
            let marquee = row.is_marquee ?? false
            let away = row.away_abbr ?? abbr(row.away_team)
            let home = row.home_abbr ?? abbr(row.home_team)
            return HStack(spacing: 0) {
                Text(TomorrowView.etTime(row.commence_time, withZone: false))
                    .font(GaryFonts.mono(12))
                    .foregroundStyle(GaryColors.gold)
                    .frame(width: 48, alignment: .leading)
                HStack(spacing: 5) {
                    Circle().fill(TomorrowView.sportDotColor(row.league)).frame(width: 6, height: 6)
                    Text("\(away) @ \(home)")
                        .font(GaryFonts.mono(12, bold: true))
                        .foregroundStyle(.white.opacity(0.92))
                    if marquee {
                        Image(systemName: "star.fill")
                            .font(.system(size: 7.5))
                            .foregroundStyle(GaryColors.gold)
                    }
                }
                .frame(maxWidth: .infinity, alignment: .leading)
                Text(Self.lineStr(row.spread, signed: true))
                    .font(GaryFonts.mono(12)).foregroundStyle(.white.opacity(0.8))
                    .frame(width: 46, alignment: .trailing)
                Text(Self.lineStr(row.total))
                    .font(GaryFonts.mono(12)).foregroundStyle(.white.opacity(0.8))
                    .frame(width: 42, alignment: .trailing)
                Text(Self.mlStr(row.ml_home))
                    .font(GaryFonts.mono(12)).foregroundStyle(.white.opacity(0.62))
                    .frame(width: 46, alignment: .trailing)
            }
            .padding(.horizontal, 12)
            .padding(.vertical, 8)
            .background(alignment: .leading) {
                if marquee {
                    LinearGradient(colors: [GaryColors.gold.opacity(0.09), .clear],
                                   startPoint: .leading, endPoint: .trailing)
                } else if alt {
                    Color.white.opacity(0.018)
                }
            }
        }

        private static func lineStr(_ v: Double?, signed: Bool = false) -> String {
            guard let v else { return "—" }
            if signed && v > 0 { return "+" + Self.trimNum(v) }
            return Self.trimNum(v)
        }
        private static func mlStr(_ v: Double?) -> String {
            guard let v else { return "—" }
            let i = Int(v.rounded())
            return i > 0 ? "+\(i)" : "\(i)"
        }
        private static func trimNum(_ v: Double) -> String {
            if v == v.rounded() { return String(Int(v)) }
            return String(format: "%.1f", v)
        }

        // ── Poisson match model (the "Team Strength" upgrade) ───────────────────
        // Independent-Poisson goal model (the standard Dixon-Coles base): each side's
        // projected goals is a Poisson mean (λ), and the joint scoreline grid gives
        // true win / draw / loss + over probabilities and the single likeliest score.
        struct MatchOdds {
            let pHome: Double, pDraw: Double, pAway: Double
            let pOver: Double?            // P(total > line); nil when no line
            let likelyHome: Int, likelyAway: Int
        }
        /// Poisson PMF in log space (no factorial overflow): P(X = k | λ).
        private static func poissonPMF(_ k: Int, _ lambda: Double) -> Double {
            guard lambda > 0, k >= 0 else { return k == 0 ? 1 : 0 }
            var logp = -lambda + Double(k) * log(lambda)
            if k > 0 { for n in 1...k { logp -= log(Double(n)) } }
            return exp(logp)
        }
        /// Score-grid (0…8 each side) → W/D/L, P(over line), and the modal scoreline.
        private static func matchOdds(lambdaHome: Double, lambdaAway: Double, totalLine: Double?) -> MatchOdds {
            let maxG = 8
            var pH = 0.0, pD = 0.0, pA = 0.0, pOver = 0.0, mass = 0.0
            var best = -1.0, bi = 0, bj = 0
            let hPMF = (0...maxG).map { poissonPMF($0, lambdaHome) }
            let aPMF = (0...maxG).map { poissonPMF($0, lambdaAway) }
            for i in 0...maxG {
                for j in 0...maxG {
                    let p = hPMF[i] * aPMF[j]
                    mass += p
                    if i > j { pH += p } else if i == j { pD += p } else { pA += p }
                    if let line = totalLine, Double(i + j) > line { pOver += p }
                    if p > best { best = p; bi = i; bj = j }
                }
            }
            let z = mass > 0 ? mass : 1   // normalize to captured mass (tail beyond 8 is tiny)
            return MatchOdds(pHome: pH / z, pDraw: pD / z, pAway: pA / z,
                             pOver: totalLine != nil ? pOver / z : nil, likelyHome: bi, likelyAway: bj)
        }
        private static func pct(_ v: Double) -> String { "\(Int((v * 100).rounded()))%" }

        private func abbr(_ team: String?) -> String {
            guard let team, !team.isEmpty else { return "—" }
            // Fallback only — server normally provides away_abbr/home_abbr.
            return String(team.prefix(3)).uppercased()
        }

        /// Proper FIFA 3-letter code for a WC nation. A naive first-3-letters slice
        /// is both WRONG (Netherlands→NED not NET, Spain→ESP, Morocco→MAR) and, for
        /// Japan, OFFENSIVE ("JAP") — so map the field explicitly. Unlisted → first 3.
        private func wcCode(_ name: String?) -> String {
            guard let name, !name.isEmpty else { return "—" }
            let t = name.lowercased()
            let map: [(String, String)] = [
                ("japan","JPN"),("brazil","BRA"),("germany","GER"),("paraguay","PAR"),
                ("argentina","ARG"),("france","FRA"),("spain","ESP"),("england","ENG"),
                ("portugal","POR"),("netherlands","NED"),("belgium","BEL"),("croatia","CRO"),
                ("italy","ITA"),("morocco","MAR"),("senegal","SEN"),("united states","USA"),
                ("usa","USA"),("mexico","MEX"),("canada","CAN"),("uruguay","URU"),
                ("colombia","COL"),("ecuador","ECU"),("south korea","KOR"),("korea republic","KOR"),
                ("korea","KOR"),("australia","AUS"),("switzerland","SUI"),("denmark","DEN"),
                ("poland","POL"),("serbia","SRB"),("ghana","GHA"),("nigeria","NGA"),
                ("cameroon","CMR"),("ivory coast","CIV"),("côte","CIV"),("tunisia","TUN"),
                ("algeria","ALG"),("egypt","EGY"),("saudi arabia","KSA"),("saudi","KSA"),
                ("iran","IRN"),("qatar","QAT"),("austria","AUT"),("norway","NOR"),
                ("sweden","SWE"),("scotland","SCO"),("wales","WAL"),("ukraine","UKR"),
                ("peru","PER"),("chile","CHI"),("costa rica","CRC"),("panama","PAN"),
                ("jamaica","JAM"),("uzbekistan","UZB"),("jordan","JOR"),("new zealand","NZL"),
                ("türkiye","TUR"),("turkiye","TUR"),("turkey","TUR"),("south africa","RSA"),
                ("cape verde","CPV"),("mali","MLI"),("dr congo","COD"),("venezuela","VEN"),
                ("bolivia","BOL"),
            ]
            if let code = map.first(where: { t.contains($0.0) })?.1 { return code }
            return String(name.uppercased().filter { $0.isLetter }.prefix(3))
        }

        // ── ④ Look-ahead tabs (Starters · Key Returns · Form · Run Profile ·
        // Weather) ─────────────────────────────────────────────────────────────
        //
        // The old version stacked the entire by-sport starters + returns lists
        // inline, which overflowed the screen on a full slate. This is now a
        // tabbed table (mono tab strip idiom):
        // with the active tab in gold, over a FIXED-HEIGHT container that scrolls
        // internally to reach every row — grouped by sport where relevant. Tabs
        // with no data are hidden; the whole section hides if nothing has data.

        /// Which look-ahead lanes actually have data, in display order.
        private var lookAheadAvailable: [LookAheadLane] {
            LookAheadLane.allCases.filter { hasData($0) }
        }
        private func hasData(_ lane: LookAheadLane) -> Bool {
            switch lane {
            case .starters: return !(board?.starters ?? []).isEmpty
            case .returns:  return !(board?.returns ?? []).isEmpty
            case .form:     return !(board?.form ?? []).isEmpty
            case .runProfile: return !(board?.run_profile ?? []).isEmpty
            case .weather:  return !(board?.weather ?? []).isEmpty
            }
        }
        /// Tomorrow's WC matches, earliest kickoff first. Empty on non-WC days.
        private var wcMatches: [TomorrowWcMatch] {
            (board?.wc_lookahead ?? []).sorted {
                ($0.commence_time ?? "") < ($1.commence_time ?? "")
            }
        }
        private var hasMlbLookahead: Bool { !lookAheadAvailable.isEmpty }
        private var hasWcLookahead: Bool { !wcMatches.isEmpty }

        /// "The Day Ahead" — an MLB / WC sport switch over the per-sport look-ahead.
        /// MLB = the tabbed table (Starters · Form · Run Profile · Weather); WC =
        /// the soccer-tailored tabbed table (Form · Key Scorers · Lineups), same
        /// style. The switch only appears when BOTH sports have look-ahead data —
        /// otherwise the single available sport renders alone (no orphan toggle).
        @ViewBuilder private var lookAheadTabs: some View {
            if hasMlbLookahead || hasWcLookahead {
                let sport: LookAheadSport = {
                    if lookAheadSport == .wc, hasWcLookahead { return .wc }
                    if lookAheadSport == .mlb, hasMlbLookahead { return .mlb }
                    return hasMlbLookahead ? .mlb : .wc
                }()
                VStack(alignment: .leading, spacing: 6) {
                    HubSectionHeader(eyebrow: "The Day Ahead", sub: "")
                    // MLB / WC switch — only when both have data.
                    if hasMlbLookahead && hasWcLookahead {
                        HStack(spacing: 18) {
                            ForEach([LookAheadSport.mlb, .wc], id: \.self) { s in
                                Button {
                                    withAnimation(.easeInOut(duration: 0.15)) { lookAheadSport = s }
                                } label: {
                                    Text(s.label)
                                        .font(GaryFonts.mono(11, bold: true)).tracking(1)
                                        .foregroundStyle(s == sport
                                            ? (s == .wc ? wcAccent : GaryColors.gold)
                                            : .white.opacity(0.4))
                                        .frame(minHeight: 30)
                                        .contentShape(Rectangle())
                                }
                                .buttonStyle(.plain)
                            }
                            Spacer()
                        }
                        .padding(.horizontal, 16)
                    }
                    if sport == .wc {
                        wcLookAheadBody
                    } else {
                        mlbLookAheadTable
                    }
                }
            }
        }

        /// The MLB look-ahead — the existing fixed-height, internally-scrolling
        /// tabbed table (Starters · Form · Run Profile · Weather).
        @ViewBuilder private var mlbLookAheadTable: some View {
            let lanes = lookAheadAvailable
            if !lanes.isEmpty {
                let active = lanes[min(lookAheadTab, lanes.count - 1)]
                VStack(alignment: .leading, spacing: 6) {
                    // Mono tab strip — active in gold, the rest dim (app-wide).
                    if lanes.count > 1 {
                        ScrollView(.horizontal, showsIndicators: false) {
                            HStack(spacing: 18) {
                                ForEach(Array(lanes.enumerated()), id: \.element) { i, lane in
                                    Button {
                                        withAnimation(.easeInOut(duration: 0.15)) { lookAheadTab = i }
                                    } label: {
                                        Text(lane.label)
                                            .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                                            .foregroundStyle(i == min(lookAheadTab, lanes.count - 1) ? GaryColors.gold : .white.opacity(0.4))
                                            .frame(minHeight: 30)
                                            .contentShape(Rectangle())
                                    }
                                    .buttonStyle(.plain)
                                }
                            }
                            .padding(.horizontal, 2)
                        }
                        .padding(.horizontal, 16)
                    }
                    // Fixed-height, internally-scrolling table.
                    VStack(spacing: 0) {
                        laneHeader(active)
                        Rectangle().fill(Color.white.opacity(0.1)).frame(height: 1)
                        ScrollView(.vertical, showsIndicators: true) {
                            laneBody(active)
                                .frame(maxWidth: .infinity)
                        }
                        .frame(height: 300)
                        .scrollIndicators(.visible)
                    }
                    .background(Color(hex: "#181616"))
                    .clipShape(RoundedRectangle(cornerRadius: 12))
                    .overlay(RoundedRectangle(cornerRadius: 12).stroke(Color.white.opacity(0.07), lineWidth: 1))
                    .padding(.horizontal, 16)
                }
            }
        }

        // ── WC look-ahead — the SAME tabbed-table style as MLB (founder call),
        // tailored to soccer: Form · Key Scorers · Lineups. Fixed-height,
        // internally scrolling, grouped by match. (Replaced the per-match cards.)
        @ViewBuilder private var wcLookAheadBody: some View {
            let lanes = wcLanesAvailable
            if !lanes.isEmpty {
                let active = lanes[min(wcLookAheadTab, lanes.count - 1)]
                VStack(alignment: .leading, spacing: 6) {
                    if lanes.count > 1 {
                        ScrollView(.horizontal, showsIndicators: false) {
                            HStack(spacing: 18) {
                                ForEach(Array(lanes.enumerated()), id: \.element) { i, lane in
                                    Button {
                                        withAnimation(.easeInOut(duration: 0.15)) { wcLookAheadTab = i }
                                    } label: {
                                        Text(lane.label)
                                            .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                                            .foregroundStyle(i == min(wcLookAheadTab, lanes.count - 1) ? GaryColors.gold : .white.opacity(0.4))
                                            .frame(minHeight: 30)
                                            .contentShape(Rectangle())
                                    }
                                    .buttonStyle(.plain)
                                }
                            }
                            .padding(.horizontal, 2)
                        }
                        .padding(.horizontal, 16)
                    }
                    VStack(spacing: 0) {
                        wcLaneHeader(active)
                        Rectangle().fill(Color.white.opacity(0.1)).frame(height: 1)
                        ScrollView(.vertical, showsIndicators: true) {
                            wcLaneBody(active).frame(maxWidth: .infinity)
                        }
                        .frame(height: 300)
                        .scrollIndicators(.visible)
                    }
                    .background(Color(hex: "#181616"))
                    .clipShape(RoundedRectangle(cornerRadius: 12))
                    .overlay(RoundedRectangle(cornerRadius: 12).stroke(Color.white.opacity(0.07), lineWidth: 1))
                    .padding(.horizontal, 16)
                }
            }
        }

        /// Which WC lanes have data, in display order.
        private var wcLanesAvailable: [WcLane] {
            WcLane.allCases.filter { lane in
                switch lane {
                case .matchup:
                    return wcMatches.contains { $0.lines != nil || $0.away?.form != nil || $0.home?.form != nil }
                case .form:
                    return wcMatches.contains { $0.away?.form != nil || $0.home?.form != nil }
                case .scorers:
                    return wcMatches.contains { !($0.away?.key_players ?? []).isEmpty || !($0.home?.key_players ?? []).isEmpty }
                }
            }
        }

        /// Column headers per WC lane — gold, mirroring the MLB table.
        @ViewBuilder private func wcLaneHeader(_ lane: WcLane) -> some View {
            HStack(spacing: 8) {
                switch lane {
                case .matchup:
                    Text("PROJECTION · WIN PROBABILITY").frame(maxWidth: .infinity, alignment: .leading)
                case .form:
                    Text("TEAM").frame(maxWidth: .infinity, alignment: .leading)
                    Text("IN WC").frame(width: 58, alignment: .trailing)
                    Text("GOALS/GM").frame(width: 72, alignment: .trailing)
                    Text("OPP/GM").frame(width: 58, alignment: .trailing)
                case .scorers:
                    Text("PLAYER / TEAM").frame(maxWidth: .infinity, alignment: .leading)
                    Text("GOALS").frame(width: 52, alignment: .trailing)
                    Text("ASSTS").frame(width: 52, alignment: .trailing)
                }
            }
            .font(GaryFonts.mono(10.5)).tracking(1.2)
            .foregroundStyle(GaryColors.gold)
            .padding(.vertical, 8).padding(.horizontal, 14)
        }

        /// The scrolling rows for the active WC lane, grouped by match.
        @ViewBuilder private func wcLaneBody(_ lane: WcLane) -> some View {
            VStack(spacing: 0) {
                ForEach(Array(wcMatches.enumerated()), id: \.offset) { _, m in
                    if lane == .matchup {
                        wcMatchupCard(m)
                    } else {
                        wcMatchSubHeader(m)
                        switch lane {
                        case .form:
                            wcFormRow(team: m.away_team, side: m.away)
                            wcFormRow(team: m.home_team, side: m.home)
                        case .scorers:
                            wcScorerRows(team: m.away_team, side: m.away)
                            wcScorerRows(team: m.home_team, side: m.home)
                        case .matchup:
                            EmptyView()
                        }
                    }
                }
            }
        }

        /// Match grouping header inside the WC table (teal matchup + kickoff).
        private func wcMatchSubHeader(_ m: TomorrowWcMatch) -> some View {
            HStack(spacing: 6) {
                Text((m.match ?? "\(m.away_team ?? "") @ \(m.home_team ?? "")").uppercased())
                    .font(GaryFonts.mono(10, bold: true)).tracking(0.8)
                    .foregroundStyle(wcAccent.opacity(0.9))
                    .lineLimit(1).minimumScaleFactor(0.8)
                Spacer(minLength: 6)
                if let k = m.kickoff, !k.isEmpty {
                    Text(k.uppercased())
                        .font(GaryFonts.mono(9, bold: true))
                        .foregroundStyle(.white.opacity(0.62))
                }
            }
            .frame(maxWidth: .infinity, alignment: .leading)
            .padding(.top, 9).padding(.bottom, 4).padding(.horizontal, 14)
        }

        /// FORM lane row — team · WC-only record (form-coloured) · goals/gm · opp goals/gm.
        @ViewBuilder private func wcFormRow(team: String?, side: TomorrowWcSide?) -> some View {
            // WC-ONLY record — this tournament's games, not last-5 overall (founder).
            // Falls back to "—" until a side has played a World Cup match.
            let f = side?.form?.wc
            let recColor: Color = {
                guard let w = f?.w, let l = f?.l else { return .white.opacity(0.85) }
                if w > l { return GaryColors.win }
                if l > w { return GaryColors.loss }
                return .white.opacity(0.85)
            }()
            VStack(spacing: 0) {
                HStack(spacing: 8) {
                    Text(side?.team ?? team ?? "—")
                        .font(GaryFonts.text(14, .semibold)).foregroundStyle(.white.opacity(0.92))
                        .lineLimit(1).minimumScaleFactor(0.85)
                        .frame(maxWidth: .infinity, alignment: .leading)
                    Text(f?.record ?? "—")
                        .font(GaryFonts.mono(13, bold: true)).foregroundStyle(recColor)
                        .frame(width: 58, alignment: .trailing)
                    Text(f?.gf_per_game.map { Self.trimNum($0) } ?? "—")
                        .font(GaryFonts.mono(13)).foregroundStyle(.white.opacity(0.85))
                        .frame(width: 72, alignment: .trailing)
                    Text(f?.ga_per_game.map { Self.trimNum($0) } ?? "—")
                        .font(GaryFonts.mono(13)).foregroundStyle(.white.opacity(0.7))
                        .frame(width: 58, alignment: .trailing)
                }
                .padding(.vertical, 9).padding(.horizontal, 14)
                hairline
            }
        }

        /// KEY SCORERS lane — a side's top scorers: name + team · goals · assists.
        @ViewBuilder private func wcScorerRows(team: String?, side: TomorrowWcSide?) -> some View {
            let teamName = side?.team ?? team ?? ""
            let players = Array((side?.key_players ?? []).prefix(3))
            ForEach(Array(players.enumerated()), id: \.offset) { _, p in
                VStack(spacing: 0) {
                    HStack(spacing: 8) {
                        VStack(alignment: .leading, spacing: 2) {
                            Text(p.name ?? "—")
                                .font(GaryFonts.text(14, .semibold)).foregroundStyle(.white.opacity(0.92)).lineLimit(1)
                            Text(teamName)
                                .font(GaryFonts.mono(10.5)).tracking(0.5).foregroundStyle(GaryColors.gold)
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                        Text("\(p.goals ?? 0)")
                            .font(GaryFonts.mono(13, bold: true)).foregroundStyle(GaryColors.gold)
                            .frame(width: 52, alignment: .trailing)
                        Text("\(p.assists ?? 0)")
                            .font(GaryFonts.mono(13)).foregroundStyle(.white.opacity(0.7))
                            .frame(width: 52, alignment: .trailing)
                    }
                    .padding(.vertical, 9).padding(.horizontal, 14)
                    hairline
                }
            }
        }

        /// MATCHUP card — the predictive hero. Projected scoreline from each side's
        /// attack rate (goals/gm) vs the opponent's defense rate (opp goals/gm), the
        /// derived lean, and the market spread/total as context. WC-only rates when a
        /// side has WC games, else its overall form. All grounded in board data.
        @ViewBuilder private func wcMatchupCard(_ m: TomorrowWcMatch) -> some View {
            let awayName = m.away?.team ?? m.away_team ?? "Away"
            let homeName = m.home?.team ?? m.home_team ?? "Home"
            let homeGf = m.home?.form?.wc?.gf_per_game ?? m.home?.form?.gf_per_game
            let homeGa = m.home?.form?.wc?.ga_per_game ?? m.home?.form?.ga_per_game
            let awayGf = m.away?.form?.wc?.gf_per_game ?? m.away?.form?.gf_per_game
            let awayGa = m.away?.form?.wc?.ga_per_game ?? m.away?.form?.ga_per_game
            // Projected goals = (own attack + opponent's concession) / 2.
            let homeProj: Double? = (homeGf != nil && awayGa != nil) ? (homeGf! + awayGa!) / 2 : nil
            let awayProj: Double? = (awayGf != nil && homeGa != nil) ? (awayGf! + homeGa!) / 2 : nil
            VStack(alignment: .leading, spacing: 9) {
                HStack(spacing: 6) {
                    Text((m.match ?? "\(awayName) @ \(homeName)").uppercased())
                        .font(GaryFonts.mono(10, bold: true)).tracking(0.8)
                        .foregroundStyle(wcAccent.opacity(0.9)).lineLimit(1).minimumScaleFactor(0.8)
                    Spacer(minLength: 6)
                    if let k = m.kickoff, !k.isEmpty {
                        Text(k.uppercased()).font(GaryFonts.mono(9, bold: true)).foregroundStyle(.white.opacity(0.62))
                    }
                }
                if let hp = homeProj, let ap = awayProj {
                    // Projected scoreline — the higher number wears gold.
                    HStack(spacing: 8) {
                        Text("PROJECTED").font(GaryFonts.mono(8.5, bold: true)).tracking(1).foregroundStyle(.white.opacity(0.62))
                        Spacer(minLength: 4)
                        Text(wcCode(awayName)).font(GaryFonts.mono(11)).foregroundStyle(.white.opacity(0.7))
                        Text(String(format: "%.1f", ap)).font(GaryFonts.mono(16, bold: true)).foregroundStyle(ap >= hp ? GaryColors.gold : .white.opacity(0.88))
                        Text("–").font(GaryFonts.mono(13)).foregroundStyle(.white.opacity(0.62))
                        Text(String(format: "%.1f", hp)).font(GaryFonts.mono(16, bold: true)).foregroundStyle(hp >= ap ? GaryColors.gold : .white.opacity(0.88))
                        Text(wcCode(homeName)).font(GaryFonts.mono(11)).foregroundStyle(.white.opacity(0.7))
                    }
                    // WIN% — true W/D/L from the Poisson scoreline grid (the favorite golds).
                    let odds = Self.matchOdds(lambdaHome: hp, lambdaAway: ap, totalLine: m.lines?.total)
                    let topP = max(odds.pHome, odds.pDraw, odds.pAway)
                    HStack(spacing: 6) {
                        Text("WIN%").font(GaryFonts.mono(8.5, bold: true)).tracking(1).foregroundStyle(.white.opacity(0.62))
                        Spacer(minLength: 4)
                        Text("\(wcCode(awayName)) \(Self.pct(odds.pAway))")
                            .font(GaryFonts.mono(11, bold: true)).foregroundStyle(odds.pAway >= topP ? GaryColors.gold : .white.opacity(0.7))
                        Text("Draw \(Self.pct(odds.pDraw))")
                            .font(GaryFonts.mono(10, bold: true)).foregroundStyle(odds.pDraw >= topP ? GaryColors.gold : .white.opacity(0.5))
                        Text("\(wcCode(homeName)) \(Self.pct(odds.pHome))")
                            .font(GaryFonts.mono(11, bold: true)).foregroundStyle(odds.pHome >= topP ? GaryColors.gold : .white.opacity(0.7))
                    }
                    // Proportional 3-segment bar: away (teal) · draw (grey) · home (gold).
                    GeometryReader { g in
                        HStack(spacing: 1.5) {
                            Capsule().fill(wcAccent).frame(width: max(2, g.size.width * odds.pAway))
                            Capsule().fill(Color.white.opacity(0.22)).frame(width: max(2, g.size.width * odds.pDraw))
                            Capsule().fill(GaryColors.gold).frame(width: max(2, g.size.width * odds.pHome))
                        }
                    }
                    .frame(height: 5)
                    // Modal scoreline (away–home, matching PROJECTED) + P(over the line).
                    HStack(spacing: 6) {
                        Text("LIKELY SCORE").font(GaryFonts.mono(8.5, bold: true)).tracking(1).foregroundStyle(.white.opacity(0.62))
                        Text("\(odds.likelyAway)–\(odds.likelyHome)").font(GaryFonts.mono(13, bold: true)).foregroundStyle(.white.opacity(0.92))
                        Text("\(wcCode(awayName))–\(wcCode(homeName))").font(GaryFonts.mono(8.5)).foregroundStyle(.white.opacity(0.62))
                        if let po = odds.pOver, let t = m.lines?.total {
                            Text("·").foregroundStyle(.white.opacity(0.62)).font(GaryFonts.mono(11))
                            Text("Over \(Self.trimNum(t)) \(Self.pct(po))").font(GaryFonts.mono(10, bold: true)).foregroundStyle(.white.opacity(0.72))
                        }
                        Spacer(minLength: 0)
                    }
                } else {
                    Text("Projection posts as both sides log World Cup games.")
                        .font(GaryFonts.mono(10)).foregroundStyle(.white.opacity(0.62))
                }
                // Market context — the board's spread + total.
                if m.lines?.spread != nil || m.lines?.total != nil {
                    HStack(spacing: 10) {
                        Text("MARKET").font(GaryFonts.mono(8.5, bold: true)).tracking(1).foregroundStyle(.white.opacity(0.62))
                        if let sp = m.lines?.spread { Text("spread \(Self.trimNum(abs(sp)))").font(GaryFonts.mono(10)).foregroundStyle(.white.opacity(0.6)) }
                        if let t = m.lines?.total { Text("total \(Self.trimNum(t))").font(GaryFonts.mono(10)).foregroundStyle(.white.opacity(0.6)) }
                        Spacer(minLength: 0)
                    }
                }
            }
            .padding(.vertical, 11).padding(.horizontal, 14)
            .overlay(hairline, alignment: .bottom)
        }

        /// Recent-form colour vs W/L: green winning, neutral even, red losing.
        private func wcFormColor(_ f: TomorrowWcForm?) -> Color {
            guard let f = f, let w = f.w, let l = f.l else { return .white.opacity(0.85) }
            if w > l { return GaryColors.win }
            if l > w { return GaryColors.loss }
            // Even record (W == L): neutral white, NOT gold — gold is the brand accent,
            // and reading an even record as highlighted was confusing (Paraguay 2-1-2).
            return .white.opacity(0.85)
        }

        /// The projected XI names (keeper first), grounded — empty when no XI.
        private func wcXiNames(_ xi: TomorrowWcXI?) -> [String] {
            guard let xi else { return [] }
            var names = (xi.xi ?? []).compactMap { $0.n }.filter { !$0.isEmpty }
            if let gk = xi.keeper, !gk.isEmpty, !names.contains(gk) {
                names.insert(gk, at: 0)
            }
            return names
        }

