/// Reverse keyword index (lowercased name keyword → the abbreviations it maps to,
/// across all leagues), built once. Used to resolve a full-team-name matchup side
/// to its abbreviation(s) in ~O(1) — the inverse of the per-row keyword scan that
/// `abbrGameMatches` runs. Cross-league keyword collisions are preserved (a token
/// can yield several abbrs); the matchup-key builder intersects both sides so a
/// real game still lands on a single key.
let reverseTeamKeywordIndex: [String: Set<String>] = {
    var idx: [String: Set<String>] = [:]
    for map in [mlbTeamKeywords, nbaTeamKeywords, nhlTeamKeywords, wcTeamKeywords] {
        for (abbr, kws) in map {
            for kw in kws { idx[kw, default: []].insert(abbr.uppercased()) }
        }
    }
    return idx
}()

/// Normalized matchup key for the LiveScoreCache index, built from a score row's
/// away/home ABBREVIATIONS ("SD","PHI" → "SD|PHI"). Lowercased+joined so the
/// query side (matchupAbbrKey) lands on the exact same string.
func liveScoreMatchupKey(awayAbbr: String?, homeAbbr: String?) -> String? {
    guard let a = awayAbbr?.uppercased(), let h = homeAbbr?.uppercased(),
          !a.isEmpty, !h.isEmpty else { return nil }
    return "\(a)|\(h)"
}

/// Resolve a full-team-name matchup ("San Diego Padres @ Philadelphia Phillies")
/// to the candidate "AWY|HOM" abbr keys the live-score index is built on. Returns
/// every combination because a side can carry abbr aliases (CWS/CHW, ATH/OAK) and
/// cross-league collisions — the score row stored ONE concrete abbr, so we probe
/// all candidates and the right one hits. Empty when neither side resolves (caller
/// falls back to the linear scan, so reach is never lost).
func matchupAbbrKeys(_ matchup: String) -> [String] {
    func abbrs(for side: String) -> [String] {
        let hay = side.lowercased()
        var hits: [String] = []
        var seen = Set<String>()
        // Longest keywords first so "white sox" wins over a bare token.
        for (kw, abset) in reverseTeamKeywordIndex.sorted(by: { $0.key.count > $1.key.count }) {
            guard hay.contains(kw) else { continue }
            for ab in abset where !seen.contains(ab) { seen.insert(ab); hits.append(ab) }
        }
        return hits
    }
    let sides = matchup.components(separatedBy: " @ ")
    guard sides.count == 2 else { return [] }
    let away = abbrs(for: sides[0]), home = abbrs(for: sides[1])
    guard !away.isEmpty, !home.isEmpty else { return [] }
    var keys: [String] = []
    for a in away { for h in home { keys.append("\(a)|\(h)") } }
    return keys
}

/// Match an "AWY @ HOM" abbreviation label (a hub edge's `game`) against a
/// full-team-name matchup string. Both abbreviations must resolve (via the
/// MLB, NBA, or World Cup keyword maps) to a name present in the matchup —
/// collisions (MIN Twins vs MIN Timberwolves, COL Rockies vs COL Colombia)
/// sort themselves out because BOTH sides must match the same matchup.
/// Compact in-card status text: "LIVE 4–6 · INN 7" / "FINAL · 4–6" (away–home;
/// the card already names the teams, so no abbreviations).
func liveSlotText(_ ls: LiveScore, label: String) -> String {
    var bits: [String] = [label]
    if let a = ls.away_score, let h = ls.home_score { bits.append("\(a)–\(h)") }
    if label == "LIVE", let det = ls.detail, !det.isEmpty, det != "LIVE" { bits.append(det) }
    return bits.joined(separator: " · ")
}

/// The rich live line shared by game + prop cards so they read identically:
/// team abbrs + score + the live situation. WC/NBA/NHL carry the poller's
/// `detail` (match minute "67'" / "Q3 4:12" / period); MLB adds outs + base
/// runners. e.g. "LIVE · URU 0 · KSA 1 · 67'" or
/// "LIVE · SD 4 · PHI 6 · BOT 7 · 2 OUT · 1B·3B".
/// Standard team abbreviation from a name via the league keyword maps. Global so any card
/// footer can label a settled score ("CHC 10 · NYM 3", not a bare "10-3" that hides who won).
func teamAbbrevFromName(_ name: String, league: String? = nil) -> String {
    let lower = name.lowercased()
    let maps: [[String: [String]]]
    switch (league ?? "").uppercased() {
    case "MLB": maps = [mlbTeamKeywords]
    case "NBA": maps = [nbaTeamKeywords]
    case "NHL": maps = [nhlTeamKeywords]
    case "WC": maps = [wcTeamKeywords]
    default: maps = [mlbTeamKeywords, nbaTeamKeywords, nhlTeamKeywords, wcTeamKeywords]
    }
    for map in maps {
        for (ab, kws) in map where kws.contains(where: { lower.contains($0) }) { return ab }
    }
    let last = lower.split(separator: " ").last.map(String.init) ?? lower
    return String(last.prefix(3)).uppercased()
}

/// A settled score WITH team labels ("CHC 10 · NYM 3") from a matchup + a raw "10-3".
/// Falls back to the raw score if it can't parse. Global — shared by every card footer.
/// 2026 World Cup phase (ET calendar) — keeps storefront copy honest as the
/// tournament moves: "kicks off June 11" is a lie by June 12.
enum WCPhase { case preTournament, live, done }
func worldCupPhase(now: Date = Date()) -> WCPhase {
    var cal = Calendar(identifier: .gregorian)
    if let tz = TimeZone(identifier: "America/New_York") { cal.timeZone = tz }
    let kickoff = DateComponents(calendar: cal, year: 2026, month: 6, day: 11).date ?? .distantFuture
    let dayAfterFinal = DateComponents(calendar: cal, year: 2026, month: 7, day: 20).date ?? .distantFuture
    if now < kickoff { return .preTournament }
    if now < dayAfterFinal { return .live }
    return .done
}

func finalScoreLine(matchup: String, raw: String, league: String? = nil) -> String {
    let parts = raw.components(separatedBy: CharacterSet(charactersIn: "-\u{2013}")).map { $0.trimmingCharacters(in: .whitespaces) }
    let teams = matchup.components(separatedBy: " @ ")
    guard parts.count == 2, teams.count == 2 else { return raw }
    return "\(teamAbbrevFromName(teams[0], league: league)) \(parts[0]) \u{00B7} \(teamAbbrevFromName(teams[1], league: league)) \(parts[1])"
}

func liveLineRich(_ ls: LiveScore, label: String) -> String {
    var bits: [String] = [label]
    // FINAL gets team labels so a settled score says who scored what.
    if label == "FINAL", let a = ls.away_score, let h = ls.home_score, let aw = ls.away_abbr, let hm = ls.home_abbr {
        bits.append("\(aw) \(a) \u{00B7} \(hm) \(h)")
    } else if let sl = ls.scoreLine { bits.append(sl) }
    else if let a = ls.away_score, let h = ls.home_score { bits.append("\(a)–\(h)") }
    guard label == "LIVE" else { return bits.joined(separator: " · ") }
    if let det = ls.detail, !det.isEmpty, det != "LIVE", det != "FINAL" { bits.append(det) }
    if (ls.league ?? "").uppercased() == "MLB" {
        if let o = ls.outs { bits.append("\(o) OUT") }
        let runners = [ls.onFirst ? "1B" : nil, ls.onSecond ? "2B" : nil, ls.onThird ? "3B" : nil].compactMap { $0 }
        if !runners.isEmpty { bits.append(runners.joined(separator: "·")) }
    }
    return bits.joined(separator: " · ")
}

/// Conviction tiers — Gary's vocabulary, not calculator language ("82%" is
/// fake precision and self-inflicted accountability). Bands set from the real
/// Apr–Jun 2026 confidence distribution so the tiers actually spread:
/// 27% SPRINKLE · 48% LEAN · 25% HAMMER.
func convictionTier(_ confidence: Double) -> String {
    confidence >= 0.80 ? "HAMMER" : confidence >= 0.70 ? "LEAN" : "SPRINKLE"
}

/// Splits a rationale into (take, rest): the opening 1–2 SENTENCES lead the
/// card back at quote weight and seed the front quote + share card. Sentence-
/// walked (not paragraph-split) because stored rationales open with a single
/// ~850-char paragraph; works for the current announcer voice and any future
/// shorter one. Strips the literal "Gary's Take" heading the JSON template
/// pastes in. Anything that doesn't split cleanly renders whole as `rest`.
func splitTake(_ rationale: String?) -> (take: String?, rest: String?) {
    guard var r = rationale?.trimmingCharacters(in: .whitespacesAndNewlines), !r.isEmpty else {
        return (nil, "No rationale available.")
    }
    if r.lowercased().hasPrefix("gary's take") {
        r = String(r.dropFirst("gary's take".count)).trimmingCharacters(in: .whitespacesAndNewlines)
    }

    // Sentence boundaries: ./!/? followed by whitespace, where the word
    // before the period isn't an abbreviation ("St. Louis", "Jr.", "vs.").
    let abbreviations: Set<String> = ["st", "jr", "sr", "dr", "vs", "mr", "mrs", "no"]
    var boundaries: [String.Index] = []
    var i = r.startIndex
    while i < r.endIndex, boundaries.count < 3 {
        let ch = r[i]
        if ch == "." || ch == "!" || ch == "?" {
            let next = r.index(after: i)
            if next == r.endIndex || r[next] == " " || r[next] == "\n" {
                let wordStart = r[..<i].lastIndex(where: { $0 == " " || $0 == "\n" })
                    .map { r.index(after: $0) } ?? r.startIndex
                if !abbreviations.contains(r[wordStart..<i].lowercased()) {
                    boundaries.append(next)
                }
            }
        }
        i = r.index(after: i)
    }

    // The take = the longest 1–2 sentence opening that stays under ~300
    // chars — enough to be a real quote, short enough to BE a quote.
    var cut: String.Index? = nil
    for end in boundaries.prefix(2) {
        if r.distance(from: r.startIndex, to: end) <= 300 { cut = end } else { break }
    }
    guard let cutIdx = cut else { return (nil, r) }
    let take = String(r[..<cutIdx]).trimmingCharacters(in: .whitespacesAndNewlines)
    let rest = String(r[cutIdx...]).trimmingCharacters(in: .whitespacesAndNewlines)
    guard take.count >= 40, !rest.isEmpty else { return (nil, r) }
    return (take, rest)
}


/// League priority for defaults, headlines and board order while a
/// championship round is running: a Finals game outranks the nightly MLB
/// slate; the World Cup owns its own Home module but ranks above the daily
/// slate elsewhere. Static for now — revisit in the fall, when the World
/// Series vs NBA regular season flips this.
enum LeaguePriority {
    static func rank(_ league: String?) -> Int {
        switch (league ?? "").uppercased() {
        case "NBA": return 0
        case "WC", "SOCCER_WORLD_CUP", "SOCCER": return 1
        case "MLB": return 2
        default: return 3
        }
    }
}

func abbrGameMatches(_ abbrGame: String, matchup: String) -> Bool {
    let hay = matchup.lowercased()
    let abbrevs = abbrGame.uppercased()
        .components(separatedBy: CharacterSet(charactersIn: " @/"))
        .filter { $0.count >= 2 }
    guard abbrevs.count >= 2 else { return false }
    return abbrevs.allSatisfy { ab in
        let kws = (mlbTeamKeywords[ab] ?? []) + (nbaTeamKeywords[ab] ?? []) + (nhlTeamKeywords[ab] ?? []) + (wcTeamKeywords[ab] ?? [])
        return kws.contains { hay.contains($0) }
    }
}

/// Resolve a LiveScore's away/home runs into the orientation of a pick's
/// matchup. Defensive: live rows and picks come from the same slates so they
/// should already align, but a verdict grades against NAMES, never positions.
func orientedFinalScores(_ ls: LiveScore, awayTeam: String?, homeTeam: String?) -> (away: Int, home: Int)? {
    guard let a = ls.away_score, let h = ls.home_score else { return nil }
    func matches(_ abbr: String?, _ team: String?) -> Bool {
        guard let ab = abbr?.uppercased(), let hay = team?.lowercased(), !hay.isEmpty else { return false }
        let kws = (mlbTeamKeywords[ab] ?? []) + (nbaTeamKeywords[ab] ?? []) + (nhlTeamKeywords[ab] ?? []) + (wcTeamKeywords[ab] ?? [])
        return kws.contains { hay.contains($0) }
    }
    if matches(ls.away_abbr, awayTeam) || matches(ls.home_abbr, homeTeam) { return (a, h) }
    if matches(ls.away_abbr, homeTeam) || matches(ls.home_abbr, awayTeam) { return (h, a) }
    return (a, h)
}

/// Grade a game pick (spread / moneyline / total) against a FINAL score.
/// Returns "won" / "lost" / "push", or nil when the verdict can't be called
/// confidently (unparseable side, or a drawn moneyline — soccer three-ways
/// are the backend grader's call). pickText must already have odds stripped.
func liveGradeGamePick(pickText: String, betType: String = "", awayPicked: Bool, homePicked: Bool, away: Int, home: Int) -> String? {
    func firstDouble(_ pattern: String, in s: String) -> Double? {
        guard let rx = try? NSRegularExpression(pattern: pattern),
              let m = rx.firstMatch(in: s, range: NSRange(s.startIndex..., in: s)),
              let r = Range(m.range, in: s) else { return nil }
        return Double(s[r])
    }
    let lower = pickText.lowercased()
    // Totals — "OVER 8.5" / "UNDER 7".
    if lower.contains("over") || lower.contains("under") {
        guard let line = firstDouble(#"\d+(?:\.\d+)?"#, in: lower) else { return nil }
        let total = Double(away + home)
        if total == line { return "push" }
        return (total > line) == lower.contains("over") ? "won" : "lost"
    }
    // 3-way moneyline DRAW pick (soccer/WC: win · tie · lose) — Gary took the
    // tie, so it wins ONLY on a level result.
    if betType.lowercased() == "draw" || lower.contains("draw") {
        return away == home ? "won" : "lost"
    }
    // Side picks — need a side to grade.
    let picked: Int, other: Int
    if homePicked { picked = home; other = away }
    else if awayPicked { picked = away; other = home }
    else { return nil }
    let margin = Double(picked - other)
    // Spread — a signed line in the pick ("PHI -1.5", "Jazz +7").
    if let line = firstDouble(#"[-+]\d+(?:\.\d+)?"#, in: pickText) {
        let adjusted = margin + line
        if adjusted == 0 { return "push" }
        return adjusted > 0 ? "won" : "lost"
    }
    // Moneyline — a team-to-win pick LOSES on a draw (3-way market: win · tie ·
    // lose). Only soccer can finish level; 2-way sports never reach margin == 0
    // at FINAL, so this stays correct for MLB / NBA / NHL.
    return margin > 0 ? "won" : "lost"
}

enum PicksDay { case today, yesterday }

struct PicksCarouselView: View {
    @Environment(\.scenePhase) private var scenePhase
    @StateObject private var store = PropsSlateStore()
    /// Observe the live-score cache so the board re-renders the moment a game goes
    /// live or final. It was read via .shared without observing, so a running app
    /// kept showing the scheduled time ("1:00 PM ET") until the user relaunched.
    @ObservedObject private var liveCache = LiveScoreCache.shared
    /// Today vs Yesterday — the day dropdown (user call, Jun 17) replaces the old
    /// mixed matchup row + per-tab "YESTERDAY" tags. Today shows upcoming-first
    /// matchups; Yesterday shows that day's matchups + picks with CASHED/LOST tags.
    @State private var pickDay: PicksDay = .today
    @StateObject private var focusState = PicksFocusState.shared
    @State private var connections: [Signal] = []
    @State private var connLoaded = false
    @State private var sport = "ALL"
    @State private var page = 0
    @State private var selectedProp: PropPick?
    /// PERF#1(b/c): memoized UNSORTED game set + precomputed per-game edge index.
    /// Rebuilt by rebuildMemo() only when picks/props/slate/connections or the
    /// day/sport filter change — never on a live-score tick. The cheap live-status
    /// sort layers on top in `games`, so a 20-25s score publish re-orders + relabels
    /// without redoing the grouping or the games×connections edge scan.
    @State private var gamesMemo: [(matchup: String, time: String, props: [PropPick])] = []
    @State private var edgeIndex: [String: [Signal]] = [:]
    /// Masthead + strip context (founder, Jul 22: the Hub's upper part —
    /// wordmark, LAST 7 DAYS line, double rule, slate strip — is the Picks
    /// page's top now): the rolling 7-day pick record, and the day board for
    /// each strip block's O/U.
    @State private var record7: (w: Int, l: Int)? = nil
    @State private var stripBoard: TomorrowBoard? = nil

    /// Every league with content: today's props/picks plus the per-sport
    /// yesterday recaps (a sport with no picks today shows its results —
    /// the same rule the rest of the app follows).
    /// 2.16: Home-run bets live in The Hub's Home Run Threats lane now, so the
    /// Picks page no longer carries an MLB HR tab or any HR pick cards. A prop is
    /// an HR bet by its TYPE, not its league label — matching the prop name also
    /// drops genuine HR props that arrive tagged plain "MLB", while leaving non-HR
    /// props mislabeled "MLB HR" upstream to keep routing to the MLB tab.
    private func isHomeRunProp(_ p: PropPick) -> Bool {
        let t = (p.prop ?? "").lowercased()
        return t.contains("home_run") || t.contains("home run")
    }
    private var sports: [String] {
        var s = Set(store.slateProps.filter { !isHomeRunProp($0) }.compactMap { ($0.effectiveLeague ?? "").uppercased() }.filter { !$0.isEmpty })
        s.formUnion(store.gamePicks.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty })
        s.formUnion(store.yesterdayGamePicks.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty })
        // Today's slate leagues too — so a sport with games tonight but no picks
        // yet still gets a filter chip (matches the look-ahead matchups below).
        s.formUnion(store.slate.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty })
        // The MLB HR lane is retired — guarantee no HR chip even if a non-HR prop
        // arrives mislabeled "MLB HR" (its card already routes to MLB via propSportKey).
        s.remove("MLB HR")
        // Display priority — WC leads, then MLB (user call Jun 13 2026: the World
        // Cup outranks MLB while it's on, so it sits closest to ALL). Anything
        // else falls back to alphabetical.
        // A league with games TODAY always outranks an idle one (founder,
        // Jul 12: WC before MLB on a no-WC day made no sense); canonical
        // priority only breaks ties inside each group.
        let todayLeagues = Set(store.slate.compactMap { ($0.league ?? "").uppercased() })
        let priority: [String: Int] = ["WC": 0, "MLB": 1]
        // ALL is flag-gated (founder, Jul 13: league chips only) — the chip
        // drops but every ALL code path below survives for an easy restore.
        return (AppFlags.picksAllTab ? ["ALL"] : []) + s.sorted { a, b in
            let ta = todayLeagues.contains(a), tb = todayLeagues.contains(b)
            if ta != tb { return ta }
            let ra = priority[a] ?? 50, rb = priority[b] ?? 50
            return ra == rb ? a < b : ra < rb
        }
    }

    /// With ALL hidden, `sport` must always sit on a real league: snap the
    /// "ALL" default (and any league that dropped off the board) to the day's
    /// first chip once data lands. No-op while the flag shows ALL.
    private func snapSportIfAllHidden() {
        guard !AppFlags.picksAllTab,
              sport == "ALL" || !sports.contains(sport),
              let first = sports.first(where: { $0 != "ALL" }) else { return }
        sport = first
    }
    /// A prop's tab key, with the MLB HR lane corrected to HOME-RUN props only.
    /// Non-HR props (total_bases, strikeouts) get mislabeled "MLB HR" upstream;
    /// route those to the regular MLB tab so the HR tab shows only HR bets
    /// (mirrors the storefront's propLeagueKey guard).
    private func propSportKey(_ p: PropPick) -> String {
        let key = (p.effectiveLeague ?? "").uppercased()
        if key == "MLB HR" {
            let t = (p.prop ?? "").lowercased()
            if !t.contains("home_run") && !t.contains("home run") { return "MLB" }
        }
        return key
    }
    private var filteredProps: [PropPick] {
        let base = store.slateProps.filter { !isHomeRunProp($0) }   // HR retired from Picks
        return sport == "ALL" ? base : base.filter { propSportKey($0) == sport }
    }
    /// TODAY's matchup rail uses today's FRESH props only. store.allProps is
    /// already freshness-filtered to games at/after the start of today (EST);
    /// slateProps additionally folds in yesterday's recap props for sports with
    /// nothing today — right for the results fallback, but it must NOT seed
    /// today's matchup tabs or yesterday's games leak into TODAY (the
    /// "Jays @ Sox · WEDNESDAY 6:45 PM" bug under a sport with no props yet).
    private var filteredTodayProps: [PropPick] {
        let today = store.allProps.filter { !$0.isTDPick && !isHomeRunProp($0) }   // HR retired from Picks
        return sport == "ALL" ? today : today.filter { propSportKey($0) == sport }
    }
    /// Yesterday's own props (sport-scoped, no TD picks) — the source for the
    /// Yesterday matchup row so every settled game shows, not just slate leftovers.
    private var filteredYesterdayProps: [PropPick] {
        let yp = store.yesterdayPropsAll.filter { !$0.isTDPick && !isHomeRunProp($0) }   // ungated: all of yesterday, HR retired
        return sport == "ALL" ? yp : yp.filter { propSportKey($0) == sport }
    }
    /// PERF#1(b): the heavy grouping/merge/look-ahead, memoized into `gamesMemo`
    /// and recomputed ONLY when picks/props/slate/day/sport change (see rebuildMemo)
    /// — never on a live-score tick. Returns the UNSORTED set; the cheap live-status
    /// sort lives in `games` so a 20-25s tick only re-orders, it never re-groups.
    private func computeGamesUnsorted() -> [(matchup: String, time: String, props: [PropPick])] {
        // The matchup row is day-scoped (the dropdown): Today groups today's slate
        // props; Yesterday groups yesterday's own props — sourcing the day directly
        // (not a fresh/stale filter on a shared list) is what makes EVERY yesterday
        // game show, not just the one that leaked into today's slate.
        let dayProps = pickDay == .today ? filteredTodayProps : filteredYesterdayProps
        var out = store.groupByMatchup(dayProps)
        var seenKeys = Set(out.map { Self.matchupKey($0.matchup) })
        func gameMatchup(_ p: GaryPick) -> String {
            let a = (p.awayTeam ?? "").trimmingCharacters(in: .whitespaces)
            let h = (p.homeTeam ?? "").trimmingCharacters(in: .whitespaces)
            return (a.isEmpty || h.isEmpty) ? "" : "\(a) @ \(h)"
        }
        func gameTime(_ p: GaryPick) -> String {
            if let iso = p.commence_time, let d = parseISO8601(iso) {
                return Formatters.tabTimeFormatterEST.string(from: d) + " ET"
            }
            return p.time ?? ""
        }
        // Merge in EVERY game pick for the day (all leagues), deduped against the
        // prop matchups by team last-words — so a game with a pick but no prop still
        // gets a tab. (Skipping prop-leagues here was what dropped most of Yesterday.)
        func merge(_ picks: [GaryPick]) {
            for p in picks {
                let lg = (p.league ?? "").uppercased()
                guard !lg.isEmpty, sport == "ALL" || lg == sport else { continue }
                let mu = gameMatchup(p)
                guard !mu.isEmpty else { continue }
                let key = Self.matchupKey(mu)
                guard !seenKeys.contains(key) else { continue }
                seenKeys.insert(key)
                out.append((matchup: mu, time: gameTime(p), props: []))
            }
        }
        merge(pickDay == .today ? store.gamePicks : store.yesterdayGamePicksAll)

        // LOOK-AHEAD (today only): include every game on today's slate so the user
        // sees tonight's matchups with a placeholder + intel before picks post.
        if pickDay == .today {
            for s in store.slate {
                let lg = (s.league ?? "").uppercased()
                guard sport == "ALL" || lg == sport else { continue }
                let a = (s.away_team ?? "").trimmingCharacters(in: .whitespaces)
                let h = (s.home_team ?? "").trimmingCharacters(in: .whitespaces)
                guard !a.isEmpty, !h.isEmpty else { continue }
                let mu = "\(a) @ \(h)"
                let key = Self.matchupKey(mu)
                guard !seenKeys.contains(key) else { continue }
                seenKeys.insert(key)
                let time: String = {
                    if let iso = s.commence_time, let d = parseISO8601(iso) {
                        return Formatters.tabTimeFormatterEST.string(from: d) + " ET"
                    }
                    return ""
                }()
                out.append((matchup: mu, time: time, props: []))
            }
        }
        return out
    }

    private var games: [(matchup: String, time: String, props: [PropPick])] {
        let out = gamesMemo
        // Today: LIVE games first, then upcoming by start time, then finished/graded
        // bumped to the very back — so the bar stays current as the day rolls on.
        // Yesterday is already all-settled; keep its existing time order. This is the
        // only per-tick work (a small sort over an already-built set) — the grouping
        // above is memoized, so a live-score publish re-orders without re-grouping.
        guard pickDay == .today else { return out }
        return out
            .map { (g: $0, bucket: gameStatusBucket($0), start: gameStart($0)) }
            .sorted { ($0.bucket, $0.start) < ($1.bucket, $1.start) }
            .map { $0.g }
    }

    /// Recompute the memoized game set + edge index. Called on first load and
    /// whenever the underlying picks/props/slate/connections or the day/sport
    /// filter change — NOT on live-score ticks. `nonEmptyKeysOf` guards the
    /// keep-last-good rule the store already follows (never blank a populated bar
    /// on a transient empty refresh).
    private func rebuildMemo() {
        let built = computeGamesUnsorted()
        gamesMemo = built
        // PERF#1(c): precompute each game's edge list ONCE (the N×M games×connections
        // scan), keyed by the game's matchup key, so edges(for:) is an O(1) dict
        // lookup at render time instead of re-scanning every connection against every
        // game on every render/live tick. Same dual match as the old edges(for:):
        // an edge attaches if its abbr-game resolves against the game's matchup+prop
        // teams (abbrGameMatches) OR shares the last-word matchup key (WC nations).
        var idx: [String: [Signal]] = [:]
        for g in built {
            let hay = g.matchup + " " + g.props.compactMap { $0.team }.joined(separator: " ")
            let gKey = Self.matchupKey(g.matchup)
            idx[gKey] = connections.filter { abbrGameMatches($0.game, matchup: hay) || Self.matchupKey($0.game) == gKey }
        }
        edgeIndex = idx
    }

    /// Match key from team last-words ("San Diego Padres @ LA Dodgers" →
    /// "padres|dodgers") — dedups the slate's full names against the picks/props
    /// short matchup format.
    static func matchupKey(_ m: String) -> String {
        let sides = m.lowercased().components(separatedBy: " @ ")
        guard sides.count == 2 else { return m.lowercased() }
        let a = sides[0].components(separatedBy: " ").last ?? sides[0]
        let h = sides[1].components(separatedBy: " ").last ?? sides[1]
        return "\(a)|\(h)"
    }

    /// Matchup-bar order: LIVE (0) → upcoming (1) → finished/graded (2). Reads the
    /// live-score cache, so a game sinks to the back the moment it goes final.
    private func gameStatusBucket(_ g: (matchup: String, time: String, props: [PropPick])) -> Int {
        if let ls = LiveScoreCache.shared.status(forMatchup: g.matchup) {
            if ls.isFinal { return 2 }
            if ls.isLive { return 0 }
        }
        return 1
    }
    /// Kickoff/first-pitch as a Date, to order within a bucket (earliest game up
    /// next) — from the matchup's props, else today's slate row, else its game pick.
    private func gameStart(_ g: (matchup: String, time: String, props: [PropPick])) -> Date {
        if let iso = g.props.first?.commence_time, let d = parseISO8601(iso) { return d }
        let key = Self.matchupKey(g.matchup)
        if let s = store.slate.first(where: { Self.matchupKey("\($0.away_team ?? "") @ \($0.home_team ?? "")") == key }),
           let iso = s.commence_time, let d = parseISO8601(iso) { return d }
        if let p = store.gamePicksForMatchup(g.matchup, preferYesterday: false).first?.pick,
           let iso = p.commence_time, let d = parseISO8601(iso) { return d }
        return .distantFuture
    }
    private var topProps: [PropPick] {
        // The selected day's props only (dropdown): Today = fresh, Yesterday = settled.
        let dayProps = filteredProps.filter {
            pickDay == .today ? !store.isYesterdayProp($0) : store.isYesterdayProp($0)
        }
        return Array(dayProps.sorted { ($0.confidence ?? 0) > ($1.confidence ?? 0) }.prefix(2))
    }
    /// The selected day's top pick — today's (fresh) or yesterday's (stamped).
    private var topGamePick: (pick: GaryPick, isYesterday: Bool)? {
        let source = pickDay == .today ? store.gamePicks : store.yesterdayGamePicks
        let filtered = (sport == "ALL") ? source : source.filter { ($0.league ?? "").uppercased() == sport }
        guard let p = filtered.sorted(by: { ($0.confidence ?? 0) > ($1.confidence ?? 0) }).first else { return nil }
        return (p, pickDay == .yesterday)
    }
    private var hasContent: Bool { !topProps.isEmpty || topGamePick != nil || !games.isEmpty }

    var body: some View {
        ZStack {
            LiquidGlassBackground(grainDensity: 0)
            VStack(spacing: 0) {
                masthead
                slateStrip
                content
            }
        }

        .task {
            await store.loadIfNeeded()
            rebuildMemo()          // build the memo before consumeFocus reads `games`
            snapSportIfAllHidden()
            consumeFocus()
            if !connLoaded { await loadConnections() }
            rebuildMemo()          // fold the just-loaded connections into the edge index
        }
        .task {
            // Masthead/strip context — both cached, both safe to miss (the record
            // line and O/U just stay off until they land).
            if stripBoard == nil { stripBoard = await TodayBoardCache.get() }
            if record7 == nil { record7 = await SupabaseAPI.fetchSevenDayPickRecord() }
        }
        .task {
            // Keep the SHARED live-score cache warm while this tab is on screen — the
            // matchup tabs and the cards both read LiveScoreCache.shared now (it owns
            // the dedup + its own adaptive refresh loop), so this page no longer keeps
            // its own snapshot that could disagree with the cards.
            LiveScoreCache.shared.startIfNeeded()
        }
        .onChange(of: sport) { _ in page = 0; rebuildMemo() }
        .onChange(of: pickDay) { _ in rebuildMemo() }
        .onChange(of: connLoaded) { _ in rebuildMemo() }
        // The store's picks/props/slate settle asynchronously after each load — a
        // count signature fires rebuildMemo() once they land (and after a refresh),
        // so the memo tracks the data without recomputing on every live-score tick.
        .onChange(of: dataSignature) { _ in rebuildMemo(); snapSportIfAllHidden() }
        .onChange(of: focusState.focusGame) { _ in consumeFocus() }
        .onChange(of: store.loading) { loading in if !loading { consumeFocus() } }
        .onChange(of: scenePhase) { phase in
            // Foreground → silently re-pull picks/props (the spinner is gated by
            // !hasContent, so existing data stays put while fresh rows load underneath).
            if phase == .active { Task { await store.refresh() } }
        }
        .onGaryTour { verb, arg in
            switch verb {
            case "picks": if let idx = Int(arg) { withAnimation { page = idx } }
            case "picksday": withAnimation { pickDay = arg == "yesterday" ? .yesterday : .today }
            case "picksport": withAnimation { sport = arg.uppercased() }
            default: break
            }
        }
    }

    /// A cheap Equatable digest of every input the memoized game set + edge index
    /// depend on (counts + the refresh tick). Changes only when the underlying data
    /// actually changes — NOT on a live-score publish — so `.onChange` drives
    /// rebuildMemo() exactly when needed and never on a tick.
    private var dataSignature: String {
        "\(store.allProps.count)-\(store.yesterdayPropsAll.count)-\(store.gamePicks.count)-\(store.yesterdayGamePicksAll.count)-\(store.slate.count)-\(connections.count)-\(store.refreshTick)"
    }

    /// Land on the matchup the Hub deep-linked ("LAD @ ARI"). Leaves the
    /// request pending while the slate is still loading; clears it once a
    /// match attempt has been made.
    private func consumeFocus() {
        guard let focus = focusState.focusGame else { return }
        // Deep links from the Hub land on TODAY's board (where the game lives).
        pickDay = .today
        guard !games.isEmpty else { return }
        focusState.focusGame = nil
        let apply = {
            if let idx = games.firstIndex(where: { abbrGameMatches(focus, matchup: $0.matchup) }) {
                withAnimation(.easeInOut(duration: 0.25)) { page = idx + 1 }
            }
        }
        if sport != "ALL" && AppFlags.picksAllTab {
            // Widen the filter first; apply after the sport-change page reset.
            sport = "ALL"
            DispatchQueue.main.async { apply() }
        } else if !AppFlags.picksAllTab {
            // ALL is hidden: jump the filter to the focused game's own league
            // (slate first, then today's picks), then land on its page.
            let lg = store.slate.first { abbrGameMatches(focus, matchup: "\($0.away_team ?? "") @ \($0.home_team ?? "")") }?.league?.uppercased()
                ?? store.gamePicks.first { abbrGameMatches(focus, matchup: "\($0.awayTeam ?? "") @ \($0.homeTeam ?? "")") }?.league?.uppercased()
            if let lg, sports.contains(lg), sport != lg {
                sport = lg
                DispatchQueue.main.async { apply() }
            } else {
                apply()
            }
        } else {
            apply()
        }
    }

    @ViewBuilder private var content: some View {
        if store.loading && !hasContent {
            Spacer(); ProgressView().tint(GaryColors.gold); Spacer()
        } else if !hasContent {
            emptyState
        } else {
            pager
        }
    }

    private var pager: some View {
        VStack(spacing: 0) {
            TabView(selection: $page) {
                ScrollView(showsIndicators: false) {
                    PicksTodayPage(topProps: topProps, topGamePick: topGamePick,
                                   gamePickResult: { store.gamePickResult($0, forYesterday: pickDay == .yesterday) }, resultForProp: { store.resultForProp($0, forYesterday: pickDay == .yesterday) },
                                   edges: sportConnections, scopeLeague: effectiveScope, isToday: pickDay == .today, refreshTick: store.refreshTick, onTapProp: { selectedProp = $0 })
                        .padding(.bottom, 130)
                }
                .refreshable { await store.refresh() }
                .tag(0)
                ForEach(Array(games.enumerated()), id: \.offset) { idx, g in
                    ScrollView(showsIndicators: false) {
                        PicksGamePage(group: g,
                                      // MLB HR is a HOME-RUN props lane — never show the game's
                                      // side/total pick there, only the HR bets. On Yesterday,
                                      // prefer yesterday's (graded) pick for a series matchup.
                                      entries: sport == "MLB HR" ? [] : store.gamePicksForMatchup(g.matchup, preferYesterday: pickDay == .yesterday),
                                      gamePickResult: { store.gamePickResult($0, forYesterday: pickDay == .yesterday) }, resultForProp: { store.resultForProp($0, forYesterday: pickDay == .yesterday) },
                                      edges: edges(for: g), onTapProp: { selectedProp = $0 },
                                      onSeeYesterday: { withAnimation(.easeInOut(duration: 0.25)) { pickDay = .yesterday; page = 0 } })
                            .padding(.bottom, 130)
                    }
                    .refreshable { await store.refresh() }
                    .tag(idx + 1)
                }
            }
            .tabViewStyle(.page(indexDisplayMode: .never))
        }
    }

    /// The Hub masthead, worn by Picks (founder, Jul 22: "the nav bar at the
    /// top of The Hub and this entire upper part is what I want for the Picks
    /// page"): bear + THE PICKS wordmark, the rolling 7-day pick record, the
    /// double gold rule, then the league tabs in the Hub's underline idiom.
    /// Same ramp (HubFont), same geometry — only the record's source differs
    /// (real game picks, not insight lanes).
    private var masthead: some View {
        VStack(alignment: .leading, spacing: 0) {
            HStack(alignment: .center, spacing: 10) {
                Image(GaryBrand.mark)
                    .resizable().scaledToFit()
                    .frame(width: 30, height: 30)
                    .clipShape(RoundedRectangle(cornerRadius: 7, style: .continuous))
                (Text("THE ").foregroundColor(GaryColors.warmWhite)
                    + Text("PICKS").foregroundColor(GaryColors.gold))
                    .font(HubFont.display(30))
                    .tracking(0.5)
                Spacer()
                Button {
                    NotificationCenter.default.post(name: Notification.Name("ShowSettingsMenu"), object: nil)
                } label: {
                    Image(systemName: "ellipsis")
                        .font(.system(size: 14, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.62))
                        .frame(width: 28, height: 30)
                }
                .buttonStyle(.plain)
                .accessibilityLabel("Settings")
            }

            HStack(spacing: 8) {
                Spacer()
                if let r = record7 {
                    let pct = Int((Double(r.w) / Double(max(r.w + r.l, 1)) * 100).rounded())
                    HStack(spacing: 5) {
                        Text("LAST 7 DAYS")
                            .font(HubFont.kicker(9.5)).tracking(1.2)
                            .foregroundStyle(.white.opacity(0.62))
                        Text("\(r.w)–\(r.l) · \(pct)%")
                            .font(HubFont.data(11))
                            .foregroundStyle(GaryColors.gold)
                    }
                }
            }
            .padding(.top, 5)

            // Double rule — the newspaper masthead seam, straight off the Hub.
            VStack(spacing: 2.5) {
                Rectangle().fill(GaryColors.gold.opacity(0.55)).frame(height: 2)
                Rectangle().fill(GaryColors.gold.opacity(0.3)).frame(height: 1)
            }
            .padding(.top, 11)

            if sports.count > 1 {
                HStack(spacing: 22) {
                    ForEach(sports, id: \.self) { s in
                        let on = (s == sport)
                        Button { withAnimation(.easeInOut(duration: 0.2)) { sport = s } } label: {
                            VStack(spacing: 5) {
                                Text(s)
                                    .font(HubFont.kicker(12))
                                    .tracking(1.6)
                                    .foregroundStyle(on ? GaryColors.warmWhite : .white.opacity(0.5))
                                Capsule().fill(GaryColors.gold)
                                    .frame(width: 22, height: 2)
                                    .opacity(on ? 1 : 0)
                            }
                            .contentShape(Rectangle())
                        }
                        .buttonStyle(.plain)
                    }
                    Spacer()
                }
                .padding(.top, 10)
            }
        }
        .padding(.horizontal, 18)
        .padding(.top, 10)
    }

    /// The day's slate as the game selector — the Hub strip's exact grammar
    /// (abbr matchup over time + O/U, hairline-separated blocks), with
    /// selection: tapping a block pages to that game. The first block is the
    /// Today/Yesterday day selector; live/final states take the second line.
    private var slateStrip: some View {
        ScrollViewReader { proxy in
            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 0) {
                    dayBlock
                    ForEach(Array(games.enumerated()), id: \.offset) { idx, g in
                        Rectangle().fill(Color.white.opacity(0.1)).frame(width: 1, height: 26)
                        stripBlock(idx + 1, g)
                    }
                }
                .padding(.horizontal, 18)
            }
            .onChange(of: page) { p in withAnimation { proxy.scrollTo(p, anchor: .center) } }
        }
        .padding(.top, 12)
        .padding(.bottom, 2)
    }

    /// The strip's first block: TODAY/YESTERDAY ▾ over the day's date. Tap =
    /// back to the day board (or flip the day when already there); long-press
    /// = the explicit menu — the old tab row's behavior in the strip's clothes.
    private var dayBlock: some View {
        let on = (page == 0)
        var cal = Calendar(identifier: .gregorian)
        cal.timeZone = TimeZone(identifier: "America/New_York") ?? cal.timeZone
        let f = DateFormatter()
        f.timeZone = cal.timeZone
        f.dateFormat = "MMM d"
        let day = f.string(from: cal.date(byAdding: .day, value: pickDay == .today ? 0 : -1, to: Date()) ?? Date()).uppercased()
        return Menu {
            Button("Today")     { withAnimation(.easeInOut(duration: 0.25)) { pickDay = .today; page = 0 } }
            Button("Yesterday") { withAnimation(.easeInOut(duration: 0.25)) { pickDay = .yesterday; page = 0 } }
        } label: {
            VStack(alignment: .leading, spacing: 3) {
                HStack(spacing: 4) {
                    Text(pickDay == .today ? "TODAY" : "YESTERDAY")
                        .font(HubFont.data(11.5, .semibold))
                        .foregroundStyle(.white.opacity(on ? 0.95 : 0.62))
                    Image(systemName: "chevron.down")
                        .font(.system(size: 8, weight: .bold))
                        .foregroundStyle(GaryColors.gold)
                }
                Text(day)
                    .font(HubFont.data(9.5, .medium))
                    .foregroundStyle(.white.opacity(0.55))
            }
            .padding(.trailing, 13)
            .padding(.vertical, 8)
            .contentShape(Rectangle())
        } primaryAction: {
            withAnimation(.easeInOut(duration: 0.25)) {
                if page != 0 {
                    // On a game page — tap the day block to return to THIS day's
                    // overview (page 0), keeping the day (Today stays Today).
                    page = 0
                } else {
                    // Already on the day board — flip Today <-> Yesterday.
                    pickDay = (pickDay == .today ? .yesterday : .today)
                }
            }
        }
        .id(0)
    }

    /// One game on the strip: "PIT @ NYY" over its status — pre-game the time
    /// (+ O/U when the board knows it), then ▶ LIVE · score, then FINAL · score.
    private func stripBlock(_ index: Int, _ g: (matchup: String, time: String, props: [PropPick])) -> some View {
        let on = (index == page)
        let lg = gameLeague(g)
        let parts = g.matchup.components(separatedBy: " @ ")
        let label = parts.count == 2
            ? "\(teamAbbrev(parts[0], league: lg)) @ \(teamAbbrev(parts[1], league: lg))"
            : g.matchup.uppercased()
        let timeLabel = g.time.replacingOccurrences(of: " ET", with: "")
        let total = totalFor(g)
        return Button { withAnimation(.easeInOut(duration: 0.25)) { page = index } } label: {
            VStack(alignment: .leading, spacing: 3) {
                Text(label)
                    .font(HubFont.data(11.5, .semibold))
                    .foregroundStyle(.white.opacity(on ? 0.95 : 0.62))
                HStack(spacing: 6) {
                    if let lf = liveFinalLine(for: g) {
                        Text(lf.text)
                            .font(HubFont.data(9.5, .medium))
                            .foregroundStyle(lf.color)
                    } else {
                        if !timeLabel.isEmpty {
                            Text(timeLabel)
                                .font(HubFont.data(9.5, .medium))
                                .foregroundStyle(on ? GaryColors.gold : .white.opacity(0.55))
                        }
                        if let total {
                            Text("O/U \(HubFmt.stat(total))")
                                .font(HubFont.data(9.5, .medium))
                                .foregroundStyle(.white.opacity(0.55))
                        }
                        if timeLabel.isEmpty && total == nil {
                            // Keep every block two lines tall so the strip never
                            // staggers when one game is missing its time.
                            Text(" ").font(HubFont.data(9.5, .medium))
                        }
                    }
                }
            }
            .padding(.horizontal, 13)
            .padding(.vertical, 8)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .id(index)
    }

    /// Board O/U for a strip block (today only — yesterday's blocks carry FINALs).
    private func totalFor(_ g: (matchup: String, time: String, props: [PropPick])) -> Double? {
        guard pickDay == .today, let rows = stripBoard?.board else { return nil }
        let key = Self.matchupKey(g.matchup)
        return rows.first {
            Self.matchupKey("\($0.away_team ?? "") @ \($0.home_team ?? "")") == key
        }?.total
    }

    /// Live-score row for a matchup (poller snapshots, abbr-matched).
    func liveScore(forMatchup matchup: String) -> LiveScore? {
        // Read the SHARED cache's deduped lookup (a live/scheduled row wins over a
        // bogus duplicate "final") — the exact source the pick cards read. This is
        // what keeps the matchup TAB and the CARD from disagreeing: the tab used to
        // grab `liveScores.first` (no dedup) and showed a stale "FINAL 5-3" while the
        // card showed the real "LIVE 0-0" for the same game.
        LiveScoreCache.shared.status(forMatchup: matchup)
    }

    /// LIVE / FINAL second line for a strip block; nil pre-game (the block
    /// shows time + O/U instead). Yesterday's FINAL comes from the graded
    /// result, not the live-score cache (which only reliably has today's
    /// games) — otherwise half of yesterday's blocks fall back to start times.
    private func liveFinalLine(for g: (matchup: String, time: String, props: [PropPick])) -> (text: String, color: Color)? {
        if pickDay == .yesterday, let raw = store.finalScore(forMatchup: g.matchup) {
            return ("FINAL · \(formatFinalScore(g.matchup, raw))", .white.opacity(0.45))
        }
        if let ls = liveScore(forMatchup: g.matchup) {
            if ls.isLive {
                let score = ls.scoreLine.map { " · \($0)" } ?? ""
                let det = (ls.detail?.isEmpty == false) ? " · \(ls.detail!)" : ""
                return ("▶ LIVE\(score)\(det)", GaryColors.win)
            }
            if ls.isFinal, let score = ls.scoreLine {
                return ("FINAL · \(formatFinalScore(g.matchup, score))", .white.opacity(0.45))
            }
        }
        return nil
    }

    /// Three-letter team abbreviation from the league keyword maps (sibling of the
    /// Home view's teamAbbrev) — renders yesterday's final as "COL 6 · CHC 8",
    /// matching the live-score line format.
    private func teamAbbrev(_ name: String, league: String) -> String {
        let lower = name.lowercased()
        let maps: [[String: [String]]]
        switch league.uppercased() {
        case "MLB", "MLB HR": maps = [mlbTeamKeywords]
        case "NBA": maps = [nbaTeamKeywords]
        case "NHL": maps = [nhlTeamKeywords]
        case "WC": maps = [wcTeamKeywords]
        default: maps = [mlbTeamKeywords, nbaTeamKeywords, nhlTeamKeywords, wcTeamKeywords]
        }
        for map in maps {
            for (ab, kws) in map where kws.contains(where: { lower.contains($0) }) { return ab }
        }
        let last = lower.split(separator: " ").last.map(String.init) ?? lower
        return String(last.prefix(3)).uppercased()
    }

    /// "6-8" + "Rockies @ Cubs" -> "COL 6 · CHC 8". final_score is away-home,
    /// matching the matchup's "Away @ Home" order.
    private func formatFinalScore(_ matchup: String, _ raw: String) -> String {
        finalScoreLine(matchup: matchup, raw: raw, league: gameLeague((matchup: matchup, time: "", props: [])))
    }

    /// Pre-pick page with VALUE, not a shrug (founder, Jul 12: the dashed
    /// "check back later" card was "half assed"). Today: the sport's actual
    /// slate with each game's pick ETA. Dark day: the honest line. Yesterday
    /// mode keeps the plain empty note.
    private var emptyState: some View {
        let rows: [(matchup: String, eta: String?)] = store.slate
            .filter { r in
                let lg = (r.league ?? "").uppercased()
                return (sport == "ALL" || lg == sport)
            }
            .sorted { ($0.commence_time ?? "") < ($1.commence_time ?? "") }
            .prefix(10)
            .map { r in
                let a = Formatters.shortTeamName(r.away_team, league: r.league)
                let h = Formatters.shortTeamName(r.home_team, league: r.league)
                var eta: String? = nil
                if let ct = r.commence_time, let d = parseISO8601(ct) {
                    eta = TomorrowView.etTime(ISO8601DateFormatter().string(from: d.addingTimeInterval(-5400)),
                                              withZone: false, meridiem: true).uppercased()
                }
                return ("\(a) @ \(h)", eta)
            }

        return VStack(alignment: .leading, spacing: 0) {
            if pickDay == .yesterday {
                Text("NO GRADED PICKS THIS DAY")
                    .font(GaryFonts.mono(11, bold: true)).tracking(1)
                    .foregroundStyle(.white.opacity(0.7))
                    .padding(.horizontal, 16).padding(.top, 20)
            } else if rows.isEmpty {
                // Dark day for this sport — say it straight.
                HStack(spacing: 8) {
                    BroadcastBar(height: 11)
                    Text(sport == "ALL" ? "NO GAMES TODAY" : "NO \(sport) TODAY")
                        .font(GaryFonts.accent(13)).tracking(0.6)
                        .foregroundStyle(GaryColors.gold)
                }
                .padding(.horizontal, 16).padding(.top, 20)
                Text("The league is dark — Gary's board returns with the next fixture.")
                    .font(GaryFonts.text(13))
                    .foregroundStyle(GaryColors.sectionSub)
                    .padding(.horizontal, 16).padding(.top, 8)
            } else {
                HStack(spacing: 8) {
                    BroadcastBar(height: 11)
                    Text("THE CARD IS COMING")
                        .font(GaryFonts.accent(13)).tracking(0.6)
                        .foregroundStyle(GaryColors.gold)
                }
                .padding(.horizontal, 16).padding(.top, 20)
                Text("Gary works game by game — every pick lands about 90 minutes before the start.")
                    .font(GaryFonts.text(13))
                    .foregroundStyle(GaryColors.sectionSub)
                    .padding(.horizontal, 16).padding(.top, 8)

                VStack(spacing: 0) {
                    ForEach(Array(rows.enumerated()), id: \.offset) { i, row in
                        HStack(alignment: .firstTextBaseline, spacing: 10) {
                            Text(row.matchup)
                                .font(GaryFonts.display(19))
                                .foregroundStyle(GaryColors.warmWhite.opacity(0.94))
                                .lineLimit(1).minimumScaleFactor(0.7)
                            Spacer(minLength: 8)
                            if let eta = row.eta {
                                Text("PICK ~\(eta)")
                                    .font(GaryFonts.mono(11.5, bold: true))
                                    .foregroundStyle(GaryColors.meta)
                            }
                        }
                        .padding(.vertical, 11)
                        if i < rows.count - 1 {
                            Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1)
                        }
                    }
                }
                .padding(.horizontal, 16).padding(.top, 14)
            }
            Spacer(minLength: 0)
        }
    }

    /// Best-effort league for a strip block so teamAbbrev can pick the right
    /// abbreviation map. Reads the game's own props first, then the day's
    /// picks / slate, falling back to the active filter.
    private func gameLeague(_ g: (matchup: String, time: String, props: [PropPick])) -> String {
        if let lg = g.props.first?.effectiveLeague, !lg.isEmpty { return lg.uppercased() }
        let key = Self.matchupKey(g.matchup)
        if let p = (store.gamePicks + store.yesterdayGamePicks).first(where: {
            Self.matchupKey("\($0.awayTeam ?? "") @ \($0.homeTeam ?? "")") == key }) {
            return (p.league ?? "").uppercased()
        }
        if let s = store.slate.first(where: {
            Self.matchupKey("\($0.away_team ?? "") @ \($0.home_team ?? "")") == key }) {
            return (s.league ?? "").uppercased()
        }
        return sport == "ALL" ? "" : sport
    }

    /// Best-effort: surface edges whose "ABBR @ ABBR" shares a team token with
    /// this game's matchup or its prop teams. abbrGameMatches resolves both MLB
    /// and NBA abbreviations, so either league's edges attach to their game.
    /// PERF#1(c): now an O(1) read of the precomputed edgeIndex (built in
    /// rebuildMemo when connections/games change), not a per-render N×M scan.
    /// Falls back to the live scan for any game key not yet indexed (e.g. a
    /// deep-link race before the first rebuild) so reach is never lost.
    private func edges(for g: (matchup: String, time: String, props: [PropPick])) -> [Signal] {
        let key = Self.matchupKey(g.matchup)
        if let hit = edgeIndex[key] { return hit }
        let hay = g.matchup + " " + g.props.compactMap { $0.team }.joined(separator: " ")
        return connections.filter { abbrGameMatches($0.game, matchup: hay) || Self.matchupKey($0.game) == key }
    }

    /// The Today page's working scope: on a ONE-league day (an all-MLB July
    /// night, the All-Star break) the ALL tab resolves to that league, so the
    /// league-wide sections (LEAGUE PULSE) run instead of collapsing — the
    /// normal system, pointed at the only sport playing. Multi-league days
    /// keep ALL as ALL.
    private var effectiveScope: String {
        guard sport == "ALL" else { return sport }
        let leagues = Set((store.gamePicks.map { ($0.league ?? "").uppercased() }
                           + store.slate.map { ($0.league ?? "").uppercased() })
            .filter { !$0.isEmpty })
        return leagues.count == 1 ? leagues.first! : sport
    }

    /// Today-page edges respect the sport filter — an NBA tab must never
    /// show a Padres edge. Sports without a hub league (NHL) get none.
    private var sportConnections: [Signal] {
        // WC lanes ride the Picks page only when the WC actually plays TODAY
        // (founder, Jul 13: no WC games — no WC content on ALL). The Hub
        // keeps the lookahead coverage on its own tab.
        let wcPlaysToday = store.slate.contains { ($0.league ?? "").uppercased() == "WC" }
        let base = wcPlaysToday ? connections : connections.filter { $0.league != .wc }
        guard sport != "ALL" else { return base }
        guard let lg = HubLeagueSel.from(sport) else { return [] }
        return base.filter { $0.league == lg }
    }

    private func loadConnections() async {
        let date = SupabaseAPI.todayEST()
        var out: [Signal] = []
        for lg in AppFlags.insightLeagues {
            if let conns = try? await SupabaseAPI.fetchInsightConnections(date: date, league: lg) {
                out.append(contentsOf: conns.compactMap { $0.toSignal() })
            }
        }
        await MainActor.run { connections = out; connLoaded = true }
    }
}

struct PicksTodayPage: View {
    let topProps: [PropPick]
    let topGamePick: (pick: GaryPick, isYesterday: Bool)?
    let gamePickResult: (GaryPick) -> String?
    let resultForProp: (PropPick) -> String?
    let edges: [Signal]
    /// The Picks page's current sport scope ("ALL"/"MLB"/"WC"/…) — the same
    /// scope that filters the edges. LEAGUE PULSE is league-wide, so it only
    /// lights up on an MLB or WC scope and collapses otherwise.
    let scopeLeague: String
    /// True on the TODAY board (not the Yesterday view). Drives the blurred
    /// "pick coming" teaser: TODAY with nothing posted for this sport yet shows the
    /// lock card, never an empty top — Yesterday with no result just shows nothing.
    let isToday: Bool
    /// Bumped by the store on every pull-to-refresh — threaded into LEAGUE PULSE
    /// so a manual refresh refetches it (it owns its own network state).
    let refreshTick: Int
    let onTapProp: (PropPick) -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            topSinglePick
            // TODAY only — the Yesterday board is a time capsule of what users
            // actually saw yesterday; a live today-keyed table doesn't belong
            // there (founder, Jul 13).
            if isToday {
                LeaguePulseSection(league: scopeLeague, refreshTick: refreshTick)  // above TODAY'S EDGES
            }
            // World Cup gets a bespoke section (4 fan-legible lanes + a tap-through
            // team-news card) instead of the generic MLB-shaped EdgesSection. WC-only:
            // the shared EdgesSection / locked MLB design is never touched.
            if scopeLeague == "WC" {
                WCTodaySection(edges: edges)
            } else {
                EdgesSection(title: "TODAY'S EDGES", edges: edges, tabbed: true)
            }
        }
    }

    /// The Today page is the free showcase — exactly ONE pick (user call, Jun 16):
    /// the highest-confidence play for this sport scope, game or prop, with today's
    /// fresh pick preferred over yesterday's stamped result.
    @ViewBuilder private var topSinglePick: some View {
        let gp = topGamePick
        let prop = topProps.first
        let gameFresh = gp.map { !$0.isYesterday && gamePickResult($0.pick) == nil } ?? false
        let propFresh = prop.map { resultForProp($0) == nil } ?? false
        // Prefer a fresh pick over a stamped one; within the same tier, higher
        // confidence wins. A graded yesterday card shows only if nothing fresh exists.
        let showGame: Bool = {
            guard gp != nil else { return false }
            guard prop != nil else { return true }
            if gameFresh != propFresh { return gameFresh }
            return (gp?.pick.confidence ?? 0) >= (prop?.confidence ?? 0)
        }()

        if showGame, let gp {
            FlippablePickCard(pick: gp.pick,
                              gameResult: gamePickResult(gp.pick),
                              showSportBadge: true)
                .padding(.horizontal, 22)   // match the per-game cards (screen−44) so eyebrow + time line up across the Picks tab
                .padding(.top, 10)          // breathing room from the day/matchup tab row (was flush after the gold underline came off)
        } else if let only = prop {
            FlippablePropCard(prop: only, gameResult: resultForProp(only), showSportBadge: true)
                .padding(.horizontal, 22)   // same width as the per-game prop cards
                .padding(.top, 10)          // breathing room from the tab row (matches the game-card variant)
        } else if isToday {
            // Nothing posted for this sport yet — tease it with the blurred lock card
            // (never an empty top). A fresh pick replaces it the moment Gary posts.
            TeasedPickCard(league: scopeLeague == "ALL" ? nil : scopeLeague)
                .frame(maxWidth: .infinity)
                .padding(.top, 10)
        }
    }

}

/// The "pick coming" card for the free Picks page (Jul 3 2026 — no blur, per
/// founder: keep the standard card design, just say the pick isn't here YET).
/// It is a real pick card in every way — eyebrow, Skyscraper hero, meta,
/// footer — whose headline happens to be INCOMING.
struct TeasedPickCard: View {
    /// Sport label for the meta line; nil on ALL.
    var league: String? = nil
    /// Start time copy for the footer's left corner ("7:05 PM ET"), if known.
    var time: String? = nil
    /// Kickoff/first pitch — once it passes, "incoming" would be a lie (the
    /// window closed), so the card switches to the honest no-pick state.
    var commence: Date? = nil
    /// Optional footer-right action (the game pages link back to yesterday).
    var onSeeYesterday: (() -> Void)? = nil

    private var gameStarted: Bool { commence.map { $0 <= Date() } ?? false }

    var body: some View {
        ZStack {
            VStack(alignment: .leading, spacing: 0) {
                HStack(alignment: .top, spacing: 10) {
                    Text("GARY'S PICK")
                        .font(GaryFonts.accent(12.5)).tracking(1.0)
                        .foregroundStyle(GaryColors.gold)
                        .padding(.top, 6)
                    Spacer()
                }
                .padding(.bottom, 6)

                VStack(alignment: .leading, spacing: -18) {
                    Text(gameStarted ? "NO PICK" : "PICKS")
                        .font(GaryFonts.display(58))
                        .foregroundStyle(.white)
                    Text(gameStarted ? "THIS GAME" : "INCOMING")
                        .font(GaryFonts.display(58))
                        .foregroundStyle(GaryColors.lightGold)
                        .lineLimit(1).minimumScaleFactor(0.5)
                }
                .padding(.top, -1)
                .padding(.trailing, 52)

                Text(gameStarted
                     ? "Gary's call didn't post for this one. The rest of the board is live."
                     : "Gary posts his call ~90 minutes before first pitch")
                    .font(GaryFonts.text(13.5, .medium))
                    .foregroundStyle(.white.opacity(0.6))
                    .lineLimit(1).minimumScaleFactor(0.8)
                    .padding(.top, -3)

                Rectangle()
                    .fill(.white.opacity(0.12))
                    .frame(height: 1)
                    .padding(.vertical, 12)

                HStack(spacing: 10) {
                    Text([league?.uppercased(), time].compactMap { $0 }.joined(separator: " · ")
                         .isEmpty ? "TONIGHT" : [league?.uppercased(), time].compactMap { $0 }.joined(separator: " · "))
                        .font(GaryFonts.mono(11, bold: true)).tracking(0.5)
                        .foregroundStyle(GaryColors.gold)
                    Spacer()
                    if let onSeeYesterday {
                        Button(action: onSeeYesterday) {
                            Text("YESTERDAY'S RESULTS ›")
                                .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                                .foregroundStyle(GaryColors.gold)
                        }
                        .buttonStyle(.plain)
                    }
                }
            }
            .padding(18)

            Image(GaryBrand.mark)
                .resizable().scaledToFit()
                .frame(width: 44, height: 44)
                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topTrailing)
                .padding(.top, 14).padding(.trailing, 16)
                .allowsHitTesting(false)
        }
        .frame(width: UIScreen.main.bounds.width - 44, height: CompactPickRow.uniformHeight)
        .background(
            RoundedRectangle(cornerRadius: 20, style: .continuous)
                .fill(Color(hex: "#121110"))
                .overlay(
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .stroke(.white.opacity(0.10), lineWidth: 1)
                )
                .shadow(color: .black.opacity(0.5), radius: 18, y: 8)
        )
        .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
    }
}

/// Day-keyed cache of the today board (today_board → tomorrow_board fallback,
/// written the evening before) — ONE fetch feeds every game page's scout.
@MainActor
enum TodayBoardCache {
    private static var stored: (day: String, board: TomorrowBoard)? = nil
    static func get() async -> TomorrowBoard? {
        let day = SupabaseAPI.todayEST()
        if let stored, stored.day == day { return stored.board }
        guard let board = await SupabaseAPI.fetchTodayBoard(date: day) else { return nil }
        stored = (day, board)
        return board
    }
}

/// Day-keyed cache of the wire (today + yesterday) — team news/injury lines
/// for the scout capsules. One fetch pair shared by every game page.
@MainActor
enum ScoutWireCache {
    private static var stored: (day: String, items: [SupabaseAPI.WireItem])? = nil
    static func get() async -> [SupabaseAPI.WireItem] {
        let day = SupabaseAPI.todayEST()
        if let stored, stored.day == day, !stored.items.isEmpty { return stored.items }
        async let today = SupabaseAPI.fetchWireItems(date: day, limit: 24)
        async let prior = SupabaseAPI.fetchWireItems(date: shiftDay(day, -1), limit: 24)
        let items = await today + prior
        // NEVER cache an empty read — a page swipe cancels in-flight .tasks and
        // the cancelled fetch returns [], which would poison every later page.
        if !items.isEmpty { stored = (day, items) }
        return items
    }
    private static func shiftDay(_ iso: String, _ delta: Int) -> String {
        let f = DateFormatter()
        f.dateFormat = "yyyy-MM-dd"
        f.timeZone = TimeZone(identifier: "America/New_York")
        guard let d = f.date(from: iso),
              let shifted = Calendar.current.date(byAdding: .day, value: delta, to: d) else { return iso }
        return f.string(from: shifted)
    }
}

/// SCOUTING REPORT — final form (founder-picked, Jul 7 PM): S5 Bebas team+
/// price heads · S3 series tug + venue split + S9 last-three meetings · THE
/// ARMS as P34/P23 blocks (side-tinted Bebas plate + quality-start tag +
/// statement ladder: label zone | rule | values) · LAST 10 as an F1 kicker
/// row · hanging-indent WIRE · conditions footer. WC speaks the same kicker-
/// row grammar (form / goal diff / shape / danger men). Flat on the page;
/// every fact server-grounded; every row omits itself when data is short.
struct GameScoutSection: View {
    let matchup: String
    var row: TomorrowBoardRow? = nil
    var board: TomorrowBoard? = nil
    var wc: TomorrowWcMatch? = nil
    var wire: [SupabaseAPI.WireItem] = []
    /// Odds captured at pick time (GaryPick.moneylineAway/Home). When present
    /// the header wears Gary's exact numbers — never a drifted board snapshot
    /// (founder, Jul 10: "MLB has to match").
    var pickMl: (away: Double?, home: Double?)? = nil

    private var sides: (away: String, home: String) {
        let p = matchup.components(separatedBy: " @ ")
        return (p.first ?? "", p.count > 1 ? p[1] : "")
    }
    private static func sideMatches(_ boardName: String?, _ side: String) -> Bool {
        guard let b = boardName?.lowercased(), !b.isEmpty else { return false }
        let s = side.lowercased()
        return s == b || s.hasSuffix(b) || b.hasSuffix(s)
    }
    private func abbr(_ side: String, fallback: String?) -> String {
        if let fallback, !fallback.isEmpty { return fallback }
        let a = teamAbbrevFromName(side, league: row?.league)
        return a.isEmpty ? side.uppercased() : a
    }
    private static func odds(_ v: Double?) -> String? {
        guard let v else { return nil }
        let i = Int(v)
        return i > 0 ? "+\(i)" : "\(i)"
    }
    private static func num(_ v: Double?) -> String? {
        guard let v else { return nil }
        return v == v.rounded() ? String(format: "%.0f", v) : String(format: "%.1f", v)
    }

    private var league: String { wc != nil ? "WC" : (row?.league ?? "").uppercased() }
    private var headerNames: (away: String, home: String) {
        (Formatters.shortTeamName(sides.away, league: league),
         Formatters.shortTeamName(sides.home, league: league))
    }
    /// Header prices. WC: TO-ADVANCE odds when the knockout market exists —
    /// a price that never needs to match Gary's 90-minute pick (founder,
    /// Jul 10) — else the 3-way ML (draw rendered separately below). MLB and
    /// the rest: the odds CAPTURED AT PICK TIME when a pick exists, so the
    /// scout header always matches Gary's number; the day board only fills
    /// the pre-pick morning.
    private var headOdds: (a: String?, h: String?) {
        if let wc {
            if wc.lines?.advance_home != nil || wc.lines?.advance_away != nil {
                return (Self.odds(wc.lines?.advance_away), Self.odds(wc.lines?.advance_home))
            }
            return (Self.odds(wc.lines?.ml_away), Self.odds(wc.lines?.ml_home))
        }
        if let pickMl, pickMl.away != nil || pickMl.home != nil {
            return (Self.odds(pickMl.away), Self.odds(pickMl.home))
        }
        return (Self.odds(row?.ml_away), Self.odds(row?.ml_home))
    }
    /// True when the header is wearing the knockout TO-ADVANCE prices.
    private var headIsAdvance: Bool {
        wc != nil && (wc?.lines?.advance_home != nil || wc?.lines?.advance_away != nil)
    }
    private var teamAbbrs: (a: String, h: String) {
        (abbr(sides.away, fallback: row?.away_abbr), abbr(sides.home, fallback: row?.home_abbr))
    }

    // MARK: styled fragments

    private static func stat(_ s: String, _ c: Color = .white.opacity(0.9)) -> Text {
        Text(s).font(GaryFonts.mono(15, bold: true)).foregroundColor(c)
    }
    private static func kicker(_ s: String) -> some View {
        Text(s).font(GaryFonts.mono(12, bold: true)).tracking(1.4)
            .foregroundStyle(GaryColors.gold.opacity(0.8))
    }
    private static func formRun(_ run: String) -> Text {
        run.reduce(Text("")) { acc, ch in
            let c: Color = ch == "W" ? GaryColors.win
                         : ch == "L" ? GaryColors.loss : .white.opacity(0.55)
            return acc + Text(String(ch)).font(GaryFonts.mono(14, bold: true)).foregroundColor(c)
        }
    }
    private static func diffText(_ v: Double?) -> Text? {
        guard let v else { return nil }
        let str = (v > 0 ? "+" : "") + (Self.num(v) ?? "0")
        return stat(str, v > 0 ? GaryColors.win : v < 0 ? GaryColors.loss : .white)
    }
    private static func last10Text(_ f: TomorrowForm?) -> Text? {
        guard let f else { return nil }
        var parts: [Text] = []
        if let l10 = f.l10, !l10.isEmpty { parts.append(stat(l10)) }
        if let st = f.streak, !st.isEmpty {
            let c: Color = st.hasPrefix("W") ? GaryColors.win
                         : st.hasPrefix("L") ? GaryColors.loss : .white
            parts.append(stat(st, c))
        }
        guard !parts.isEmpty else { return nil }
        return parts.dropFirst().reduce(parts[0]) { $0 + stat(" · ", .white.opacity(0.35)) + $1 }
    }
    /// "16.2 IP · 5 ER · 21 K" — plain; the numbers speak for themselves.
    private static func ipLine(ip: String, er: Int, k: Int?) -> Text {
        let ipShow = ip.hasSuffix(".0") ? String(ip.dropLast(2)) : ip
        var bits = "\(ipShow) IP · \(er) ER"
        if let k, k > 0 { bits += " · \(k) K" }
        return stat(bits)
    }
    /// "5 IP · 1 ER · 10 K vs CIN" — the opponent tag stays neutral.
    private static func outingText(_ o: TomorrowOuting?) -> Text? {
        guard let o, let ip = o.ip else { return nil }
        var t = ipLine(ip: ip, er: o.er ?? 0, k: o.k)
        if let opp = o.opp {
            t = t + Text(" \(o.at ?? "vs") \(opp)").font(GaryFonts.mono(13.5)).foregroundColor(.white.opacity(0.62))
        }
        return t
    }
    private static func l3Text(_ l: TomorrowL3?) -> Text? {
        guard let l, let ip = l.ip, let er = l.er else { return nil }
        return ipLine(ip: ip, er: er, k: l.k)
    }
    /// "4 days" — the note ("short" / "layoff") carries the flag in words.
    private static func restText(_ r: TomorrowRest?) -> Text? {
        guard let d = r?.days else { return nil }
        var t = stat("\(d) day\(d == 1 ? "" : "s")")
        if d <= 3 {
            t = t + Text(" · short").font(GaryFonts.mono(13.5)).foregroundColor(.white.opacity(0.62))
        } else if d >= 10 {
            t = t + Text(" · layoff").font(GaryFonts.mono(13.5)).foregroundColor(.white.opacity(0.55))
        }
        return t
    }
    private func vsOppText(_ v: TomorrowVsOpp?) -> Text? {
        guard let v, let era = v.era, let gs = v.gs else { return nil }
        return Self.stat(String(format: "%.2f ERA", era))
            + Text(" · \(gs) start\(gs == 1 ? "" : "s") this season").font(GaryFonts.mono(13.5)).foregroundColor(.white.opacity(0.62))
    }
    private func seasonText(_ st: TomorrowPerson) -> Text? {
        var bits: [Text] = []
        if let e = st.era { bits.append(Self.stat(String(format: "%.2f ERA", e))) }
        if let x = st.xera { bits.append(Self.stat(String(format: "%.2f xERA", x))) }
        guard !bits.isEmpty else { return nil }
        return bits.dropFirst().reduce(bits[0]) { $0 + Self.stat(" · ", .white.opacity(0.35)) + $1 }
    }
    /// The name-row tag: "3 STRAIGHT QS" / "1 QS IN LAST 4" — plain, no judgment color.
    private static func qsTag(_ st: TomorrowPerson?) -> Text? {
        guard let q = st?.qs_form, let w = q.window, w >= 2, let n = q.qs else { return nil }
        let font = GaryFonts.mono(12.5, bold: true)
        let c: Color = .white.opacity(0.72)
        if let s = q.streak, s >= 2 {
            return Text("\(s) STRAIGHT QS").font(font).foregroundColor(c)
        }
        return Text("\(n) QS IN LAST \(w)").font(font).foregroundColor(c)
    }

    private func news(_ teamKey: String) -> String? {
        let key = teamKey.lowercased()
        guard !key.isEmpty else { return nil }
        let today = SupabaseAPI.todayEST()
        let mine = wire.filter {
            ($0.league ?? "").uppercased() == league
                && ($0.headline ?? "").lowercased().contains(key)
        }
        if let inj = mine.first(where: { $0.kind == "injury" }) { return inj.headline }
        return mine.first(where: { ($0.kind == "line_move" || $0.kind == "pace") && $0.date == today })?.headline
    }

    private var footer: String? {
        var bits: [String] = []
        if let wc {
            if let ou = Self.num(wc.lines?.total) { bits.append("O/U \(ou)") }
            if let st = wc.stage { bits.append(st) }
            if let v = wc.venue { bits.append(v) }
        } else if let row {
            if let ou = Self.num(row.total) { bits.append("O/U \(ou)") }
            let ab = teamAbbrs
            if let w = board?.weather?.first(where: {
                ($0.away_abbr == ab.a && $0.home_abbr == ab.h) || Self.sideMatches($0.matchup, matchup)
            }) {
                if let v = w.venue { bits.append(v) }
                if let t = w.temp_f { bits.append("\(t)°") }
                if let wind = w.wind_mph { bits.append("Wind \(wind) mph") }
                if let pr = w.precip_pct { bits.append("Rain \(pr)%") }
                if let note = w.note { bits.append(note) }
            } else if let v = row.venue {
                bits.append(v)
            }
        }
        return bits.isEmpty ? nil : bits.joined(separator: " · ")
    }

    private var awayStarter: TomorrowPerson? { board?.starters.first { $0.abbr == teamAbbrs.a } }
    private var homeStarter: TomorrowPerson? { board?.starters.first { $0.abbr == teamAbbrs.h } }
    private var hasContent: Bool {
        if wc != nil { return true }
        return row?.series != nil || awayStarter != nil || homeStarter != nil
            || board?.form?.isEmpty == false
    }

    var body: some View {
        if row != nil || wc != nil, hasContent {
            VStack(alignment: .leading, spacing: 0) {
                Text("SCOUTING REPORT")
                    .font(GaryFonts.accent(11.5)).tracking(0.6)
                    .foregroundStyle(.white.opacity(0.65))
                    .padding(.bottom, 12)
                HStack(alignment: .firstTextBaseline, spacing: 10) {
                    Text(headerNames.away + (headOdds.a.map { " \($0)" } ?? ""))
                        .font(GaryFonts.display(24))
                        .foregroundStyle(.white.opacity(0.92))
                        .lineLimit(1).minimumScaleFactor(0.6)
                    Spacer(minLength: 8)
                    Text(headerNames.home + (headOdds.h.map { " \($0)" } ?? ""))
                        .font(GaryFonts.display(24))
                        .foregroundStyle(GaryColors.gold)
                        .lineLimit(1).minimumScaleFactor(0.6)
                }
                .padding(.bottom, headIsAdvance || (wc?.lines?.ml_draw) != nil ? 4 : 10)
                // The market caption: names the knockout TO-ADVANCE market, or
                // carries the draw the 2-way header can't show.
                if headIsAdvance {
                    Text("TO ADVANCE")
                        .font(GaryFonts.mono(9.5, bold: true)).tracking(1.6)
                        .foregroundStyle(GaryColors.gold.opacity(0.7))
                        .padding(.bottom, 10)
                } else if let draw = wc?.lines?.ml_draw {
                    Text("DRAW \(Self.odds(draw) ?? "—")")
                        .font(GaryFonts.mono(9.5, bold: true)).tracking(1.6)
                        .foregroundStyle(.white.opacity(0.62))
                        .padding(.bottom, 10)
                }
                if let series = wc == nil ? row?.series : nil { seriesBlock(series) }
                if wc == nil { mlbArms } else { wcRows }
                wireLines
                if let footer {
                    Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1)
                    Text(footer)
                        .font(GaryFonts.text(14, .medium))
                        .foregroundStyle(.white.opacity(0.78))
                        .fixedSize(horizontal: false, vertical: true)
                        .padding(.top, 10)
                }
            }
            .padding(.horizontal, 16)
        }
    }

    // ── THE ARMS — Bebas plate + QS tag + statement ladder per pitcher ──

    private struct ArmRow: Identifiable {
        let id: Int
        let label: String
        let value: Text
    }
    private func armRows(_ st: TomorrowPerson, oppAbbr: String) -> [ArmRow] {
        var out: [ArmRow] = []
        if let t = Self.outingText(st.last_outing) { out.append(ArmRow(id: 0, label: "LAST OUTING", value: t)) }
        if let t = Self.l3Text(st.l3) { out.append(ArmRow(id: 1, label: "LAST \(st.l3?.gs ?? 3)", value: t)) }
        if let t = vsOppText(st.vs_opp) { out.append(ArmRow(id: 2, label: "VS \(oppAbbr)", value: t)) }
        if let t = Self.restText(st.rest) { out.append(ArmRow(id: 3, label: "REST", value: t)) }
        if let t = seasonText(st) { out.append(ArmRow(id: 4, label: "SEASON", value: t)) }
        return out
    }

    @ViewBuilder private func armBlock(_ st: TomorrowPerson?, tint: Color, oppAbbr: String) -> some View {
        VStack(alignment: .leading, spacing: 7) {
            HStack(alignment: .firstTextBaseline, spacing: 10) {
                Text(st?.name ?? "TBA")
                    .font(GaryFonts.display(20))
                    .foregroundStyle(st == nil ? tint.opacity(0.45) : tint)
                    .lineLimit(1).minimumScaleFactor(0.6)
                Spacer(minLength: 8)
                if let tag = Self.qsTag(st) { tag }
            }
            if let st {
                let rows = armRows(st, oppAbbr: oppAbbr)
                if !rows.isEmpty {
                    HStack(alignment: .top, spacing: 12) {
                        VStack(alignment: .leading, spacing: 0) {
                            ForEach(rows) { r in
                                Text(r.label)
                                    .font(GaryFonts.mono(11.5, bold: true)).tracking(1)
                                    .foregroundStyle(.white.opacity(0.62))
                                    .frame(height: 30, alignment: .leading)
                            }
                        }
                        .frame(width: 116, alignment: .leading)
                        Rectangle().fill(Color.white.opacity(0.1)).frame(width: 1)
                        VStack(alignment: .leading, spacing: 0) {
                            ForEach(rows) { r in
                                r.value
                                    .lineLimit(1).minimumScaleFactor(0.7)
                                    .frame(height: 30, alignment: .leading)
                            }
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                    }
                    .fixedSize(horizontal: false, vertical: true)
                }
            }
        }
        .padding(.vertical, 10)
    }

    @ViewBuilder private var mlbArms: some View {
        let ab = teamAbbrs
        if awayStarter != nil || homeStarter != nil {
            Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1)
            armBlock(awayStarter, tint: .white.opacity(0.92), oppAbbr: ab.h)
            Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1)
            armBlock(homeStarter, tint: GaryColors.gold, oppAbbr: ab.a)
        }
        if let fa = board?.form?.first(where: { $0.abbr == ab.a || Self.sideMatches($0.team, sides.away) }),
           let fh = board?.form?.first(where: { $0.abbr == ab.h || Self.sideMatches($0.team, sides.home) }),
           let ta = Self.last10Text(fa), let th = Self.last10Text(fh) {
            Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1)
            VStack(alignment: .leading, spacing: 5) {
                Self.kicker("LAST 10")
                HStack {
                    ta
                    Spacer(minLength: 10)
                    th
                }
            }
            .padding(.vertical, 10)
        }
    }

    // ── WC — the same kicker-row grammar ──

    private struct WcRow: Identifiable {
        let id: Int
        let label: String
        let away: Text
        let home: Text
        var awaySub: Text? = nil
        var homeSub: Text? = nil
    }
    private var wcRowList: [WcRow] {
        guard let wc else { return [] }
        var out: [WcRow] = []
        func add(_ label: String, _ a: Text?, _ h: Text?, _ aSub: Text? = nil, _ hSub: Text? = nil) {
            guard a != nil || h != nil else { return }
            let dash = Self.stat("—", .white.opacity(0.45))
            out.append(WcRow(id: out.count, label: label, away: a ?? dash, home: h ?? dash, awaySub: aSub, homeSub: hSub))
        }
        add("FORM · L5", (wc.away?.form?.form).map(Self.formRun), (wc.home?.form?.form).map(Self.formRun))
        // GOALS/GM — scored and allowed per match, net tinted at the end
        // (totals bettors want both halves, not just the diff).
        func goals(_ s: TomorrowWcSide?) -> Text? {
            guard let f = s?.form, let gf = f.gf_per_game, let ga = f.ga_per_game else { return nil }
            let d = gf - ga
            let dim: (String) -> Text = { Text($0).font(GaryFonts.mono(12)).foregroundColor(.white.opacity(0.62)) }
            var t = Self.stat(Self.num(gf) ?? "—") + dim(" for · ")
                + Self.stat(Self.num(ga) ?? "—") + dim(" vs")
            if let dTxt = Self.diffText(d) { t = t + dim("  ") + dTxt }
            return t
        }
        add("GOALS / GM", goals(wc.away), goals(wc.home))
        // AT THIS CUP — tournament-only record (excludes friendlies/qualifiers).
        func cup(_ s: TomorrowWcSide?) -> Text? {
            guard let c = s?.form?.wc, let rec = c.record else { return nil }
            let w = c.w ?? 0
            let l = c.l ?? 0
            let tint: Color = w > l ? GaryColors.win : l > w ? GaryColors.loss : .white.opacity(0.9)
            return Self.stat(rec, tint)
                + Text(" W-D-L").font(GaryFonts.mono(11)).foregroundColor(.white.opacity(0.62))
        }
        add("AT THIS CUP", cup(wc.away), cup(wc.home))
        func manLine(_ p: TomorrowWcKeyPlayer) -> String? {
            guard let n = p.name else { return nil }
            var stat: [String] = []
            if let g = p.goals, g > 0 { stat.append("\(g)G") }
            if let a = p.assists, a > 0 { stat.append("\(a)A") }
            return stat.isEmpty ? n : "\(n) \(stat.joined(separator: " "))"
        }
        func men(_ s: TomorrowWcSide?) -> (Text, Text?)? {
            let lines = (s?.key_players ?? []).compactMap(manLine)
            guard let first = lines.first else { return nil }
            let mk: (String) -> Text = { Text($0).font(GaryFonts.text(13.5, .semibold)).foregroundColor(.white.opacity(0.92)) }
            let sub = lines.count > 1
                ? Text(lines[1]).font(GaryFonts.text(12, .medium)).foregroundColor(.white.opacity(0.62))
                : nil
            return (mk(first), sub)
        }
        let ma = men(wc.away), mh = men(wc.home)
        add("DANGER MEN", ma?.0, mh?.0, ma?.1, mh?.1)
        return out
    }

    @ViewBuilder private var wcRows: some View {
        ForEach(wcRowList) { r in
            Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1)
            VStack(alignment: .leading, spacing: 5) {
                Self.kicker(r.label)
                HStack(alignment: .top, spacing: 10) {
                    VStack(alignment: .leading, spacing: 2) {
                        r.away.lineLimit(1).minimumScaleFactor(0.7)
                        if let sub = r.awaySub { sub.lineLimit(1).minimumScaleFactor(0.7) }
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)
                    VStack(alignment: .trailing, spacing: 2) {
                        r.home.lineLimit(1).minimumScaleFactor(0.7)
                        if let sub = r.homeSub { sub.lineLimit(1).minimumScaleFactor(0.7) }
                    }
                    .frame(maxWidth: .infinity, alignment: .trailing)
                }
            }
            .padding(.vertical, 10)
        }
    }

    /// S3's tug + venue split + S9's meetings.
    @ViewBuilder private func seriesBlock(_ s: TomorrowSeries) -> some View {
        VStack(alignment: .leading, spacing: 4) {
            if let split = s.split_line {
                Text("SERIES · \(split)")
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(.white.opacity(0.68))
            }
            if let meets = s.meetings, !meets.isEmpty {
                VStack(alignment: .leading, spacing: 3) {
                    ForEach(Array(meets.enumerated()), id: \.offset) { _, m in
                        HStack(spacing: 8) {
                            Text(m.d ?? "")
                                .font(GaryFonts.mono(14.5, bold: true))
                                .foregroundStyle(.white.opacity(0.88))
                                .frame(width: 62, alignment: .leading)
                            Text(m.line ?? "")
                                .font(GaryFonts.mono(14.5, bold: true))
                                .foregroundStyle(.white.opacity(0.88))
                            Spacer(minLength: 8)
                            Text(m.venue ?? "")
                                .font(GaryFonts.mono(14.5))
                                .foregroundStyle(.white.opacity(0.62))
                        }
                    }
                }
                .padding(.top, 6)
            }
        }
        .padding(.bottom, 12)
    }

    /// Hanging-indent wire notes (injury first), de-duped across the sides.
    @ViewBuilder private var wireLines: some View {
        let aKey = wc != nil ? sides.away : Formatters.shortTeamName(sides.away, league: "MLB")
        let hKey = wc != nil ? sides.home : Formatters.shortTeamName(sides.home, league: "MLB")
        let items = [news(aKey), news(hKey)].compactMap { $0 }
        let uniq = items.reduce(into: [String]()) { if !$0.contains($1) { $0.append($1) } }
        if !uniq.isEmpty {
            Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1)
            HStack(alignment: .top, spacing: 10) {
                Text("WIRE")
                    .font(GaryFonts.mono(10.5, bold: true)).tracking(1)
                    .foregroundStyle(GaryColors.gold.opacity(0.8))
                    .padding(.top, 2)
                VStack(alignment: .leading, spacing: 5) {
                    ForEach(uniq, id: \.self) { h in
                        Text(h)
                            .font(GaryFonts.text(14.5))
                            .foregroundStyle(.white.opacity(0.8))
                            .fixedSize(horizontal: false, vertical: true)
                    }
                }
            }
            .padding(.vertical, 10)
        }
    }
}

// MARK: - The Scout Trio (Jul 22 2026 — founder-picked mocks, ported as designed)
//
// Three stacked report sections replace GameScoutSection on the game page:
// THE TUG (mock MY 07: center-out comparison bars), THE NOTEBOOK (MY 08:
// prose chapters assembled strictly from real fields — never generated), and
// THE BIG NUMBERS (MY 04: one numeral per fact, pipeline edges leading).
// GameScoutSection stays in the file unreferenced — the founder may still
// fold parts of it back in after seeing these live.

/// Shared palette + type for the trio — 1:1 with the approved mock values.
fileprivate enum ScoutMock {
    static let card = Color(hex: "#1B1714")
    static let warm = Color(hex: "#F2EDE4")
    static let hairline = Color(hex: "#FFF8EB").opacity(0.09)
    static func kicker(_ s: String, size: CGFloat = 9) -> some View {
        Text(s.uppercased()).font(.system(size: size, weight: .semibold).monospacedDigit())
            .tracking(1.2).foregroundStyle(warm.opacity(0.42)).lineLimit(1)
    }
    static func value(_ s: String, size: CGFloat = 12.5) -> Text {
        Text(s).font(.system(size: size, weight: .semibold).monospacedDigit())
    }
    static var cardShape: some View {
        RoundedRectangle(cornerRadius: 14, style: .continuous).fill(card)
            .overlay(RoundedRectangle(cornerRadius: 14, style: .continuous).stroke(hairline, lineWidth: 1))
    }
}

/// Hairline with the centered gold seam tick — the band separator the founder
/// screenshotted and asked to keep exactly.
fileprivate struct ScoutBandTick: View {
    var body: some View {
        ZStack {
            Rectangle().fill(Color.white.opacity(0.06)).frame(height: 1)
            RoundedRectangle(cornerRadius: 1).fill(GaryColors.gold)
                .frame(width: 2, height: 13)
                .shadow(color: GaryColors.gold.opacity(0.4), radius: 6)
        }
    }
}

/// Flat kicker + prose band (TONIGHT · SERIES / THE WIRE) — flat inside its
/// parent, never its own container (founder call, Jul 22).
fileprivate struct ScoutFlatBand: View {
    let kicker: String
    let text: String
    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            ScoutMock.kicker(kicker)
            Text(text)
                .font(.system(size: 12.5).monospacedDigit())
                .foregroundStyle(ScoutMock.warm.opacity(0.84))
                .lineSpacing(3)
                .fixedSize(horizontal: false, vertical: true)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }
}

/// One extraction of everything the trio renders — real board/wire fields only.
fileprivate struct ScoutTrioData {
    let awayName: String            // "Reds"
    let homeName: String            // "Mariners"
    let awayStarter: TomorrowPerson?
    let homeStarter: TomorrowPerson?
    let awayL10: String?            // "6-4"
    let homeL10: String?
    let awayStreak: String?         // "W3"
    let homeStreak: String?
    let venue: String?
    let tempF: Int?
    let windMph: Int?
    let weatherNote: String?
    let total: Double?
    let seriesLine: String?         // split_line
    let lastMeeting: (d: String, line: String)?
    let wireLines: [String]

    init(matchup: String, row: TomorrowBoardRow?, board: TomorrowBoard?, wire: [SupabaseAPI.WireItem]) {
        let sides = matchup.components(separatedBy: " @ ")
        let awaySide = sides.first ?? "", homeSide = sides.count > 1 ? sides[1] : ""
        let lg = (row?.league ?? "MLB").uppercased()
        awayName = Formatters.shortTeamName(awaySide, league: lg)
        homeName = Formatters.shortTeamName(homeSide, league: lg)

        func abbr(_ side: String, _ fallback: String?) -> String {
            if let fallback, !fallback.isEmpty { return fallback }
            let a = teamAbbrevFromName(side, league: row?.league)
            return a.isEmpty ? side.uppercased() : a
        }
        let aAb = abbr(awaySide, row?.away_abbr), hAb = abbr(homeSide, row?.home_abbr)
        func matches(_ name: String?, _ side: String) -> Bool {
            guard let b = name?.lowercased(), !b.isEmpty else { return false }
            let s = side.lowercased()
            return s == b || s.hasSuffix(b) || b.hasSuffix(s)
        }
        awayStarter = board?.starters.first { $0.abbr == aAb }
        homeStarter = board?.starters.first { $0.abbr == hAb }
        let fa = board?.form?.first { $0.abbr == aAb || matches($0.team, awaySide) }
        let fh = board?.form?.first { $0.abbr == hAb || matches($0.team, homeSide) }
        awayL10 = fa?.l10; homeL10 = fh?.l10
        awayStreak = fa?.streak; homeStreak = fh?.streak

        let w = board?.weather?.first {
            ($0.away_abbr == aAb && $0.home_abbr == hAb) || matches($0.matchup, matchup)
        }
        venue = w?.venue ?? row?.venue
        tempF = w?.temp_f; windMph = w?.wind_mph; weatherNote = w?.note
        total = row?.total
        seriesLine = row?.series?.split_line
        if let m = row?.series?.meetings?.last, let d = m.d, let line = m.line {
            lastMeeting = (d, line)
        } else { lastMeeting = nil }

        // The wire, one line per team: injury first, else today's move (the
        // same selection GameScoutSection used).
        let today = SupabaseAPI.todayEST()
        func news(_ key: String) -> String? {
            let k = key.lowercased()
            guard !k.isEmpty else { return nil }
            let mine = wire.filter { ($0.league ?? "").uppercased() == lg && ($0.headline ?? "").lowercased().contains(k) }
            if let inj = mine.first(where: { $0.kind == "injury" }) { return inj.headline }
            return mine.first(where: { ($0.kind == "line_move" || $0.kind == "pace") && $0.date == today })?.headline
        }
        var lines: [String] = []
        for h in [news(awayName), news(homeName)].compactMap({ $0 }) where !lines.contains(h) { lines.append(h) }
        wireLines = lines
    }

    /// "T-Mobile Park · 74° · Wind 9 mph · O/U 7.5 · CIN 2-1" — the shared band.
    var tonightLine: String? {
        var bits: [String] = []
        if let venue { bits.append(venue) }
        if let tempF { bits.append("\(tempF)°") }
        if let windMph { bits.append("Wind \(windMph) mph") }
        if let weatherNote, !weatherNote.isEmpty { bits.append(weatherNote) }
        if let total { bits.append("O/U " + (total == total.rounded() ? String(format: "%.0f", total) : String(format: "%.1f", total))) }
        if let seriesLine, !seriesLine.isEmpty { bits.append("Series \(seriesLine)") }
        return bits.isEmpty ? nil : bits.joined(separator: " · ")
    }
    var wireText: String? { wireLines.isEmpty ? nil : wireLines.joined(separator: " · ") }
    static func l10Wins(_ s: String?) -> Int? {
        guard let first = s?.split(separator: "-").first else { return nil }
        return Int(first.trimmingCharacters(in: .whitespaces))
    }
}

/// THE TUG (mock MY 07) — every stat a pair of center-out bars, away in warm
/// white, home in gold; bar length lands before the digits do. Bars stay
/// neutral: no win/loss coloring, the page never argues the pick.
fileprivate struct ScoutTugSection: View {
    let d: ScoutTrioData

    private struct Row: Identifiable {
        let id: String
        let label: String
        let a: Double, h: Double
        let lowerWins: Bool
        let fmt: (Double) -> String
    }
    private var rows: [Row] {
        var out: [Row] = []
        let int: (Double) -> String = { String(format: "%.0f", $0) }
        if let a = d.awayStarter?.era, let h = d.homeStarter?.era {
            out.append(Row(id: "era", label: "ERA · LOWER WINS THE PULL", a: a, h: h, lowerWins: true,
                           fmt: { String(format: "%.2f", $0) }))
        }
        if let a = d.awayStarter?.last_outing?.k, let h = d.homeStarter?.last_outing?.k {
            out.append(Row(id: "k", label: "K'S · LAST OUTING", a: Double(a), h: Double(h), lowerWins: false, fmt: int))
        }
        if let a = d.awayStarter?.l3?.er, let h = d.homeStarter?.l3?.er {
            out.append(Row(id: "er", label: "ER · LAST 3", a: Double(a), h: Double(h), lowerWins: true, fmt: int))
        }
        if let a = ScoutTrioData.l10Wins(d.awayL10), let h = ScoutTrioData.l10Wins(d.homeL10) {
            out.append(Row(id: "w10", label: "WINS · LAST 10", a: Double(a), h: Double(h), lowerWins: false, fmt: int))
        }
        return out
    }
    /// Better value takes the longer pull; the other side scales down. The
    /// +1 in the lower-wins score keeps a 0-ER run finite.
    private func widths(_ r: Row) -> (a: CGFloat, h: CGFloat) {
        let sa = r.lowerWins ? 1.0 / (r.a + 1) : r.a
        let sh = r.lowerWins ? 1.0 / (r.h + 1) : r.h
        let top = max(sa, sh, 0.0001)
        let maxW: CGFloat = 112
        return (maxW * CGFloat(sa / top), maxW * CGFloat(sh / top))
    }

    var body: some View {
        if rows.count >= 2, let aN = d.awayStarter?.name, let hN = d.homeStarter?.name {
            VStack(alignment: .leading, spacing: 0) {
                HStack(alignment: .firstTextBaseline) {
                    Text(aN).font(GaryFonts.display(17)).foregroundStyle(ScoutMock.warm)
                        .lineLimit(1).minimumScaleFactor(0.6)
                    Spacer(minLength: 8)
                    Text(hN).font(GaryFonts.display(17)).foregroundStyle(GaryColors.gold)
                        .lineLimit(1).minimumScaleFactor(0.6)
                }
                .padding(.bottom, 2)
                ForEach(rows) { r in
                    let w = widths(r)
                    VStack(spacing: 6) {
                        ScoutMock.kicker(r.label, size: 8.5).frame(maxWidth: .infinity)
                        HStack(spacing: 3) {
                            HStack(spacing: 7) {
                                Spacer(minLength: 0)
                                Text(r.fmt(r.a)).font(.system(size: 11.5, weight: .bold).monospacedDigit())
                                    .foregroundStyle(ScoutMock.warm)
                                RoundedRectangle(cornerRadius: 3).fill(ScoutMock.warm.opacity(0.5))
                                    .frame(width: w.a, height: 9)
                            }
                            HStack(spacing: 7) {
                                RoundedRectangle(cornerRadius: 3).fill(GaryColors.gold.opacity(0.65))
                                    .frame(width: w.h, height: 9)
                                Text(r.fmt(r.h)).font(.system(size: 11.5, weight: .bold).monospacedDigit())
                                    .foregroundStyle(ScoutMock.warm)
                                Spacer(minLength: 0)
                            }
                        }
                    }
                    .padding(.top, 9)
                }
                if let tonight = d.tonightLine {
                    ScoutBandTick().padding(.top, 12)
                    ScoutFlatBand(kicker: "Tonight · Series", text: tonight).padding(.vertical, 10)
                }
                if let wire = d.wireText {
                    ScoutBandTick()
                    ScoutFlatBand(kicker: "The Wire", text: wire).padding(.top, 10)
                }
            }
            .padding(.horizontal, 14).padding(.vertical, 12)
            .background(ScoutMock.cardShape)
            .padding(.horizontal, 16)
        }
    }
}

/// THE NOTEBOOK (mock MY 08) — prose chapters assembled from real fields in
/// fixed templates (never generated), each with its data line underneath.
fileprivate struct ScoutNotebookSection: View {
    let d: ScoutTrioData

    /// "three straight quality starts" / "2 quality starts in his last 4" /
    /// "a 3.44 ERA" — the pitcher's calling card, from qs_form else season ERA.
    private func armPhrase(_ p: TomorrowPerson?) -> String? {
        if let s = p?.qs_form?.streak, s >= 2 { return "\(s) straight quality starts" }
        if let q = p?.qs_form?.qs, let w = p?.qs_form?.window, w >= 2 { return "\(q) quality starts in his last \(w)" }
        if let e = p?.era { return String(format: "a %.2f ERA", e) }
        return nil
    }
    private var armsProse: Text? {
        guard let aN = d.awayStarter?.name, let hN = d.homeStarter?.name,
              let aP = armPhrase(d.awayStarter), let hP = armPhrase(d.homeStarter) else { return nil }
        var lead = Text("\(aN) brings ").foregroundColor(ScoutMock.warm.opacity(0.88))
            + Text(aP).bold().foregroundColor(ScoutMock.warm)
        if let rest = d.awayStarter?.rest?.days {
            lead = lead + Text(" on \(rest) days' rest").foregroundColor(ScoutMock.warm.opacity(0.88))
        }
        return lead + Text(". \(hN) counters with ").foregroundColor(ScoutMock.warm.opacity(0.88))
            + Text(hP).bold().foregroundColor(ScoutMock.warm)
            + Text(".").foregroundColor(ScoutMock.warm.opacity(0.88))
    }
    private var armsData: String? {
        func line(_ o: TomorrowOuting?) -> String? {
            guard let o, let ip = o.ip else { return nil }
            let ipShow = ip.hasSuffix(".0") ? String(ip.dropLast(2)) : ip
            var s = "\(ipShow) IP · \(o.er ?? 0) ER"
            if let k = o.k { s += " · \(k) K" }
            return s
        }
        guard let a = line(d.awayStarter?.last_outing), let h = line(d.homeStarter?.last_outing) else { return nil }
        return "\(a) last out — vs — \(h)"
    }
    private var parkProse: Text? {
        var parts: [Text] = []
        if let t = d.tempF, let w = d.windMph {
            var wind = Text("\(t)°").bold().foregroundColor(ScoutMock.warm)
                + Text(" with the wind at ").foregroundColor(ScoutMock.warm.opacity(0.88))
                + Text("\(w) mph").bold().foregroundColor(ScoutMock.warm)
            if let note = d.weatherNote, !note.isEmpty {
                wind = wind + Text(" — \(note)").foregroundColor(ScoutMock.warm.opacity(0.88))
            }
            parts.append(wind)
        }
        if let total = d.total {
            let tShow = total == total.rounded() ? String(format: "%.0f", total) : String(format: "%.1f", total)
            parts.append(Text("The total sits at ").foregroundColor(ScoutMock.warm.opacity(0.88))
                + Text(tShow).bold().foregroundColor(ScoutMock.warm))
        }
        guard !parts.isEmpty else { return nil }
        return parts.dropFirst().reduce(parts[0]) { $0 + Text(". ").foregroundColor(ScoutMock.warm.opacity(0.88)) + $1 }
            + Text(".").foregroundColor(ScoutMock.warm.opacity(0.88))
    }
    private var seriesProse: Text? {
        guard let s = d.seriesLine, !s.isEmpty else { return nil }
        var t = Text("Series ").foregroundColor(ScoutMock.warm.opacity(0.88))
            + Text(s).bold().foregroundColor(ScoutMock.warm)
        if let m = d.lastMeeting {
            t = t + Text(" — last meeting \(m.d): ").foregroundColor(ScoutMock.warm.opacity(0.88))
                + Text(m.line).bold().foregroundColor(ScoutMock.warm)
        }
        return t + Text(".").foregroundColor(ScoutMock.warm.opacity(0.88))
    }
    private var seriesData: String? {
        var bits: [String] = []
        if let l = d.awayL10 {
            var s = "\(d.awayName) \(l) last ten"
            if let st = d.awayStreak { s += " · \(st)" }
            bits.append(s)
        }
        if let l = d.homeL10 {
            var s = "\(d.homeName) \(l)"
            if let st = d.homeStreak { s += " · \(st)" }
            bits.append(s)
        }
        return bits.isEmpty ? nil : bits.joined(separator: " — ")
    }

    @ViewBuilder private func chapter(_ title: String, prose: Text, data: String? = nil) -> some View {
        VStack(alignment: .leading, spacing: 5) {
            Text(title.uppercased())
                .font(GaryFonts.display(13)).tracking(0.8)
                .foregroundStyle(GaryColors.gold)
            prose
                .font(.system(size: 13.5).monospacedDigit())
                .lineSpacing(4)
                .fixedSize(horizontal: false, vertical: true)
            if let data {
                Text(data)
                    .font(.system(size: 11.5, weight: .semibold).monospacedDigit())
                    .foregroundStyle(ScoutMock.warm.opacity(0.55))
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.top, 12)
    }

    var body: some View {
        let arms = armsProse, park = parkProse, series = seriesProse
        if arms != nil || park != nil || series != nil || !d.wireLines.isEmpty {
            VStack(alignment: .leading, spacing: 0) {
                if let arms { chapter("The Arms", prose: arms, data: armsData) }
                if let park { chapter("The Park", prose: park) }
                if let wire = d.wireText {
                    chapter("The News", prose: Text(wire).foregroundColor(ScoutMock.warm.opacity(0.88)))
                }
                if let series { chapter("The Series", prose: series, data: seriesData) }
            }
            .padding(.horizontal, 15).padding(.top, 2).padding(.bottom, 14)
            .background(ScoutMock.cardShape)
            .padding(.horizontal, 16)
        }
    }
}

/// THE BIG NUMBERS (mock MY 04) — one numeral per fact, the numeral as the
/// headline; the pipeline's edges lead in gold, context rows follow in white.
fileprivate struct ScoutBigNumbersSection: View {
    let d: ScoutTrioData
    let edges: [Signal]

    private struct Row: Identifiable {
        let id: String
        let numeral: String
        let bold: String
        let rest: String
    }
    private var rows: [Row] {
        var out: [Row] = []
        // The game's strongest edges lead — value + headline straight from the
        // insights pipeline (short numerals only; long values read as text).
        for s in edges.prefix(4) where out.count < 2 {
            let v = s.value.trimmingCharacters(in: .whitespaces)
            guard !v.isEmpty, v.count <= 4, !s.headline.isEmpty else { continue }
            out.append(Row(id: "edge-\(s.id)", numeral: v, bold: s.headline, rest: ""))
        }
        // Straight-QS run, whichever starter owns one.
        for p in [d.awayStarter, d.homeStarter] {
            if let p, let s = p.qs_form?.streak, s >= 2, out.count < 5 {
                var rest = ""
                if let l3 = p.l3, let ip = l3.ip, let er = l3.er {
                    rest = " — \(ip) IP, \(er) ER" + (l3.k.map { ", \($0) K" } ?? "") + " over the run"
                }
                out.append(Row(id: "qs-\(p.abbr ?? "")", numeral: "\(s)",
                               bold: "Straight quality starts for \(p.name ?? "the starter")", rest: rest))
                break
            }
        }
        // The hotter team's streak.
        if out.count < 5 {
            let aSt = d.awayStreak, hSt = d.homeStreak
            let pick: (String, String, String?, String?)? =
                aSt?.hasPrefix("W") == true ? (aSt!, d.awayName, d.awayL10, d.homeL10)
                : hSt?.hasPrefix("W") == true ? (hSt!, d.homeName, d.homeL10, d.awayL10) : nil
            if let (streak, team, own, other) = pick {
                var rest = ""
                if let own { rest = " — \(own) in their last ten" }
                if let other { rest += rest.isEmpty ? " — the other side \(other)" : ", the other side \(other)" }
                out.append(Row(id: "streak", numeral: streak, bold: "\(team) arrive hot", rest: rest))
            }
        }
        if out.count < 5, let t = d.tempF, let w = d.windMph {
            var rest = ""
            if let note = d.weatherNote, !note.isEmpty { rest = " — \(note)" }
            if let total = d.total {
                let tShow = total == total.rounded() ? String(format: "%.0f", total) : String(format: "%.1f", total)
                rest += ", total sitting at \(tShow)"
            }
            out.append(Row(id: "wx", numeral: "\(t)°", bold: "Wind \(w) mph", rest: rest))
        }
        if out.count < 5, let s = d.seriesLine,
           let numRange = s.range(of: #"\d+\s*[-–]\s*\d+"#, options: .regularExpression) {
            var rest = ""
            if let m = d.lastMeeting { rest = " — last one \(m.line), \(m.d)" }
            out.append(Row(id: "series", numeral: String(s[numRange]).replacingOccurrences(of: "-", with: "–"),
                           bold: "Series \(s)", rest: rest))
        }
        return out
    }

    var body: some View {
        let built = rows
        if built.count >= 2 {
            VStack(alignment: .leading, spacing: 0) {
                VStack(alignment: .leading, spacing: 0) {
                    ForEach(Array(built.enumerated()), id: \.element.id) { i, r in
                        HStack(alignment: .firstTextBaseline, spacing: 14) {
                            Text(r.numeral)
                                .font(GaryFonts.display(40))
                                .foregroundStyle(i < 2 ? GaryColors.gold : ScoutMock.warm)
                                .frame(minWidth: 64, alignment: .leading)
                                .lineLimit(1).minimumScaleFactor(0.5)
                            (Text(r.bold).bold().foregroundColor(ScoutMock.warm)
                                + Text(r.rest).foregroundColor(ScoutMock.warm.opacity(0.85)))
                                .font(.system(size: 12.5).monospacedDigit())
                                .lineSpacing(2.5)
                                .fixedSize(horizontal: false, vertical: true)
                        }
                        .padding(.horizontal, 14).padding(.vertical, 12)
                        if i < built.count - 1 {
                            Rectangle().fill(Color.white.opacity(0.06)).frame(height: 1)
                        }
                    }
                }
                .background(ScoutMock.cardShape)
                if let wire = d.wireText {
                    ScoutFlatBand(kicker: "The Wire", text: wire)
                        .padding(.horizontal, 2).padding(.top, 12)
                }
            }
            .padding(.horizontal, 16)
        }
    }
}

struct PicksGamePage: View {
    let group: (matchup: String, time: String, props: [PropPick])
    let entries: [(pick: GaryPick, isYesterday: Bool)]
    let gamePickResult: (GaryPick) -> String?
    let resultForProp: (PropPick) -> String?
    let edges: [Signal]
    let onTapProp: (PropPick) -> Void
    /// Flips the whole Picks view to YESTERDAY's board/results — wired from the
    /// locked look-ahead card so a user with no pick yet can go see last night.
    var onSeeYesterday: (() -> Void)? = nil

    /// The shared day board — feeds THE SCOUT and lets the league branches
    /// below engage from the MORNING, before any pick or intel row exists
    /// (founder, Jul 7: the game page sat blank until the first intel run).
    @State private var scoutBoard: TomorrowBoard? = nil
    @State private var scoutWire: [SupabaseAPI.WireItem] = []

    private var matchSides: (away: String, home: String) {
        let p = group.matchup.components(separatedBy: " @ ")
        return (p.first ?? "", p.count > 1 ? p[1] : "")
    }
    private static func scoutSideMatches(_ boardName: String?, _ side: String) -> Bool {
        guard let b = boardName?.lowercased(), !b.isEmpty else { return false }
        let s = side.lowercased()
        return s == b || s.hasSuffix(b) || b.hasSuffix(s)
    }
    private var scoutRow: TomorrowBoardRow? {
        scoutBoard?.board.first {
            Self.scoutSideMatches($0.away_team, matchSides.away) &&
            Self.scoutSideMatches($0.home_team, matchSides.home)
        }
    }
    private var topProps: [PropPick] {
        // The slip scales — show up to 5, strongest first.
        Array(group.props.sorted { ($0.confidence ?? 0) > ($1.confidence ?? 0) }.prefix(5))
    }

    /// MLB games swap the flat GAME INTEL list for the modular MLB dashboard.
    private var isMLB: Bool {
        if (group.props.first?.effectiveLeague ?? "").uppercased() == "MLB" { return true }
        if (entries.first?.pick.league ?? "").uppercased() == "MLB" { return true }
        if scoutRow?.league?.uppercased() == "MLB" { return true }
        return edges.contains { $0.league == .mlb }
    }

    /// "Blue Jays @ Red Sox" — mascot-short matchup name for the white page header.
    /// Keeps two-word mascots whole and WC nations intact (never the bare last word).
    private var matchupTitle: String {
        let parts = group.matchup.components(separatedBy: " @ ")
        guard parts.count == 2 else { return group.matchup }
        let lg = (group.props.first?.effectiveLeague ?? "").uppercased()
        return "\(Formatters.shortTeamName(parts[0], league: lg)) @ \(Formatters.shortTeamName(parts[1], league: lg))"
    }

    /// The live/final score strip ("FINAL SD 4 · PHI 6") leads the page while the
    /// game is in progress or done; pre-game opens straight to the pick.
    @ObservedObject private var liveCache = LiveScoreCache.shared
    private var heroScore: LiveScore? { liveCache.status(forMatchup: group.matchup) }

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            // The page leads STRAIGHT with Gary's pick (user call, Jun 18). The
            // matchup name + live score already live on the nav-bar tab above and
            // on each pick card's own slot (liveInSlot below), so we no longer
            // repeat a white title + LiveScoreStrip header here — the user selects
            // the game and sees the pick first, then scrolls to the intel.
            if entries.count + topProps.count > 0 {
                // All of this matchup's plays ride ONE horizontal carousel — game
                // pick(s) first (World Cup ships two: a SIDE and a TOTAL), then the
                // prop cards, strongest first. Swipe one at a time, a sliver of the
                // next peeking — the exact same full-size carousel as Home's Top
                // Plays (cardW = screen − 44). The pick cards are FULL SIZE and
                // unchanged — this only replaces the old vertical list.
                let cardW = UIScreen.main.bounds.width - 44   // a sliver of the next card peeks
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(alignment: .top, spacing: 12) {
                        ForEach(Array(entries.enumerated()), id: \.offset) { _, e in
                            FlippablePickCard(pick: e.pick,
                                              gameResult: gamePickResult(e.pick),
                                              showSportBadge: false,
                                              liveInSlot: true)
                                .frame(width: cardW)
                        }
                        ForEach(topProps) { p in
                            FlippablePropCard(prop: p, gameResult: resultForProp(p), showSportBadge: true, liveInSlot: true)
                                .frame(width: cardW)
                        }
                    }
                    .padding(.horizontal, 16)
                }
            } else if !(heroScore?.isLive ?? false) && !(heroScore?.isFinal ?? false) {
                // Look-ahead placeholder in the pick's slot — the game's on the
                // board, Gary's pick lands ~90 min out, and the intel below is
                // live now. Only for an UPCOMING game (a live/final game shows its
                // score on the LiveScoreStrip above; "drops ~90 min before" copy
                // would be wrong once the game has started).
                // No pick yet → the standard INCOMING card (no blur, Jul 3): a real
                // pick card whose headline says the pick isn't here YET. Keeps the
                // page's design language intact and links back to last night.
                TeasedPickCard(league: group.props.first?.effectiveLeague ?? entries.first?.pick.league,
                               time: group.time.isEmpty ? nil : group.time,
                               // The upcoming-game guard above leans on the live cache,
                               // which can MISS a game entirely — the card checks the
                               // real clock itself and flips to the honest no-pick state.
                               commence: parseISO8601(group.props.first?.commence_time ?? ""),
                               onSeeYesterday: onSeeYesterday)
                    .padding(.horizontal, 16)
            }

            // THE SCOUT — on the page from the morning, stays as the live
            // sections underneath fill in (founder, Jul 7).
            // All-Star specials swap the team-game scout/intel for the event's
            // own "lineup": the contest field (founder, Jul 13 — the page works
            // like any other game day, the field IS the lineup view).
            if entries.contains(where: { ($0.pick.type ?? "") == "special" }) {
                DerbyContestSection()
            } else {
            // The Scout Trio (founder, Jul 22): the three approved mocks
            // stacked in his order — THE TUG, THE NOTEBOOK, THE BIG NUMBERS.
            // One shared extraction feeds all three; GameScoutSection retired
            // from this page (struct kept while the design settles).
            let trio = ScoutTrioData(matchup: group.matchup, row: scoutRow, board: scoutBoard, wire: scoutWire)
            if trio.awayStarter != nil || trio.tonightLine != nil || trio.wireText != nil {
                Text("SCOUTING REPORT")
                    .font(GaryFonts.accent(11.5)).tracking(0.6)
                    .foregroundStyle(.white.opacity(0.65))
                    .padding(.horizontal, 16)
            }
            ScoutTugSection(d: trio)
            ScoutNotebookSection(d: trio)
            ScoutBigNumbersSection(d: trio, edges: edges)
            PlayerIntelSection(matchup: group.matchup)
            }
            if isMLB {
                // MLB: the flat GAME INTEL list becomes the modular dashboard —
                // a baseball-field anchor + Pitching / Bats / Park & Weather.
                // The field + real (projected → confirmed) lineup self-load off
                // mlb_field_lineups. The Derby page keeps it too (founder):
                // a synthetic lineup row carries the 8 contestants, so the
                // standard field view + tappable player cards just work.
                MLBGameIntelView(matchup: group.matchup, edges: edges, showHeader: false)
            } else if !entries.contains(where: { ($0.pick.type ?? "") == "special" }) {
                EdgesSection(title: "GAME INTEL", edges: edges)
            }
        }
        .padding(.top, 14)
        .task {
            scoutBoard = await TodayBoardCache.get()
            scoutWire = await ScoutWireCache.get()
        }
        .onAppear { LiveScoreCache.shared.startIfNeeded() }
    }
}

/// PLAYER INTEL — the game page's player-level layer, between the props and
/// GAME INTEL. One row per player with a breakdown pack today (the probable
/// starters lead, then hitters); tapping a row opens the same full breakdown
/// sheet the Hub uses. Rows ride player_insight_cards (computed daily by the
/// insights pipeline) and the section hides itself entirely on days or games
/// without packs — non-MLB pages render nothing extra.
struct PlayerIntelSection: View {
    let matchup: String
    @State private var rows: [PlayerInsightCardRow] = []
    @State private var selected: PlayerInsightCardRow? = nil

    /// Keeps the page scannable — the slate page is a stack, not a roster dump.
    private static let maxRows = 8

    var body: some View {
        Group {
            if !rows.isEmpty {
                VStack(alignment: .leading, spacing: 4) {
                    Text("PLAYER INTEL")
                        .font(GaryFonts.mono(9.5, bold: true)).tracking(1)
                        .foregroundStyle(.white.opacity(0.62))
                        .padding(.horizontal, 16).padding(.top, 4)
                    VStack(spacing: 0) {
                        ForEach(Array(rows.enumerated()), id: \.element.id) { idx, row in
                            Button { selected = row } label: { intelRow(row) }
                                .buttonStyle(.plain)
                            if idx < rows.count - 1 {
                                Divider().background(Color.white.opacity(0.05)).padding(.leading, 14)
                            }
                        }
                    }
                    .quantPanel()
                    .padding(.horizontal, 16)
                }
            }
        }
        .task(id: matchup) {
            let all = await SupabaseAPI.fetchPlayerIntelRows(date: SupabaseAPI.todayEST())
            let mine = all.filter { r in
                guard let g = r.payload?.game, !g.isEmpty else { return false }
                return abbrGameMatches(g, matchup: matchup)
            }
            // Pitchers lead (they drive the matchup), then hitters by name.
            rows = Array(mine.sorted { a, b in
                let ap = a.payload?.type == "pitcher", bp = b.payload?.type == "pitcher"
                if ap != bp { return ap }
                return (a.player_name ?? "") < (b.player_name ?? "")
            }.prefix(Self.maxRows))
        }
        .sheet(item: $selected) { PlayerInsightSheet(signal: nil, prefetched: $0) }
    }

    private func intelRow(_ row: PlayerInsightCardRow) -> some View {
        let p = row.payload
        let meta = [p?.team?.uppercased(), p?.position].compactMap { $0 }.joined(separator: " · ")
        let signalLine = p?.strengths?.first ?? p?.weaknesses?.first
        return HStack(spacing: 10) {
            VStack(alignment: .leading, spacing: 3) {
                HStack(spacing: 8) {
                    Text(row.player_name ?? p?.name ?? "Player")
                        .font(GaryFonts.text(14, .semibold)).foregroundStyle(.white)
                    if !meta.isEmpty {
                        Text(meta).font(GaryFonts.mono(9.5)).foregroundStyle(.white.opacity(0.62))
                    }
                }
                if let line = signalLine {
                    Text(line)
                        .font(GaryFonts.text(12)).foregroundStyle(.white.opacity(0.55))
                        .lineLimit(2)
                }
            }
            Spacer(minLength: 8)
            Image(systemName: "chevron.right")
                .font(.system(size: 11, weight: .semibold))
                .foregroundStyle(.white.opacity(0.25))
        }
        .padding(.horizontal, 14).padding(.vertical, 11)
        .contentShape(Rectangle())
    }
}


// MARK: - League Pulse (league-wide tabbed tables — TODAY page only)
//
// A fully data-driven section: each league_pulse row owns its columns[] + rows[]
// so ONE generic PulseTable renders every tab with no per-tab Swift code. The
// tab bar is one pill per returned row's tab (in a fixed display order); a tab
// with no row is simply absent. League-wide, so it sits ONLY on PicksTodayPage
// and collapses to EmptyView on any non-MLB / non-WC scope (or when empty).
struct LeaguePulseSection: View {
    /// The Picks page's sport scope ("ALL"/"MLB"/"WC"/…).
    let league: String
    /// Bumped by the Picks store on each pull-to-refresh; a change re-keys the
    /// `.task` below so a manual refresh refetches LEAGUE PULSE (it owns its
    /// own network state and isn't part of the store's data load).
    var refreshTick: Int = 0

    @State private var rows: [LeaguePulseRow] = []
    @State private var selectedTab: String? = nil
    @State private var loaded = false
    /// The (league|EST-day|refreshTick) key the current `rows` were fetched for.
    /// Used to decide when a `.task` run is a refresh/rollover (force a refetch,
    /// bypassing the 30-min cache) vs. a first paint.
    @State private var loadedKey: String = ""

    /// LEAGUE PULSE is league-wide — only MLB or WC scopes resolve to a feed.
    /// "ALL" and every other scope fetch nothing (EmptyView, no gap).
    private var pulseLeague: String? {
        switch HubLeagueSel.from(league) {
        case .mlb: return "MLB"
        case .wc:  return "WC"
        default:   return nil   // ALL / NBA / NHL / etc — no league-wide pulse
        }
    }

    /// Fixed display order per league; any tab without a row drops out.
    private static let tabOrder: [String: [String]] = [
        "MLB": ["starting_pitchers", "hot_cold_bats", "bullpen", "injuries"],
        "WC":  ["top_scorers", "form_xg", "injuries", "discipline"],
    ]

    /// Returned rows arranged in the league's fixed tab order (unknown tabs last).
    private var orderedRows: [LeaguePulseRow] {
        let order = Self.tabOrder[pulseLeague ?? ""] ?? []
        return rows.sorted { a, b in
            let ai = order.firstIndex(of: a.tab ?? "") ?? Int.max
            let bi = order.firstIndex(of: b.tab ?? "") ?? Int.max
            if ai != bi { return ai < bi }
            return (a.tab ?? "") < (b.tab ?? "")
        }
    }

    private var activeRow: LeaguePulseRow? {
        if let t = selectedTab, let r = orderedRows.first(where: { $0.tab == t }) { return r }
        return orderedRows.first
    }

    var body: some View {
        Group {
            if pulseLeague != nil && !orderedRows.isEmpty {
                VStack(alignment: .leading, spacing: 4) {
                    Text("LEAGUE PULSE")
                        .font(GaryFonts.mono(9.5, bold: true)).tracking(1)
                        .foregroundStyle(.white.opacity(0.62))
                        .padding(.horizontal, 16).padding(.top, 4)

                    if orderedRows.count > 1 { tabBar }

                    if let row = activeRow {
                        VStack(alignment: .leading, spacing: 0) {
                            // Title + subtitle/sort_note caption for the selected tab.
                            VStack(alignment: .leading, spacing: 2) {
                                if let title = row.title, !title.isEmpty {
                                    Text(title)
                                        .font(GaryFonts.text(14, .semibold)).foregroundStyle(.white)
                                }
                                let caption = [row.subtitle, row.sortNote]
                                    .compactMap { $0?.isEmpty == false ? $0 : nil }
                                    .joined(separator: " · ")
                                if !caption.isEmpty {
                                    Text(caption)
                                        .font(GaryFonts.mono(9.5)).foregroundStyle(.white.opacity(0.62))
                                        .lineLimit(2)
                                }
                            }
                            .padding(.horizontal, 14).padding(.top, 12).padding(.bottom, 8)

                            PulseTable(row: row)
                                .padding(.bottom, 4)
                        }
                        .quantPanel()
                        .padding(.horizontal, 16)
                    }
                }
            } else {
                // Zero-size anchor so the .task below always has a live view to
                // ride: a Group whose lone child is behind the `if` renders
                // NOTHING before the first fetch, an absent view never
                // "appears", and the task never fired — the section
                // deadlocked empty forever (found Jul 13).
                Color.clear.frame(width: 0, height: 0)
            }
        }
        // Key on the EST slate day AND the refresh tick (not just `league`) so the
        // task re-runs across the 3am EST rollover and on pull-to-refresh — the
        // old `.task(id: league)` never refetched once the day rolled or the user
        // pulled to refresh.
        .task(id: "\(league)|\(SupabaseAPI.todayEST())|\(refreshTick)") {
            guard let lg = pulseLeague else { rows = []; loaded = true; loadedKey = ""; return }
            let key = "\(lg)|\(SupabaseAPI.todayEST())|\(refreshTick)"
            // A changed key that we've already loaded once = a rollover or manual
            // refresh → bypass the 30-min cache so we actually pull fresh rows.
            let force = loaded && key != loadedKey
            let fetched = await SupabaseAPI.fetchLeaguePulse(date: SupabaseAPI.todayEST(), league: lg, forceRefresh: force)
            await MainActor.run { rows = fetched; loaded = true; loadedKey = key }
        }
    }

    /// One pill per present tab — gold underline marks the active tab, matching
    /// the TODAY'S EDGES category tab bar.
    private var tabBar: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 22) {
                ForEach(orderedRows) { tabPill($0) }
            }
            .padding(.horizontal, 16).padding(.top, 8).padding(.bottom, 2)
        }
    }

    @ViewBuilder
    private func tabPill(_ row: LeaguePulseRow) -> some View {
        let active = (activeRow?.tab == row.tab)
        let label = (row.title ?? row.tab ?? "").uppercased()
        Button { withAnimation(.easeInOut(duration: 0.15)) { selectedTab = row.tab } } label: {
            Text(label)
                .font(GaryFonts.mono(11.5, bold: true)).tracking(1.2)
                .foregroundStyle(active ? GaryColors.gold : .white.opacity(0.45))
                .padding(.bottom, 8)
                .overlay(alignment: .bottom) {
                    Rectangle().fill(active ? GaryColors.gold : .clear).frame(height: 2)
                }
        }
        .buttonStyle(.plain)
    }
}

/// Renders ONE league_pulse row as a small table: a header from columns[] and a
/// row per rows[] entry, reading row[col.key]. Zero hardcoding — the schema is
/// in the payload. Reserved cell keys it honors: "team" (abbr beside the primary
/// cell), "trend" ("hot"/"cold" → ▲/▼ chip), "highlight" ("today" → gold edge).
struct PulseTable: View {
    let row: LeaguePulseRow

    private var columns: [LeaguePulseColumn] { row.columns }
    private var cells: [[String: String]] { row.rows }

    var body: some View {
        VStack(spacing: 0) {
            header
            Divider().background(Color.white.opacity(0.07))
            if cells.isEmpty {
                Text("No data yet.")
                    .font(.system(size: 12)).foregroundStyle(.white.opacity(0.62))
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(.horizontal, 14).padding(.vertical, 12)
            } else {
                ForEach(Array(cells.enumerated()), id: \.offset) { idx, cell in
                    dataRow(cell)
                    if idx < cells.count - 1 {
                        Divider().background(Color.white.opacity(0.05)).padding(.leading, 14)
                    }
                }
            }
        }
    }

    /// Columns that actually paint — the trend chip rides inside the primary
    /// cell, so its raw column would otherwise burn a full equal-width slot
    /// rendering nothing (a third of why names truncated).
    private var paintedColumns: [LeaguePulseColumn] {
        columns.filter { $0.key != "trend" }
    }
    private var primaryColumn: LeaguePulseColumn? { paintedColumns.first { $0.emphasis == "primary" } }
    private var restColumns: [LeaguePulseColumn] { paintedColumns.filter { $0.emphasis != "primary" } }

    // Row grammar (no-ellipsis law, founder Jul 13): the NAME gets one flexible
    // half of the row, the short numeric columns split the other half — an
    // equal N-way split starved "W. Contreras" into "W. Con…" while "14"
    // lounged in the same width. Header and rows share the structure so the
    // columns stay aligned.
    private var header: some View {
        HStack(spacing: 8) {
            if let p = primaryColumn {
                Text(p.label.uppercased())
                    .font(GaryFonts.mono(9, bold: true)).tracking(0.8)
                    .foregroundStyle(.white.opacity(0.62))
                    .lineLimit(1).minimumScaleFactor(0.7)
                    .frame(maxWidth: .infinity, alignment: alignment(p))
            }
            HStack(spacing: 8) {
                ForEach(Array(restColumns.enumerated()), id: \.offset) { _, col in
                    // One line, scale before wrap — "TEAM" once broke into
                    // "TEA/M" in a narrow slot (founder, Jul 13).
                    Text(col.label.uppercased())
                        .font(GaryFonts.mono(9, bold: true)).tracking(0.8)
                        .foregroundStyle(.white.opacity(0.62))
                        .lineLimit(1).minimumScaleFactor(0.7)
                        .frame(maxWidth: .infinity, alignment: alignment(col))
                }
            }
            .frame(maxWidth: .infinity)
        }
        .padding(.horizontal, 14).padding(.vertical, 8)
    }

    private func dataRow(_ cell: [String: String]) -> some View {
        let isToday = (cell["highlight"] == "today")
        return HStack(spacing: 8) {
            if let p = primaryColumn {
                cellView(p, cell)
                    .frame(maxWidth: .infinity, alignment: alignment(p))
            }
            HStack(spacing: 8) {
                ForEach(Array(restColumns.enumerated()), id: \.offset) { _, col in
                    cellView(col, cell)
                        .frame(maxWidth: .infinity, alignment: alignment(col))
                }
            }
            .frame(maxWidth: .infinity)
        }
        .padding(.horizontal, 14).padding(.vertical, 9)
        .overlay(alignment: .leading) {
            // "today" → gold left edge (a probable starter / today's player).
            Rectangle().fill(isToday ? GaryColors.gold : .clear).frame(width: 2)
        }
        .background(isToday ? GaryColors.gold.opacity(0.05) : .clear)
    }

    @ViewBuilder
    private func cellView(_ col: LeaguePulseColumn, _ cell: [String: String]) -> some View {
        let value = cell[col.key] ?? ""
        if col.emphasis == "primary" {
            // Primary cell: bold name + optional team abbr + optional trend chip.
            // HARD LAW (founder, Jul 13): information NEVER ellipsizes — the name
            // scales down before it can ever cut off ("Ju…" shipped once; never
            // again). The feed also sends short names ("J. Caminero") now.
            HStack(spacing: 6) {
                Text(value)
                    .font(GaryFonts.text(13.5, .semibold)).foregroundStyle(.white)
                    .lineLimit(1)
                    .minimumScaleFactor(0.6)
                if let team = cell["team"], !team.isEmpty, col.key != "team" {
                    Text(team.uppercased())
                        .font(GaryFonts.mono(9))
                        .foregroundStyle(.white.opacity(0.62))
                        .fixedSize()
                }
                trendChip(cell["trend"])
            }
        } else if col.key == "trend" {
            // The trend is already represented by the ▲/▼ chip in the primary cell —
            // don't also draw the raw "hot"/"cold" word as a duplicate column.
            EmptyView()
        } else {
            Text(value.isEmpty ? "—" : value)
                .font(emphasisFont(col.emphasis))
                .foregroundStyle(emphasisColor(col.emphasis))
                .lineLimit(1)
                .minimumScaleFactor(0.6)
        }
    }

    @ViewBuilder
    private func trendChip(_ trend: String?) -> some View {
        switch trend {
        case "hot":
            Text("▲").font(.system(size: 10, weight: .bold)).foregroundStyle(GaryColors.mlbGrass)
        case "cold":
            Text("▼").font(.system(size: 10, weight: .bold)).foregroundStyle(Color(hex: "#D9534F"))
        default:
            EmptyView()
        }
    }

    private func emphasisFont(_ e: String?) -> Font {
        switch e {
        case "stat":  return GaryFonts.mono(13, bold: true)
        case "muted": return GaryFonts.mono(12)
        default:      return GaryFonts.mono(12.5)
        }
    }

    private func emphasisColor(_ e: String?) -> Color {
        switch e {
        case "stat":  return .white.opacity(0.9)
        case "muted": return .white.opacity(0.45)
        default:      return .white.opacity(0.7)
        }
    }

    private func alignment(_ col: LeaguePulseColumn) -> Alignment {
        col.align == "trailing" ? .trailing : .leading
    }
}


/// The Prop Slip — one silver card, one two-line row per prop (name + team,
/// then the gold pick + odds), with a W/L letter rail that fills in as props
/// settle. Replaces stacked prop cards anywhere a game carries 1–5 props.
/// Locked-card language throughout: same frame, fonts, and gold-only-pick rule.
extension PropPick {
    /// "TOTAL BASES OVER 1.5" — the locked card's pick composition, shared by
    /// the slip rows and the condensed Take sheet.
    var slipPickText: String {
        var words = Formatters.propDisplay(prop, league: effectiveLeague)
            .split(separator: " ").map(String.init)
        if let last = words.last, Double(last) != nil { words.removeLast() }
        var name = words.joined(separator: " ").uppercased()
        name = CompactPropRow.marketAbbrevShared[name] ?? name
        var call = (bet ?? "").uppercased()
        if let raw = line?.trimmingCharacters(in: .whitespaces), !raw.isEmpty {
            let lineText = Double(raw).map { $0.truncatingRemainder(dividingBy: 1) == 0 ? String(format: "%g", $0) : String(format: "%.1f", $0) } ?? raw
            call = call.isEmpty ? lineText : "\(call) \(lineText)"
        }
        return [name, call].filter { !$0.isEmpty }.joined(separator: " ")
    }
}


/// The slip's back face — one prop's take in the game-pick back's language:
/// gold voice header, the pick, THE NUMBERS, THE READ, tap to flip home.
/// A little player toggle hops between the slip's reads without flipping —
/// one flip reads the whole slip instead of packing it all into one view.
struct PropSlipBack: View {
    let props: [PropPick]
    @Binding var current: PropPick?
    let onFlipBack: () -> Void

    // Optional + guarded (was `props[0]` — crashed if ever handed an empty array;
    // App Review runs on empty/fresh states, so no force-unwraps on the back).
    private var prop: PropPick? { current ?? props.first }

    private func toggleName(_ p: PropPick) -> String {
        let full = p.player ?? p.team ?? ""
        return (full.split(separator: " ").last.map(String.init) ?? full).uppercased()
    }

    var body: some View {
        if let prop { bodyContent(prop) } else { EmptyView() }
    }

    @ViewBuilder private func bodyContent(_ prop: PropPick) -> some View {
        VStack(alignment: .leading, spacing: 9) {
            HStack {
                Text("GARY'S TAKE")
                    .font(GaryFonts.mono(11, bold: true)).tracking(1)
                    .foregroundStyle(GaryColors.gold)
                Spacer()
                if let m = prop.matchup, !m.isEmpty {
                    Text(m.uppercased())
                        .font(GaryFonts.mono(10, bold: false))
                        .foregroundStyle(.white.opacity(0.62)).lineLimit(1).minimumScaleFactor(0.7)
                }
            }

            if props.count > 1 {
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(spacing: 6) {
                        ForEach(props, id: \.id) { p in
                            let on = p.id == prop.id
                            Button {
                                withAnimation(.easeInOut(duration: 0.18)) { current = p }
                            } label: {
                                Text(toggleName(p))
                                    .font(GaryFonts.mono(10, bold: true)).tracking(0.6)
                                    .foregroundStyle(on ? Color.black.opacity(0.85) : GaryColors.silver.opacity(0.75))
                                    .padding(.horizontal, 10).padding(.vertical, 5)
                                    .background(
                                        Capsule()
                                            .fill(on ? GaryColors.silver.opacity(0.92) : Color.white.opacity(0.05))
                                            .overlay(Capsule().stroke(GaryColors.silver.opacity(on ? 0 : 0.35), lineWidth: 1))
                                    )
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
            }

            HStack(alignment: .firstTextBaseline, spacing: 8) {
                Text(prop.player ?? "")
                    .font(GaryFonts.text(19, .heavy))
                    .foregroundStyle(GaryColors.silver).lineLimit(1).minimumScaleFactor(0.7)
                Spacer()
                if let team = prop.team, !team.isEmpty {
                    Text(Formatters.shortTeamName(team, league: prop.effectiveLeague).uppercased())
                        .font(GaryFonts.text(10, .semibold))
                        .foregroundStyle(GaryColors.silver.opacity(0.7))
                }
            }

            HStack(alignment: .firstTextBaseline, spacing: 8) {
                propPickStyled(prop.slipPickText)
                    .font(GaryFonts.mono(15, bold: true)).tracking(0.6)
                    .foregroundStyle(GaryColors.heroAccent)
                    .lineLimit(1).minimumScaleFactor(0.65)
                Spacer(minLength: 6)
                Text(Formatters.americanOdds(prop.odds))
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(GaryColors.silver.opacity(0.8))
            }

            ScrollView(showsIndicators: false) {
                VStack(alignment: .leading, spacing: 10) {
                    if let stats = prop.key_stats, !stats.isEmpty {
                        VStack(alignment: .leading, spacing: 6) {
                            Text("The Numbers")
                                .font(GaryFonts.display(15))
                                .foregroundStyle(GaryColors.sectionHead)
                            ForEach(Array(stats.prefix(4).enumerated()), id: \.offset) { _, s in
                                HStack(alignment: .top, spacing: 7) {
                                    Circle().fill(GaryColors.silver.opacity(0.7))
                                        .frame(width: 4, height: 4).padding(.top, 7)
                                    Text(s)
                                        .font(GaryFonts.text(14)).foregroundStyle(.white.opacity(0.85))
                                        .fixedSize(horizontal: false, vertical: true)
                                }
                            }
                        }
                    }
                    if let a = prop.analysis, !a.isEmpty {
                        VStack(alignment: .leading, spacing: 5) {
                            Text("The Read")
                                .font(GaryFonts.display(15))
                                .foregroundStyle(GaryColors.sectionHead)
                            Text(cleanPropAnalysis(a))
                                .font(GaryFonts.text(14.5)).foregroundStyle(.white.opacity(0.75))
                                .lineSpacing(3)
                                .fixedSize(horizontal: false, vertical: true)
                        }
                    }
                    // Tail room so the last line clears the fade (game-back parity).
                    Color.clear.frame(height: 30)
                }
            }
            // Scroll-affordance fade (game-back parity): the read continues
            // below the fold — never let a hard cut look like truncation.
            .overlay(alignment: .bottom) {
                LinearGradient(colors: [Color(hex: "#1C1A1A").opacity(0), Color(hex: "#1C1A1A")],
                               startPoint: .top, endPoint: .bottom)
                    .frame(height: 24)
                    .allowsHitTesting(false)
            }

            Text("tap to flip back  ↺")
                .font(GaryFonts.mono(9, bold: false)).tracking(0.6)
                .foregroundStyle(.white.opacity(0.62))
                .frame(maxWidth: .infinity, alignment: .center)
        }
        .padding(14)
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
        .background(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .fill(Color(hex: "#1C1A1A"))
                .overlay(
                    RoundedRectangle(cornerRadius: 12, style: .continuous)
                        .stroke(GaryColors.silver.opacity(0.32), lineWidth: 1)
                )
        )
        .contentShape(Rectangle())
        .onTapGesture { onFlipBack() }
    }
}

/// Compact live/final score banner above a game's pick card.
struct LiveScoreStrip: View {
    let score: LiveScore
    var body: some View {
        HStack(spacing: 8) {
            if score.isLive {
                Circle().fill(GaryColors.gold).frame(width: 6, height: 6)
                Text("LIVE")
                    .font(GaryFonts.mono(9.5, bold: true)).tracking(1.4)
                    .foregroundStyle(GaryColors.gold)
            } else {
                Text("FINAL")
                    .font(GaryFonts.mono(9.5, bold: true)).tracking(1.4)
                    .foregroundStyle(.white.opacity(0.62))
            }
            if let line = score.scoreLine {
                Text(line)
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(GaryColors.gold)
            }
            if score.isLive, let det = score.detail, !det.isEmpty {
                Text(det)
                    .font(GaryFonts.mono(10, bold: true)).tracking(0.6)
                    .foregroundStyle(GaryColors.gold.opacity(0.6))
            }
            if score.hasGameState {
                BaseDiamond(onFirst: score.onFirst, onSecond: score.onSecond, onThird: score.onThird)
                    .padding(.leading, 2)
                if let o = score.outs {
                    HStack(spacing: 3) {
                        ForEach(0..<2, id: \.self) { i in
                            Circle()
                                .fill(i < min(o, 2) ? GaryColors.gold : Color.white.opacity(0.18))
                                .frame(width: 5, height: 5)
                        }
                    }
                    Text("OUT")
                        .font(GaryFonts.mono(8.5, bold: true)).tracking(0.5)
                        .foregroundStyle(.white.opacity(0.62))
                }
            }
            Spacer()
        }
        .padding(.vertical, 2)
    }
}

/// Tiny baseball diamond — a base fills gold when a runner is on. MLB live cards only.
struct BaseDiamond: View {
    let onFirst: Bool
    let onSecond: Bool
    let onThird: Bool
    var size: CGFloat = 20

    private func base(_ on: Bool) -> some View {
        let s = size * 0.34
        return RoundedRectangle(cornerRadius: 1.5, style: .continuous)
            .fill(on ? GaryColors.gold : Color.white.opacity(0.10))
            .overlay(
                RoundedRectangle(cornerRadius: 1.5, style: .continuous)
                    .stroke(on ? GaryColors.gold : Color.white.opacity(0.3), lineWidth: 0.8)
            )
            .frame(width: s, height: s)
            .rotationEffect(.degrees(45))
    }

    var body: some View {
        ZStack {
            base(onSecond).offset(y: -size * 0.28)
            base(onThird).offset(x: -size * 0.28)
            base(onFirst).offset(x: size * 0.28)
        }
        .frame(width: size, height: size)
    }
}

// MARK: - Connection -> Signal mapping
// Lets a fetched `Connection` (Models.swift) render through SignalRow and the
// Hub (HubView.swift). Reuses the existing SignalKind cases by matching the
// category string.

extension SignalKind {
    /// Map a stored category string onto an existing SignalKind case.
    /// Returns nil for unrecognized kinds so the row is dropped rather than
    /// mis-bucketed.
    static func from(_ raw: String?) -> SignalKind? {
        switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
        case "streak": return .streak
        case "h2h", "head-to-head", "head_to_head", "owned": return .h2h
        case "hot", "heat", "heat check", "heat_check": return .hot
        case "cold", "cooling", "cooling off", "cooling_off": return .cold
        case "injury", "replacement", "beneficiary": return .injury
        case "situational", "rest", "fatigue", "rest & fatigue", "rest_fatigue": return .situational
        case "platoon", "platoon edge", "platoon_edge": return .platoon
        case "ballpark", "ballpark shift", "ballpark_shift": return .ballpark
        case "regression", "regression watch", "regression_watch", "regression_tomorrow": return .regression
        case "xg_regression", "xg regression": return .xgRegression
        case "advancement", "advancement_odds", "advancement odds": return .advancement
        case "xg_recap", "xg recap": return .xgRecap
        case "tournament", "stakes", "group", "tournament_stakes": return .tournament
        case "gary_hr_threats", "hr_threat", "hr threats": return .hrThreat
        case "streaking": return .streak
        case "starter_form": return .starterForm
        case "starter_team_record", "team_record": return .teamRecord
        case "bullpen_fatigue": return .bullpenFatigue
        case "first_inning": return .firstInning
        case "running_game": return .runningGame
        case "park_weather": return .parkWeather
        case "fantasy_pickups", "streamers", "pickups": return .fantasyPickups
        default: return nil
        }
    }
}

extension HubLeagueSel {
    static func from(_ raw: String?) -> HubLeagueSel? {
        switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).uppercased() {
        case "MLB": return .mlb
        case "NBA": return .nba
        case "WC", "WORLD CUP", "SOCCER_WORLD_CUP": return .wc
        default: return nil
        }
    }
}

extension HubTone {
    static func from(_ raw: String?) -> HubTone {
        switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
        case "good", "positive", "up": return .good
        case "bad", "negative", "down": return .bad
        default: return .neutral
        }
    }
}

extension Connection {
    /// Convert to a render-ready Signal. Returns nil when the row lacks the
    /// minimum needed to bucket/render it (unknown league or category), so the
    /// caller can decide whether the overall fetch is usable.
    func toSignal() -> Signal? {
        guard let lg = HubLeagueSel.from(league),
              let kd = SignalKind.from(category) else { return nil }
        let head = (headline ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !head.isEmpty else { return nil }

        return Signal(
            league: lg,
            kind: kd,
            headline: head,
            detail: detail ?? "",
            game: (game ?? "").trimmingCharacters(in: .whitespacesAndNewlines),
            value: value ?? "",
            tone: HubTone.from(tone),
            spark: spark ?? [],
            lineVal: line_val,
            playerId: player_id,
            result: result,
            resultNote: result_note,
            swap: (meta?.kind == "swap") ? meta : nil,
            confirmedXI: (meta?.kind == "confirmedXI") ? meta : nil,
            reg: (meta?.kind == "regression_pitcher") ? meta : nil,
            h2h: (meta?.kind == "h2h") ? meta : nil,
            nrfi: (meta?.kind == "nrfi") ? meta : nil,
            slateDate: date,
            weather: (meta?.kind == "park_weather") ? meta : nil,
            fantasy: (meta?.kind == "fantasy_pickup") ? meta : nil,
            position: meta?.position
        )
    }
}


// MARK: - Night Board (the whole league's night, searchable — night_highlights)

/// Every homer, multi-hit night, K show, gem, RBI night and steal job from
/// last night — searchable by player or team, Gary's mark only where he had
/// the position. The Hub's morning centerpiece.
struct NightBoard: View {
    let rows: [NightHighlightRow]
    @State private var tab = 0

    static let cats: [(key: String, label: String, noun: String)] = [
        ("hr", "HR", "homered"),
        ("multi_hit", "2+ HITS", "had multi-hit nights"),
        ("k_show", "K SHOW", "struck out 7+"),
        ("gem", "GEMS", "dealt a gem"),
        ("rbi_night", "RBI", "drove in 3+"),
        ("sb_night", "SPEED", "stole 2+ bags")
    ]

    private var present: [(key: String, label: String, noun: String)] {
        Self.cats.filter { c in rows.contains { $0.category == c.key } }
    }

    private static func lead(_ d: String?) -> Int {
        Int((d ?? "").prefix(while: { $0.isNumber })) ?? 0
    }

    private func ordered(_ r: [NightHighlightRow]) -> [NightHighlightRow] {
        r.sorted {
            let (a, b) = (Self.lead($0.detail), Self.lead($1.detail))
            if a != b { return a > b }
            return ($0.gary_result != nil) && ($1.gary_result == nil)
        }
    }

    /// Player names get their own shortener — the team one takes the last
    /// word, which turns "Bobby Witt Jr." into "JR.".
    static func shortPlayer(_ name: String?) -> String {
        let suffixes: Set<String> = ["jr", "jr.", "sr", "sr.", "ii", "iii", "iv", "v"]
        let parts = (name ?? "").split(separator: " ").map(String.init)
        guard let last = parts.last else { return "" }
        if suffixes.contains(last.lowercased()), parts.count >= 2 {
            return parts.suffix(2).joined(separator: " ")
        }
        return last
    }

    private var visible: [NightHighlightRow] {
        // Page-level search covers the board now (one search per page);
        // the board itself just tabs its categories.
        guard !present.isEmpty else { return [] }
        let key = present[min(tab, present.count - 1)].key
        return ordered(rows.filter { $0.category == key })
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            if present.count > 1 { tabStrip }
            VStack(spacing: 0) {
                if visible.isEmpty {
                    Text("Nothing on the board from last night.")
                        .font(.system(size: 12))
                        .foregroundStyle(.white.opacity(0.62))
                        .padding(.horizontal, 14).padding(.vertical, 16)
                        .frame(maxWidth: .infinity, alignment: .leading)
                }
                ForEach(Array(visible.enumerated()), id: \.offset) { i, r in
                    boardRow(r, showCategory: false)
                    if i < visible.count - 1 {
                        Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
                    }
                }
            }
            .quantPanel()
        }
    }

    private var tabStrip: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 18) {
                ForEach(Array(present.enumerated()), id: \.offset) { i, c in
                    Button {
                        withAnimation(.easeInOut(duration: 0.15)) { tab = i }
                    } label: {
                        Text(c.label)
                            .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                            .foregroundStyle(i == tab ? GaryColors.gold : .white.opacity(0.4))
                            .frame(minHeight: 30)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 2)
        }
    }

    private func boardRow(_ r: NightHighlightRow, showCategory: Bool) -> some View {
        HStack(spacing: 8) {
            VStack(alignment: .leading, spacing: 2) {
                Text(Self.shortPlayer(r.player_name).uppercased())
                    .font(GaryFonts.mono(12, bold: true))
                    .foregroundStyle(.white.opacity(0.9))
                    .lineLimit(1).minimumScaleFactor(0.7)
                if showCategory, let c = Self.cats.first(where: { $0.key == r.category }) {
                    Text(c.label)
                        .font(GaryFonts.mono(8))
                        .foregroundStyle(GaryColors.gold.opacity(0.7))
                }
            }
            .frame(width: 108, alignment: .leading)
            Text(HomeView.shortTeam(r.team).uppercased())
                .font(GaryFonts.mono(10.5, bold: true))
                .foregroundStyle(TeamColors.color(for: r.team) ?? .white.opacity(0.45))
                .lineLimit(1).minimumScaleFactor(0.7)
                .frame(width: 64, alignment: .leading)
            Text(r.detail ?? "")
                .font(GaryFonts.mono(11.5, bold: true))
                .foregroundStyle(.white.opacity(0.92))
                .lineLimit(1).minimumScaleFactor(0.75)
                .frame(maxWidth: .infinity, alignment: .trailing)
            Group {
                switch r.gary_result {
                case "won":  Text("✓").foregroundStyle(GaryColors.win)
                case "lost": Text("✗").foregroundStyle(GaryColors.loss)
                default:     Text("–").foregroundStyle(.white.opacity(0.62))
                }
            }
            .font(.system(size: 11, weight: .bold))
            .frame(width: 22, alignment: .center)
        }
        .padding(.vertical, 9).padding(.horizontal, 14)
    }
}

/// Deep-link target from Home's Edges rows into the Hub: the tapped lane
/// lands here; HubView consumes it whenever the tab becomes visible
/// (same idiom as PicksFocusState for the Picks tab). @Published so a tap
/// AFTER the Hub's first load still lands — tabs are kept alive, so a
/// load-time-only consume would go dead for the rest of the session.
final class HubFocusState: ObservableObject {
    static let shared = HubFocusState()
    @Published var focusLane: SignalKind? = nil
}

